const DATA = [["Genezis 3:15","Potomstvo ženy — narodenie z panny","Galaťanom 4:4–5; Matúš 1:18","Nepriateľstvo ustanovujem medzi tebou a ženou, medzi tvojím potomstvom a jej potomstvom; ono ti rozšliape hlavu, ty mu však zraníš pätu!","Ale keď prišla plnosť času, Boh poslal svojho Syna narodeného zo ženy, narodeného pod zákonom, aby vykúpil tých, čo sú pod zákonom, a aby sme dostali synovstvo. / S narodením Ježiša Krista to bolo takto: Jeho matka Mária bola zasnúbená s Jozefom. Skôr však, ako sa zišli, ukázalo sa, že počala z Ducha Svätého.","https://biblia.sk/citanie/seb/gn/3"],["Genezis 3:15","Rozšliape satanovi hlavu","Hebrejom 2:14; 1. Jánov 3:8","Nepriateľstvo ustanovujem medzi tebou a ženou, medzi tvojím potomstvom a jej potomstvom; ono ti rozšliape hlavu, ty mu však zraníš pätu!","Keďže všetkých súrodencov spája krv a telo, i on sa stal jedným z nich, aby smrťou zničil toho, čo mal moc nad smrťou, totiž diabla, / Kto pácha hriech, je z diabla, lebo diabol hreší od počiatku. Boží Syn sa zjavil nato, aby maril diablove skutky.","https://biblia.sk/citanie/seb/gn/3"],["Genezis 5:24","Telesné nanebovstúpenie predobrazené","Marek 16:19","Henoch chodil s Bohom a nebolo ho, lebo ho Boh vzal.","Keď im to Pán Ježiš povedal, bol vzatý do neba a zasadol po Božej pravici.","https://biblia.sk/citanie/seb/gn/5"],["Genezis 9:26–27","Boh Sema bude Semovým synom","Lukáš 3:36","Dodal: Nech je zvelebený Hospodin, Boh Šémov! Nech mu je Kanaán otrokom! Kiež Boh dá, aby sa Jefet rozšíril a býval v Šémových stanoch! Kiež mu je Kanaán otrokom!","Kainam, Arfaxad, Sem, Nóach, Lámech,","https://biblia.sk/citanie/seb/gn/9"],["Genezis 12:3","Abrahámovo potomstvo požehná všetky národy","Galaťanom 3:8; Skutky 3:25–26","Požehnám tých, čo žehnajú teba, zlorečiť budem tým, čo tebe zlorečia. V tebe budú požehnané všetky pokolenia zeme.","Keďže sa v Písme predvídalo, že Boh z viery ospravedlňuje pohanov, už Abrahám dostal prísľub: V tebe budú požehnané všetky národy. / Vy ste synovia prorokov a zmluvy, ktorú Boh dal vašim otcom, keď povedal Abrahámovi: V tvojom potomkovi budú požehnané všetky národy zeme. Predovšetkým pre vás vzbudil Boh svojho Služobníka a poslal ho, aby vám priniesol požehnanie a odvrátil každého z vás od zlomyseľných skutkov.","https://biblia.sk/citanie/seb/gn/12"],["Genezis 12:7","Prisľúbenie dané Abrahámovmu potomkovi","Galaťanom 3:16","Abrámovi sa zjavil Hospodin a povedal mu: Túto krajinu dám tvojmu potomstvu. Potom tam postavil oltár Hospodinovi, ktorý sa mu zjavil.","Prísľuby boli dané Abrahámovi a jeho potomkovi. Nehovorí: a potomkom, akoby šlo o mnohých, ale o jedného: a tvojmu potomkovi, a ním je Kristus.","https://biblia.sk/citanie/seb/gn/12"],["Genezis 14:18","Kňaz podľa radu Melchizedecha","Hebrejom 6:20","Šálemský kráľ Melchisedek priniesol chlieb a víno. Bol totiž kňazom najvyššieho Boha.","kde za nás vošiel Ježiš ako predchodca, keď sa stal veľkňazom naveky na spôsob Melchisedeka.","https://biblia.sk/citanie/seb/gn/14"],["Genezis 14:18","Kráľ pokoja a spravodlivosti","Hebrejom 7:2","Šálemský kráľ Melchisedek priniesol chlieb a víno. Bol totiž kňazom najvyššieho Boha.","A Abrahám mu zo všetkého dal desiatok. Jeho meno sa prekladá najprv ako Kráľ spravodlivosti, potom však aj Kráľ Salemu, čo znamená Kráľ pokoja.","https://biblia.sk/citanie/seb/gn/14"],["Genezis 14:18","Predobraz Poslednej večere","Matúš 26:26–29","Šálemský kráľ Melchisedek priniesol chlieb a víno. Bol totiž kňazom najvyššieho Boha.","Keď jedli, vzal Ježiš chlieb a dobrorečil, lámal ho a dával učeníkom so slovami: Vezmite, jedzte, toto je moje telo. Potom vzal kalich, vzdal vďaku a dal im ho so slovami: Pite z neho všetci! Veď toto je moja krv zmluvy, ktorá sa vylieva za mnohých na odpustenie hriechov. …","https://biblia.sk/citanie/seb/gn/14"],["Genezis 17:19","Potomok Izáka","Rimanom 9:7","Boh však opakoval: Tvoja žena Sára ti porodí syna a dáš mu meno Izák. Uzavriem s ním zmluvu, večnú zmluvu s ním i s jeho potomstvom.","Ani deťmi nie sú všetci len preto, že sú potomstvom Abraháma, ale: Podľa Izáka sa bude volať tvoje potomstvo.","https://biblia.sk/citanie/seb/gn/17"],["Genezis 21:12","Potomok Izáka","Rimanom 9:7; Hebrejom 11:18","Boh však povedal Abrahámovi: Netráp sa nad chlapcom ani nad slúžkou. Poslúchni Sáru vo všetkom, čo ti povedala, lebo tvoje potomstvo sa bude volať po Izákovi.","Ani deťmi nie sú všetci len preto, že sú potomstvom Abraháma, ale: Podľa Izáka sa bude volať tvoje potomstvo. / a ktorému bolo povedané: Po Izákovi sa bude volať tvoje potomstvo.","https://biblia.sk/citanie/seb/gn/21"],["Genezis 22:8","Prisľúbený Boží Baránok","Ján 1:29","Abrahám odvetil: Syn môj, baránka na spaľovanú obetu si obstará Boh. Tak šli obaja spolu ďalej.","Keď na druhý deň videl, ako Ježiš prichádza k nemu, povedal: Hľa, Baránok Boží, ktorý sníma hriech sveta.","https://biblia.sk/citanie/seb/gn/22"],["Genezis 22:18","Ako Izákov potomok požehná všetky národy","Galaťanom 3:16","Pretože si poslúchol môj hlas, v tvojom potomstve budú požehnané všetky národy zeme.","Prísľuby boli dané Abrahámovi a jeho potomkovi. Nehovorí: a potomkom, akoby šlo o mnohých, ale o jedného: a tvojmu potomkovi, a ním je Kristus.","https://biblia.sk/citanie/seb/gn/22"],["Genezis 26:2–5","Izákov potomok prisľúbený ako Vykupiteľ","Hebrejom 11:18","Zjavil sa mu Hospodin a povedal: Nechoď do Egypta, zostaň v krajine, o ktorej ti poviem. Pobudni v tej krajine ako cudzinec. Ja budem s tebou a požehnám ťa. Tebe a tvojmu potomstvu dám všetky tieto krajiny. Tak splním prísahu, ktorou som sa zaviazal tvojmu otcovi Abrahámovi: Rozmnožím tvoje potomstvo ako nebeské hviezdy a tvojmu potomstvu dám všetky tieto krajiny. V tvojom potomstve budú požehnané všetky národy zeme. …","a ktorému bolo povedané: Po Izákovi sa bude volať tvoje potomstvo.","https://biblia.sk/citanie/seb/gn/26"],["Genezis 28:12","Most do neba — Jakubov rebrík","Ján 1:51","Vo sne videl rebrík postavený na zemi, ktorého vrchol sa dotýkal neba. Boží anjeli po ňom vystupovali a zostupovali.","Potom mu povedal: Amen, amen, hovorím vám, uvidíte otvorené nebo a Božích anjelov vystupovať a zostupovať na Syna človeka.","https://biblia.sk/citanie/seb/gn/28"],["Genezis 28:14","Potomok Jakuba","Lukáš 3:34","Tvojho potomstva bude ako prachu zeme. Rozmnožíš sa na západ i na východ, na sever i na juh. V tebe a v tvojom potomstve budú požehnané všetky rody zeme.","Jákob, Izák, Abrahám, Thara, Náchor,","https://biblia.sk/citanie/seb/gn/28"],["Genezis 49:10","Čas jeho príchodu","Lukáš 2:1–7; Galaťanom 4:4","Nevzdiali sa žezlo od Júdu ani vladárska berla od jeho nôh, kým z neho nevzíde vládca, ktorého budú poslúchať národy.","V tých dňoch cisár Augustus vydal príkaz vykonať súpis ľudu na celom svete. Tento prvý súpis sa konal, keď v Sýrii vládol Kyrenios. A všetci sa šli dať zapísať — každý do svojho mesta. … / Ale keď prišla plnosť času, Boh poslal svojho Syna narodeného zo ženy, narodeného pod zákonom,","https://biblia.sk/citanie/seb/gn/49"],["Genezis 49:10","Potomok Júdu","Lukáš 3:33","Nevzdiali sa žezlo od Júdu ani vladárska berla od jeho nôh, kým z neho nevzíde vládca, ktorého budú poslúchať národy.","Aminádab, Admin, Arni, Ezrom, Fáres, Júda,","https://biblia.sk/citanie/seb/gn/49"],["Genezis 49:10","Nazvaný Šílo — Poslaný","Ján 17:3","Nevzdiali sa žezlo od Júdu ani vladárska berla od jeho nôh, kým z neho nevzíde vládca, ktorého budú poslúchať národy.","A večný život je v tom, aby poznali teba, jediného, pravého Boha i toho, ktorého si poslal, Ježiša Krista.","https://biblia.sk/citanie/seb/gn/49"],["Genezis 49:10","Príde skôr, než Júda stratí svoju identitu","Ján 11:47–52","Nevzdiali sa žezlo od Júdu ani vladárska berla od jeho nôh, kým z neho nevzíde vládca, ktorého budú poslúchať národy.","Nato zvolali veľkňazi a farizeji veľradu a povedali: Čo robiť? Veď tento človek robí mnoho znamení! Ak ho necháme tak, všetci v neho uveria, prídu Rimania a zničia nám toto miesto i národ. Ale jeden z nich, Kajfáš, ktorý bol v tom roku veľkňazom, im povedal: Vy nič neviete …","https://biblia.sk/citanie/seb/gn/49"],["Genezis 49:10","Jemu bude patriť poslušnosť národov","Ján 10:16","Nevzdiali sa žezlo od Júdu ani vladárska berla od jeho nôh, kým z neho nevzíde vládca, ktorého budú poslúchať národy.","Mám aj iné ovce, ktoré nie sú z tohto ovčinca. Aj tie musím priviesť. Budú počúvať môj hlas a bude jedno stádo a jeden pastier.","https://biblia.sk/citanie/seb/gn/49"],["Exodus 3:13–15","Veľký JA SOM","Ján 4:26; 8:58","Mojžiš sa však Boha opýtal: Keď prídem k Izraelitom a poviem im: Boh vašich otcov ma posiela k vám a oni sa ma spýtajú: Aké je jeho meno? Čo im poviem? Boh povedal Mojžišovi: Ja som, ktorý som; a dodal: Izraelitom povieš: „Ja som“ ma poslal k vám. Boh ešte povedal Mojžišovi: Izraelitom povedz toto: Poslal ma k vám Hospodin, Boh vašich otcov — Boh Abraháma, Boh Izáka a Boh Jákoba. Toto je moje meno naveky, ktorým si ma budú pripomínať a vzývať z pokolenia na pokolenie.","Ježiš jej povedal: Ja som to — ten, čo sa rozpráva s tebou. / Ježiš im odpovedal: Amen, amen, hovorím vám: Skôr ako bol Abrahám, Ja som!","https://biblia.sk/citanie/seb/ex/3"],["Exodus 12:5","Baránok bez chyby","Hebrejom 9:14; 1. Petrov 1:19","Baránok musí byť bez chyby, ročný samček. Môžete ho vybrať z jahniat alebo z kozliat.","o to viac krv Krista, ktorý mocou večného Ducha sám seba priniesol Bohu ako nepoškvrnenú obetu, očistí nám svedomie od mŕtvych skutkov, aby sme mohli slúžiť živému Bohu. / ale drahou krvou Krista. On ako bezchybný a nepoškvrnený baránok","https://biblia.sk/citanie/seb/ex/12"],["Exodus 12:13","Krv Baránka zachraňuje pred hnevom","Rimanom 5:8","Vaším znamením bude krv na domoch, v ktorých bývate. Keď uvidím krv, obídem vás, takže vás zhubná rana nezastihne, keď budem biť Egypt.","No Boh dokazuje svoju lásku k nám tým, že Kristus zomrel za nás, keď sme boli ešte hriešni.","https://biblia.sk/citanie/seb/ex/12"],["Exodus 12:21–27","Kristus je náš veľkonočný Baránok","1. Korinťanom 5:7","Mojžiš zavolal všetkých starších Izraela a povedal im: Choďte, obstarajte si zviera zo stáda podľa svojich rodov a zarežte ho ako veľkonočného baránka. Potom vezmite zväzok yzopu, namočte ho v krvi, ktorá bude v miske, potrite ňou obe veraje aj ich hornú časť. Nech nikto z vás až do rána nevychádza z dverí svojho domu. Hospodin bude totiž prechádzať a biť Egypťanov. Keď uvidí krv na oboch verajach a ich hornej časti, Hospodin prejde popri dverách a Z hubcovi nedovolí vojsť do vašich domov a zabíjať. …","Vyčistite starý kvas, aby ste boli novým cestom, keďže ste nekvaseným chlebom; veď Kristus, náš veľkonočný Baránok, bol obetovaný.","https://biblia.sk/citanie/seb/ex/12"],["Exodus 12:46","Baránkovi nebude zlomená ani kosť","Ján 19:31–36","Musí sa zjesť v tom istom dome. Z mäsa sa nič nesmie vyniesť z domu. Nijakú kosť z neho nepolámete.","Pretože bol prípravný deň, Židia požiadali Piláta, aby dal ukrižovaným polámať kosti a sňať ich, aby ich telá nezostali na kríži v sobotu, lebo na tú sobotu pripadal veľký sviatok. Prišli teda vojaci a polámali nohy prvému i druhému, čo boli s ním ukrižovaní. Keď však prišli k Ježišovi a videli, že je už mŕtvy, nepolámali mu nohy, …","https://biblia.sk/citanie/seb/ex/12"],["Exodus 15:2","Jeho vyvýšenie predpovedané ako Ješua","Skutky 7:55–56","Mojou silou a ochranou je Hospodin, on sa mi stal spásou. On je môj Boh, velebím ho; Boh môjho otca, chcem ho vyvyšovať.","Ale on, plný Ducha Svätého, uprene sa zahľadel na nebo, videl Božiu slávu a Ježiša stáť po pravici Boha a povedal: Hľa, vidím otvorené nebo a Syna človeka stáť po pravici Boha.","https://biblia.sk/citanie/seb/ex/15"],["Exodus 15:11","Jeho povaha — svätosť","Lukáš 1:35; Skutky 4:27","Kto spomedzi bohov je taký ako ty, Hospodin? Kto sa ti vyrovná velebou svätosti? Divotvorca hrozný, hoden všetkej chvály?","Anjel jej odpovedal: Duch Svätý zostúpi na teba a zatôni ťa moc Najvyššieho, a preto aj dieťa bude sväté a bude sa volať Božím Synom. / Veď v tomto meste sa Herodes a Pontský Pilát naozaj spolčili s pohanmi a s izraelským ľudom proti tvojmu svätému Služobníkovi Ježišovi, ktorého si pomazal,","https://biblia.sk/citanie/seb/ex/15"],["Exodus 17:6","Duchovná Skala Izraela","1. Korinťanom 10:4","Tam budem stáť pred tebou na skale na Horebe. Keď udrieš skalu, vyjde z nej voda a ľud sa napije. Mojžiš to urobil pred očami starších Izraela.","a všetci pili ten istý duchovný nápoj, lebo pili z duchovnej skaly, ktorá ich sprevádzala, a tou skalou bol Kristus.","https://biblia.sk/citanie/seb/ex/17"],["Exodus 33:19","Jeho povaha — milosrdný","Lukáš 1:72","Hospodin mu povedal: Ukážem ti všetku svoju dobrotu a vyslovím pred tebou svoje meno Hospodin. Zmilujem sa, nad kým sa chcem zmilovať, a zľutujem sa, nad kým sa chcem zľutovať.","Preukázal milosrdenstvo našim otcom a rozpamätal sa na svoju svätú zmluvu, na prísahu, ktorou sa zaviazal nášmu otcovi Abrahámovi,","https://biblia.sk/citanie/seb/ex/33"],["Levitikus 1:2–9","Jeho obeta — príjemná vôňa Bohu","Efezanom 5:2","Prehovor k Izraelitom povedz im: Keď niekto z vás chce priniesť Hospodinovi obetný dar, prinesiete svoj obetný dar zo zvierat, z hovädzieho dobytka alebo z drobného stáda. Ak bude jeho obetným darom spaľovaná obeta z hovädzieho dobytka, nech privedie bezchybného samca. Privedie ho k vchodu stanu stretávania, aby získal Hospodinovu priazeň. Položí ruku na hlavu spaľovanej obety; tá bude so záľubou prijatá, aby získal zmierenie. …","a žite v láske, ako aj Kristus miloval nás a vydal samého seba za nás ako dar a obetu Bohu príjemnej vône.","https://biblia.sk/citanie/seb/lv/1"],["Levitikus 14:11","Očistený malomocný — znamenie kňazstvu","Lukáš 5:12–14; Skutky 6:7","Kňaz, ktorý očisťuje, postaví očisťovaného človeka s tým všetkým pred Hospodina k vchodu do stanu stretávania.","Keď bol Ježiš v ktoromsi meste, objavil sa pred ním človek s pokročilým malomocenstvom. Len čo zazrel Ježiša, padol na tvár a prosil ho: Pane, ak chceš, môžeš ma očistiť. On vystrel ruku, dotkol sa ho a povedal: Chcem, buď čistý! A malomocenstvo z neho ihneď zmizlo. Prikázal mu, aby nikomu o tom nehovoril. A potom mu povedal: Choď! Ukáž sa kňazovi! Prines obetu za svoje očistenie tak, ako to prikázal Mojžiš, na svedectvo pre nich! / Božie slovo sa šírilo a počet učeníkov v Jeruzaleme mimoriadne rástol. Aj veľké množstvo kňazov poslušne prijalo vieru.","https://biblia.sk/citanie/seb/lv/14"],["Levitikus 16:15–17","Predobraz Kristovej smrti raz a navždy","Hebrejom 9:7–14","Zareže capa na obetu za hriech ľudu a krv zanesie dnu za oponu. S krvou capa urobí to isté, čo urobil s krvou býčka; vykropí ju na vrchnák a pred vrchnák. Tým vykoná obrad zmierenia svätyne za nečistoty Izraelitov, za ich priestupky a za všetky ich hriechy. Tak nech urobí aj pri stane stretávania, ktorý je medzi nimi, uprostred ich nečistôt. Keď kňaz vojde do svätyne vykonať obrad zmierenia, nikto nesmie byť v stane stretávania, až kým nevyjde. Tam vykoná obrad zmierenia za seba, za svoj dom a za celé zhromaždenie Izraela.","Do druhého však vstupuje iba sám veľkňaz raz do roka, nie však bez krvi, ktorú prináša za svoje priestupky a za priestupky ľudu. Takto Duch Svätý naznačuje, že kým stojí prvý stánok, nie je ešte otvorená cesta do svätyne. To je prirovnanie pre terajší čas, keď sa prinášajú dary a obety, ktoré nemôžu vo svedomí urobiť dokonalým toho, kto koná bohoslužbu; …","https://biblia.sk/citanie/seb/lv/16"],["Levitikus 16:27","Utrpenie za táborom","Matúš 27:33; Hebrejom 13:11–12","Býčka na obetu za hriech a capa na obetu za hriech, ktorých krv vniesli do svätyne na obetu zmierenia, dá vyniesť za tábor. Ich kože, mäso a trus spáli.","Tak prišli na miesto zvané Golgota — to znamená Lebka, / Veď telá zvierat, ktorých krv veľkňaz prináša za hriechy do svätyne, spaľujú mimo tábora. Preto aj Ježiš trpel vonku za bránou, aby posvätil ľud svojou krvou.","https://biblia.sk/citanie/seb/lv/16"],["Levitikus 17:11","Krv — život tela","Matúš 26:28; Marek 10:45","Veď v krvi je život tela. Určil som vám ju na oltár na vykonávanie obradov zmierenia za váš život. Krvou, v ktorej je život, získava sa zmierenie.","Veď toto je moja krv zmluvy, ktorá sa vylieva za mnohých na odpustenie hriechov. / Lebo ani Syn človeka neprišiel, aby sa dal obsluhovať, ale aby sám slúžil a dal svoj život ako výkupné za mnohých.","https://biblia.sk/citanie/seb/lv/17"],["Levitikus 17:11","Krv je to, čo zmieruje","Rimanom 3:23–24; 1. Jánov 1:7","Veď v krvi je život tela. Určil som vám ju na oltár na vykonávanie obradov zmierenia za váš život. Krvou, v ktorej je život, získava sa zmierenie.","lebo všetci zhrešili a nemajú Božiu slávu. Ospravedlňovaní sú zadarmo, jeho milosťou, vykúpením v Ježišovi Kristovi. / Ale ak chodíme vo svetle, ako on je vo svetle, máme spoločenstvo medzi sebou a krv Ježiša, jeho Syna, nás očisťuje od každého hriechu.","https://biblia.sk/citanie/seb/lv/17"],["Levitikus 23:36–37","Obeta nápoja: „ak je niekto smädný…“","Ján 7:37","Sedem dní prinášajte Hospodinovi ohňovú obetu, ôsmy deň budete mať slávnostné zhromaždenie a prinesiete ohňovú obetu Hospodinovi. Je to sviatočné zhromaždenie. Nesmiete konať nijakú obvyklú prácu. Toto sú Hospodinove slávnosti, na ktoré budete zvolávať slávnostné zhromaždenie, aby ste prinášali Hospodinovi ohňovú obetu, spaľovanú obetu, pokrmovú obetu, obetu s hostinou a nápojovú obetu podľa predpisu na jednotlivé dni","Posledný veľký deň sviatkov Ježiš vstal a zvolal: Ak je niekto smädný, nech príde ku mne a nech sa napije ten,","https://biblia.sk/citanie/seb/lv/23"],["Numeri 9:12","Nebude mu zlomená ani kosť","Ján 19:31–36","Nech však z neho nič nenechajú do rána, ani mu nepolámu kosti. Sláviť budú podľa všetkých ustanovení o Pasche.","Pretože bol prípravný deň, Židia požiadali Piláta, aby dal ukrižovaným polámať kosti a sňať ich, aby ich telá nezostali na kríži v sobotu, lebo na tú sobotu pripadal veľký sviatok. Prišli teda vojaci a polámali nohy prvému i druhému, čo boli s ním ukrižovaní. Keď však prišli k Ježišovi a videli, že je už mŕtvy, nepolámali mu nohy, …","https://biblia.sk/citanie/seb/nm/9"],["Numeri 21:9","Had na žrdi — Kristus vyzdvihnutý","Ján 3:14–18; 12:32","Mojžiš teda zhotovil bronzového hada a pripevnil ho na žrď. Keď had niekoho uštipol a uštipnutý pozrel na bronzového hada, zostal nažive.","A ako Mojžiš vyzdvihol hada na púšti, tak musí byť vyzdvihnutý aj Syn človeka, aby každý, kto v neho verí, mal večný život. Veď Boh tak miloval svet, že dal svojho jednorodeného Syna, aby nezahynul nik, kto v neho verí, ale mal večný život. … / A ja, keď budem vyzdvihnutý zo zeme, všetkých pritiahnem k sebe.","https://biblia.sk/citanie/seb/nm/21"],["Numeri 24:17","Čas: „Vidím ho, ale nie teraz.“","Ján 1:14; Galaťanom 4:4","Vidím ho, ale zatiaľ neprítomného, hľadím naňho, ale nie zblízka. Vychádza hviezda z Jákoba, povstáva žezlo z Izraela. On prerazí spánky Moába i temeno všetkých Šétovcov.","A Slovo sa stalo telom a prebývalo medzi nami a my sme videli jeho slávu, slávu, akú má od Otca jednorodený Syn, plný milosti a pravdy. / Ale keď prišla plnosť času, Boh poslal svojho Syna narodeného zo ženy, narodeného pod zákonom,","https://biblia.sk/citanie/seb/nm/24"],["Deuteronómium 18:15","„Toto je naozaj ten prorok.“","Ján 6:14","Hospodin, tvoj Boh, ti vzbudí proroka, ako som ja, spomedzi vás, z tvojich bratov. Toho poslúchajte.","Ľudia, ktorí videli znamenie, čo vykonal Ježiš, hovorili: Toto je naozaj prorok, ktorý má prísť na svet.","https://biblia.sk/citanie/seb/dt/18"],["Deuteronómium 18:15–16","„Keby ste verili Mojžišovi, verili by ste mne.“","Ján 5:45–47","Hospodin, tvoj Boh, ti vzbudí proroka, ako som ja, spomedzi vás, z tvojich bratov. Toho poslúchajte. Bude to tak, ako si žiadal od Hospodina, svojho Boha, na Horebe v deň zhromaždenia, keď si vravel: Kiež už nepočujem hlas Hospodina, svojho Boha, a nevidím už ten veľký oheň, aby som nezomrel.","Nemyslite si, že ja budem na vás žalovať u Otca. Vaším žalobcom je Mojžiš, do ktorého ste vložili svoju nádej. Lebo keby ste verili Mojžišovi, verili by ste aj mne, veď on písal o mne. Ale ak neveríte jeho písmam, akože uveríte mojim slovám?!","https://biblia.sk/citanie/seb/dt/18"],["Deuteronómium 18:18","Poslaný Otcom hovoriť jeho slovo","Ján 8:28–29","Vzbudím im proroka ako si ty spomedzi ich bratov. Do úst mu vložím svoje slová a on im povie všetko, čo mu prikážem.","Ježiš im teda povedal: Keď vyzdvihnete Syna človeka, vtedy spoznáte, že Ja som a že nič nerobím sám od seba, ale hovorím tak, ako ma naučil Otec. A ten, čo ma poslal, je so mnou. Nenechal ma samého, pretože ja robím vždy to, čo sa jemu páči.","https://biblia.sk/citanie/seb/dt/18"],["Deuteronómium 18:19","Kto nepočúvne, ponesie svoj hriech","Skutky 3:22–23","Kto neposlúchne moje slová, ktoré bude hovoriť v mojom mene, toho vezmem na zodpovednosť.","Už Mojžiš povedal: Pán, váš Boh, vám vzbudí spomedzi vašich bratov proroka ako mňa. Budete ho počúvať vo všetkom, čo vám povie. A všetci, ktorí tohto proroka nebudú počúvať, budú z ľudu odstránení.","https://biblia.sk/citanie/seb/dt/18"],["Deuteronómium 21:23","Prekliaty, kto visí na dreve","Galaťanom 3:10–13","nenecháš jeho mŕtvolu na dreve cez noc, ale musíš ho pochovať ešte v ten deň, lebo obesenec je Bohom prekliaty. Preto si nepoškvrň pôdu, ktorú ti dáva Hospodin, tvoj Boh, do dedičného vlastníctva.","Ale všetci, čo sú zo skutkov podľa zákona, sú pod kliatbou, lebo je napísané: Prekliaty je každý, kto nezotrváva vo všetkom, čo je napísané v knihe zákona, a neplní to. Je zjavné, že pred Bohom nikto nie je ospravedlnený zo zákona, pretože spravodlivý bude žiť z viery. Zákon však nie je z viery, ale kto plní prikázania, bude žiť z nich. …","https://biblia.sk/citanie/seb/dt/21"],["Rút 4:4–10","Kristus, náš príbuzný, nás vykúpil","Efezanom 1:3–7","Rozhodol som sa, že ti poviem, aby si to pole kúpil pred prísediacimi staršími môjho ľudu. Ak ho chceš kúpiť, kúp ho, no ak nie, oznám mi to. Viem totiž, že okrem teba niet nikoho, kto by mal právo kúpiť ho. Ja nasledujem po tebe. Príbuzný povedal: ja ho kúpim. Bóaz však pokračoval: V ten deň, keď od Noémi kúpiš pole, dostaneš aj Moábčanku Rút, ženu po zosnulom, a máš povinnosť zachovať meno zosnulého s jeho dedičstvom. Príbuzný nato povedal: Nemôžem ho kúpiť pre seba, aby som nepoškodil vlastné dedičstvo. Právom príbuzenstva kúp ty, čo som mal kúpiť ja, lebo ja to nemôžem kúpiť. …","Požehnaný Boh a Otec nášho Pána Ježiša Krista, ktorý nás požehnal všetkým duchovným požehnaním cez naše spoločenstvo s Kristom v nebesiach. Veď ešte pred stvorením sveta si nás vyvolil, aby sme boli pred ním svätí a nepoškvrnení v láske. Podľa svojej milostivej vôle nás predurčil, aby sme boli skrze Ježiša Krista jeho synmi …","https://biblia.sk/citanie/seb/rut/4"],["1. Samuelova 2:35","Verný kňaz","Hebrejom 2:17; 3:1–3; 7:24–25","Ustanovím si verného kňaza, ktorý bude účinkovať podľa môjho srdca a zmýšľania. Dám mu trvalý dom; ustavične bude konať službu pred mojím pomazaným kráľom.","Preto sa vo všetkom musel pripodobniť bratom, aby sa stal milosrdným a verným veľkňazom pred Bohom a odčinil hriechy ľudu. / Preto, bratia, ktorí ste svätí a máte účasť na nebeskom povolaní, pozorne sa zahľaďte na Ježiša, apoštola a veľkňaza nášho vyznania. On je verný tomu, ktorý ho ustanovil, ako aj Mojžiš bol verný v celom jeho dome. On je však hoden o toľko väčšej slávy ako Mojžiš, o koľko má väčšiu česť staviteľ domu ako dom. / No tento, pretože zostáva naveky, má kňazstvo, ktoré neprechádza na iného. A preto môže aj dokonale spasiť tých, čo prostredníctvom neho prichádzajú k Bohu, lebo žije neustále, aby sa za nich prihováral.","https://biblia.sk/citanie/seb/1sam/2"],["2. Samuelova 7:12","Potomok Dávida","Matúš 1:1","Keď nadíde tvoj čas a ty sa pripojíš k tvojim otcom, vzbudím ti potomka, čo vzíde z teba, a upevním jeho kráľovskú moc.","Rodokmeň Ježiša Krista, syna Dávida, syna Abraháma.","https://biblia.sk/citanie/seb/2sam/7"],["2. Samuelova 7:13","Jeho kráľovstvo je večné","2. Petrov 1:11","On postaví dom na počesť môjho mena a ja natrvalo upevním jeho kráľovský trón.","Tak budete mať úplne zaistený prístup do večného kráľovstva nášho Pána a Spasiteľa Ježiša Krista.","https://biblia.sk/citanie/seb/2sam/7"],["2. Samuelova 7:14","Boží Syn","Lukáš 1:32; Rimanom 1:3–4","Budem mu otcom a on mi bude synom. Keď sa previní, potrescem ho palicou a údermi ako kohokoľvek z ľudí.","On sa bude volať synom Najvyššieho a Pán, Boh, mu dá trón jeho otca Dávida. / evanjelium o jeho Synovi, ktorý sa podľa tela narodil z Dávidovho potomstva a podľa Ducha svätosti je ustanovený od vzkriesenia z mŕtvych ako Boží Syn s mocou, evanjelium o Ježišovi Kristovi, našom Pánovi.","https://biblia.sk/citanie/seb/2sam/7"],["2. Samuelova 7:16","Dávidov dom upevnený naveky","Lukáš 3:31; Zjavenie 22:16","Tvoj rod bude pevný a tvoje kráľovstvo trvalé predo mnou, tvoj trón bude navždy pevný.","Melea, Mena, Matat, Nátan, Dávid, / Ja, Ježiš, som poslal svojho anjela, aby vám v cirkvách svedčil o týchto veciach. Ja som koreň a Dávidov rod, jasná ranná hviezda.","https://biblia.sk/citanie/seb/2sam/7"],["2. Kráľov 2:11","Telesné nanebovstúpenie predobrazené","Lukáš 24:51","Ako sa tak prechádzali a zhovárali, objavil sa zrazu ohnivý voz a ohnivé kone. Tie oddelili oboch od seba a E liáš sa vo víchrici vznášal do neba.","Keď ich žehnal, vzdialil sa od nich a vznášal sa do neba.","https://biblia.sk/citanie/seb/2krl/2"],["1. Kroník 17:11","Potomok Dávida","Matúš 1:1; 9:27","On mi postaví dom a ja mu natrvalo upevním trón.","Rodokmeň Ježiša Krista, syna Dávida, syna Abraháma. / Keď Ježiš odtiaľ odchádzal, išli za ním dvaja slepci, ktorí volali: Zmiluj sa nad nami, syn Dávidov!","https://biblia.sk/citanie/seb/1krn/17"],["1. Kroník 17:12–13","Bude naveky kraľovať na Dávidovom tróne","Lukáš 1:32–33","Budem mu otcom a on mi bude synom. Priazeň mu však neodnímem, ako som ju odňal tvojmu predchodcovi, ale ho ponechám vo svojom dome a vo svojom kráľovstve navždy, jeho trón bude vždy pevný.","On sa bude volať synom Najvyššieho a Pán, Boh, mu dá trón jeho otca Dávida. Bude kraľovať nad Jákobovým domom naveky a jeho kráľovstvu nebude konca.","https://biblia.sk/citanie/seb/1krn/17"],["1. Kroník 17:13","„Ja mu budem Otcom a on mi bude Synom.“","Hebrejom 1:5","ale ho ponechám vo svojom dome a vo svojom kráľovstve navždy, jeho trón bude vždy pevný.","Veď komu z anjelov Boh povedal: Ty si môj syn, ja som ťa dnes splodil? A opäť: Ja budem jeho otcom a on mi bude synom?","https://biblia.sk/citanie/seb/1krn/17"],["Jób 9:32–33","Prostredník medzi človekom a Bohom","1. Timotejovi 2:5","Ja predsa nie som mu roveň, aby som sa mohol ozvať: Poďme spolu na súd! Niet toho, kto by medzi nami rozhodol, kto by na oboch svoju ruku položil.","lebo jeden je Boh a jeden prostredník medzi Bohom a ľuďmi — človek Kristus Ježiš,","https://biblia.sk/citanie/seb/job/9"],["Jób 19:23–27","Predpovedané vzkriesenie","Ján 5:24–29","Kiežby sa moje slová zapisovali, kiežby sa dostali do knihy, železným rydlom a olovom naveky boli vyryté do kameňa! Ja viem, že môj Vykupiteľ žije a nakoniec sa postaví nad prachom! …","Amen, amen, hovorím vám: Kto počúva moje slovo a verí tomu, ktorý ma poslal, má večný život a nejde na súd, ale prešiel zo smrti do života. Amen, amen, hovorím vám: Prichádza hodina, ba už je tu, keď mŕtvi počujú hlas Božieho Syna a tí, čo ho počujú, budú žiť. Lebo ako Otec má život sám v sebe, tak dal aj Synovi, aby aj on mal život sám v sebe. …","https://biblia.sk/citanie/seb/job/19"],["Žalm 2:1–3","Nepriateľstvo kráľov vopred určené","Skutky 4:25–28","Prečo sa búria národy a ľudia vymýšľajú daromnosti? Spolčujú sa pozemskí králi, vládcovia sa spolu radia proti Hospodinovi a jeho pomazanému. Roztrhnime putá a odhoďme ich povrazy!","Ty si skrze Ducha Svätého povedal ústami nášho otca Dávida, tvojho služobníka: Prečo sa búria pohania a národy snujú daromné plány? Povstali pozemskí králi a vladári sa spolčili proti Pánovi a proti jeho Pomazanému. Veď v tomto meste sa Herodes a Pontský Pilát naozaj spolčili s pohanmi a s izraelským ľudom proti tvojmu svätému Služobníkovi Ježišovi, ktorého si pomazal, …","https://biblia.sk/citanie/seb/z/2"],["Žalm 2:2","Ponesie titul Pomazaný — Kristus","Ján 1:41; Skutky 2:36","Spolčujú sa pozemskí králi, vládcovia sa spolu radia proti Hospodinovi a jeho pomazanému.","Ten našiel najprv svojho brata Šimona a povedal mu: Našli sme Mesiáša, čo v preklade znamená okolo štvrtej popoludní Pomazaný. / Nech teda celý dom Izraela s istotou vie, že Boh toho Ježiša, ktorého ste vy ukrižovali, urobil Pánom aj Mesiášom.","https://biblia.sk/citanie/seb/z/2"],["Žalm 2:6","Jeho povaha — svätosť","Ján 8:46; Zjavenie 3:7","Ja som ustanovil svojho kráľa na Sione, na svojom svätom vrchu.","Kto z vás ma usvedčí z hriechu? A keď hovorím pravdu, prečo mi neveríte? / Anjelovi cirkvi vo Filadelfii napíš: Toto hovorí Svätý, Pravdivý, ktorý má Dávidov kľúč, ktorý otvára tak, že nikto nezatvorí, a zatvára tak, že nikto neotvorí.","https://biblia.sk/citanie/seb/z/2"],["Žalm 2:6","Ponesie titul Kráľ","Matúš 2:2","Ja som ustanovil svojho kráľa na Sione, na svojom svätom vrchu.","Pýtali sa: Kde je ten práve narodený židovský kráľ? Videli sme totiž na východe jeho hviezdu a prišli sme sa mu pokloniť.","https://biblia.sk/citanie/seb/z/2"],["Žalm 2:7","Vyhlásený za milovaného Syna","Matúš 3:17; Rimanom 1:4","Oznamujem rozhodnutie Hospodina. Povedal mi: Ty si môj syn, ja som ťa dnes splodil.","A z neba zaznel hlas: Toto je môj milovaný Syn, v ktorom som našiel zaľúbenie. / a podľa Ducha svätosti je ustanovený od vzkriesenia z mŕtvych ako Boží Syn s mocou, evanjelium o Ježišovi Kristovi, našom Pánovi.","https://biblia.sk/citanie/seb/z/2"],["Žalm 2:7–8","Naznačené ukrižovanie a vzkriesenie","Skutky 13:29–33","Oznamujem rozhodnutie Hospodina. Povedal mi: Ty si môj syn, ja som ťa dnes splodil. Požiadaj ma a dám ti národy ako dedičstvo, končiny zeme do vlastníctva.","Keď splnili všetko, čo bolo o ňom napísané, sňali ho z dreva a uložili do hrobu. Lenže Boh ho vzkriesil z mŕtvych a on sa viacero dní zjavoval tým, čo prišli spolu s ním z Galiley do Jeruzalema. Oni sú teraz jeho svedkami pred ľudom. …","https://biblia.sk/citanie/seb/z/2"],["Žalm 2:8–9","Bude vládnuť národom železným žezlom","Zjavenie 2:27; 12:5; 19:15","Požiadaj ma a dám ti národy ako dedičstvo, končiny zeme do vlastníctva. Rozbiješ ich železným prútom, roztlčieš ako hlinenú nádobu.","bude nad nimi vládnuť železnou berlou a rozbije ich ako hlinené nádoby — / Žena utiekla na púšť, kde jej Boh pripravil miesto, aby ju tam živili tisícdvestošesťdesiat dní. / Z úst mu vychádza ostrý meč, aby ním bil národy. Bude nad nimi vládnuť železnou berlou a sám bude šliapať lis s vínom rozhorčeného hnevu všemohúceho Boha.","https://biblia.sk/citanie/seb/z/2"],["Žalm 2:12","Život prichádza vierou v neho","Ján 20:31","Bozkávajte syna, aby sa nerozhneval a nezahynuli ste na ceste, lebo jeho hnev veľmi ľahko vzplanie. Blahoslavení sú všetci, čo sa k nemu utiekajú.","No tieto sú zapísané preto, aby ste verili, že Ježiš je Mesiáš, Boží Syn, a aby ste vierou mali život v jeho mene.","https://biblia.sk/citanie/seb/z/2"],["Žalm 8:2","Z úst detí zaznieva jeho chvála","Matúš 21:16","Zúst detí a dojčiat si si pripravil chválu proti svojim odporcom, aby si umlčal nepriateľa i pomstiteľa.","a povedali mu: Počuješ, čo hovoria? Ježiš im odpovedal: Pravdaže! Nikdy ste nečítali: Z úst batoliat a dojčeniec pripravil si si chválu?","https://biblia.sk/citanie/seb/z/8"],["Žalm 8:5–6","Jeho poníženie a vyvýšenie","Hebrejom 2:5–9","Urobil si ho len o niečo menším než nebeské bytosti. Korunoval si ho slávou a dôstojnosťou. Ustanovil si ho za vládcu nad dielom svojich rúk, všetko si mu položil pod nohy:","Veď Pán nepodriadil budúci svet, o ktorom hovoríme, anjelom. Tak o tom ktosi kdesi svedčí: Čo je človek, že naňho pamätáš, alebo syn človeka, že oňho dbáš? Postavil si ho nakrátko nižšie, ako sú anjeli, potom si ho ovenčil slávou a cťou …","https://biblia.sk/citanie/seb/z/8"],["Žalm 9:7–10","Bude súdiť svet v spravodlivosti","Skutky 17:31","Hospodin však tróni naveky, súdny stolec má pripravený. On bude spravodlivo súdiť svet, národy rozsúdi podľa práva. Hospodin je útočiskom utláčanému, útočiskom v čase súženia. …","Lebo určil deň, keď bude spravodlivo súdiť celý svet skrze muža, ktorého ustanovil. Všetkým o tom poskytol spoľahlivý dôkaz, keď ho vzkriesil z mŕtvych.","https://biblia.sk/citanie/seb/z/9"],["Žalm 16:10","Neuvidí porušenie","Skutky 2:31; 13:35","lebo ma nenecháš v ríši smrti a svojmu zbožnému nedáš uzrieť porušenie.","videl dopredu a Kristovo vzkriesenie ohlásil výrokom: Ani nebol ponechaný napospas podsvetiu, ani jeho telo nevidelo porušenie. / Preto aj na inom mieste hovorí: Nedopustíš, aby tvoj svätý uvidel porušenie.","https://biblia.sk/citanie/seb/z/16"],["Žalm 16:9–11","Vstane z mŕtvych","Ján 20:9","Preto sa srdce teší a duša mi plesá, ba aj telo bude v bezpečí, lebo ma nenecháš v ríši smrti a svojmu zbožnému nedáš uzrieť porušenie. Dávaš mi poznať cestu života, plnosť radosti v tvojej prítomnosti. Po tvojej pravici je večná blaženosť.","Ešte totiž nerozumeli Písmu, že má vstať z mŕtvych.","https://biblia.sk/citanie/seb/z/16"],["Žalm 17:15","Predpovedané vzkriesenie","Lukáš 24:6","Ja však v spravodlivosti uzriem tvoju tvár, keď sa prebudím, nasýtim sa tvojím obrazom.","Niet ho tu, bol vzkriesený. Spomeňte si, ako vám hovoril, keď bol ešte v Galilei:","https://biblia.sk/citanie/seb/z/17"],["Žalm 18:2–3","Roh spásy","Lukáš 1:69–71","Hospodin je moja skala, moja pevnosť a môj vysloboditeľ; môj Boh je moje bralo, k nemu sa utiekam; môj štít, roh mojej spásy a môj hrad. Volám k Hospodinovi, ktorý je hoden chvály, budem zachránený pred svojimi nepriateľmi.","a vzbudil nám mocného Spasiteľa v dome svojho služobníka Dávida, ako oddávna hovoril ústami svojich prorokov že nás oslobodí od našich nepriateľov a z rúk všetkých, čo nás nenávidia.","https://biblia.sk/citanie/seb/z/18"],["Žalm 22:1","Opustený pre hriechy iných","2. Korinťanom 5:21","Bože môj, Bože môj! Prečo si ma opustil? Ďaleko si od mojej spásy, ďaleko od môjho kriku.","Toho, ktorý nepoznal hriech, urobil za nás hriechom, aby sme sa v ňom stali Božou spravodlivosťou.","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:1","„Bože môj, Bože môj, prečo si ma opustil?“","Matúš 27:46","Bože môj, Bože môj! Prečo si ma opustil? Ďaleko si od mojej spásy, ďaleko od môjho kriku.","Okolo deviatej hodiny zvolal Ježiš silným hlasom: Éli, Éli, lema sabachthani?, čo znamená: Bože môj, Bože môj, prečo si ma opustil?","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:2","Tma nad Golgotou tri hodiny","Matúš 27:45","Bože môj, volám vo dne — neodpovedáš. Volám v noci — neviem sa utíšiť.","Od šiestej hodiny nastala tma po celej zemi, až do deviatej hodiny.","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:7","Vyškierajú sa a potriasajú hlavou","Matúš 27:39–44","Všetci, čo ma vidia, posmievajú sa mi, uškŕňajú sa, pokyvujú hlavou:","Tí, čo tade prechádzali, rúhali sa mu, výsmešne potriasali hlavou a hovorili: Ty, čo zbúraš chrám a za tri dni ho postavíš! Zachráň sám seba, ak si Syn Boží, a zostúp z kríža! Podobne sa mu posmievali aj veľkňazi so zákonníkmi a staršími: …","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:8","„Dúfal v Boha, nech ho vyslobodí.“","Matúš 27:43","Spoľahol sa na Hospodina, mal by ho zachrániť. Nech ho vytrhne, veď má v ňom záľubu.","Dúfal v Boha, nech ho teraz vyslobodí, ak ho má rád! Veď povedal: Som Boží Syn!","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:9–10","Narodený ako Spasiteľ","Lukáš 2:7","Veď ty si ma vytiahol z lona matky, na jej prsiach dával si mi nádej. Od svojho zrodu odkázaný som na teba, ty si môj Boh už od lona matky.","A porodila svojho prvorodeného syna. Zavinula ho do plienok a uložila do jasieľ, lebo v útulku pre nich nebolo miesta.","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:12–13","Usilujú o jeho smrť","Ján 19:6","Obkľúčilo ma mnoho juncov, bášanské býky ma obstúpili. Roztvorili tlamu proti mne ako dravý a revúci lev.","Len čo ho veľkňazi a ich sluhovia zazreli, kričali: Ukrižuj ho! Ukrižuj! Pilát im povedal: Vezmite si ho a vy ho ukrižujte! Lebo ja na ňom nenachádzam vinu!","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:14","Jeho krv vyliata pri prebodnutí boku","Ján 19:34","Som ako rozliata voda, uvoľnili sa mi všetky kosti. Moje srdce je ako vosk, roztopilo sa vo mne.","ale jeden z vojakov mu prebodol kopijou bok, odkiaľ hneď vyšla krv a voda.","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:14–15","Trpel muky na Golgote","Marek 15:34–37","Som ako rozliata voda, uvoľnili sa mi všetky kosti. Moje srdce je ako vosk, roztopilo sa vo mne. Hrdlo mi vyschlo ako črepiny, jazyk sa mi prilepil na podnebie, vrhol si ma do prachu smrti.","Keď to niektorí z okolostojacich počuli, povedali: Pozrite, volá Eliáša. Ktosi odbehol, namočil špongiu do octu, nastokol ju na trstinovú tyč, dával mu piť a hovoril: Nechajte ho, uvidíme, či ho príde Eliáš sňať. No Ježiš zvolal mocným hlasom a vydýchol. …","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:15","Bol smädný","Ján 19:28","Hrdlo mi vyschlo ako črepiny, jazyk sa mi prilepil na podnebie, vrhol si ma do prachu smrti.","Potom, keďže Ježiš vedel, že je už všetko dokonané, povedal, aby sa splnilo Písmo: Som smädný!","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:16","Prebodli mu ruky a nohy","Ján 19:34–37; 20:27","Psy ma obkľúčili, zovrela ma tlupa zlosynov, prebodli mi ruky a nohy.","ale jeden z vojakov mu prebodol kopijou bok, odkiaľ hneď vyšla krv a voda. Ten, čo to videl, vydal o tom svedectvo a jeho svedectvo je pravdivé. On vie, že hovorí pravdu — aby ste aj vy verili. Stalo sa to preto, aby sa splnilo Písmo: Kosť mu nebude zlomená. … / Potom povedal Tomášovi: Daj si sem prst a pozri si moje ruky! Daj sem ruku a vlož ju do môjho boku! a nebuď neveriaci, ale veriaci!","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:17–18","Vyzliekli ho pred očami ľudí","Lukáš 23:34–35","Môžem si spočítať všetky kosti. Oni sa prizerajú, oči si pasú na mne. Delia si moje rúcho, o môj odev losujú.","Ježiš povedal: Otče, odpusť im, lebo nevedia, čo robia. Potom si rozdelili jeho šaty a losovali o ne. Ľud tam stál a díval sa. Poprední muži sa mu vysmievali a hovorili: Iných zachraňoval, nech zachráni aj seba, ak je vyvolený Boží Mesiáš.","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:18","Rozdelili si jeho rúcho a hádzali lós","Ján 19:23–24","Delia si moje rúcho, o môj odev losujú.","Keď vojaci Ježiša ukrižovali, vzali jeho vrchné rúcho a rozdelili ho na štyri časti, každému vojakovi jednu. Vzali aj jeho spodný odev, ktorý však bol nezošívaný, ale odhora nadol vcelku utkaný. Preto si medzi sebou povedali: Netrhajme ho, ale žrebujme oň, čí bude! Tým sa naplnilo Písmo: Rozdelili si moje rúcho a o môj odev hodili žreb. A vojaci to tak aj urobili.","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:20–21","Odovzdal sa Bohu","Lukáš 23:46","Zachráň mi pred mečom život, to jediné, čo mám, z moci psov. Vytrhni ma z tlamy levovej, spred rohov byvolov! — A ty si ma vypočul.","Tu zvolal Ježiš silným hlasom: Otče, do tvojich rúk porúčam svojho ducha. Keď to povedal, dokonal.","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:20–21","Satan raní Vykupiteľovu pätu","Hebrejom 2:14","Zachráň mi pred mečom život, to jediné, čo mám, z moci psov. Vytrhni ma z tlamy levovej, spred rohov byvolov! — A ty si ma vypočul.","Keďže všetkých súrodencov spája krv a telo, i on sa stal jedným z nich, aby smrťou zničil toho, čo mal moc nad smrťou, totiž diabla,","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:22","Ohlásené jeho vzkriesenie","Ján 20:17","Svojim bratom chcem ohlasovať tvoje meno, v zhromaždení ťa chcem chváliť.","Ježiš jej povedal: Nedrž ma zato, že som ešte nevystúpil k Otcovi, ale choď k mojim bratom a povedz im: Vystupujem k svojmu Otcovi a k vášmu Otcovi, k svojmu Bohu a k vášmu Bohu.","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:27–28","Bude vládcom národov","Kolosanom 1:16","Všetky končiny zeme sa rozpomenú a vrátia sa k Hospodinovi. Všetky kmene národov budú sa ti klaňať. Hospodinovi patrí vláda, on panuje nad národmi.","Veď v ňom bolo stvorené všetko na nebi i na zemi, viditeľné i neviditeľné, tróny i panstvá, kniežatstvá a mocnosti, všetko je stvorené skrze neho a pre neho.","https://biblia.sk/citanie/seb/z/22"],["Žalm 22:31","„Je dokonané.“","Ján 19:30; Hebrejom 10:10–18","Bude prichádzať a zvestovať jeho spravodlivosť budúcemu ľudu: On to urobil.","Keď Ježiš okúsil ocot, povedal: Je dokonané! Naklonil hlavu a odovzdal ducha. / V tejto vôli sme raz a navždy posvätení obetou tela Ježiša Krista. Každý kňaz stojí a koná denne bohoslužbu a veľa ráz prináša tie isté obety, ktoré nijako nemôžu odstrániť hriechy. No Kristus priniesol jednu obetu za hriechy a navždy zasadol po pravici Boha. …","https://biblia.sk/citanie/seb/z/22"],["Žalm 23:1","„Ja som dobrý pastier.“","Ján 10:11; 1. Petrov 2:25","Dávidov žalm. Hospodin je môj pastier, nič mi nechýba.","Ja som dobrý pastier. Dobrý pastier kladie svoj život za ovce. / Boli ste totiž ako blúdiace ovce, no teraz ste sa vrátili k pastierovi a biskupovi svojich duší. Bohu milé.","https://biblia.sk/citanie/seb/z/23"],["Žalm 24:3","Predpovedané jeho vyvýšenie","Skutky 1:11; Filipanom 2:9","Kto smie vystúpiť na vrch Hospodina? Kto sa smie postaviť na jeho svätom mieste?","a povedali: Muži galilejskí, čo stojíte a hľadíte do neba? Tento Ježiš, ktorý bol vzatý od vás do neba, príde tak, ako ste ho videli odchádzať do neba. / Preto ho Boh nad všetko povýšil a dal mu meno nad každé meno,","https://biblia.sk/citanie/seb/z/24"],["Žalm 27:12","Povstávajú proti nemu falošní svedkovia","Matúš 26:60–61","Nevydaj ma napospas utláčateľom, veď sa proti mne postavili falošní svedkovia; srší z nich krutosť.","Nenašli ho však, hoci prišlo mnoho falošných svedkov. Napokon prišli dvaja a hovorili: Tento povedal: Môžem zbúrať Boží chrám a za tri dni ho postaviť.","https://biblia.sk/citanie/seb/z/27"],["Žalm 30:3","Predpovedané jeho vzkriesenie","Skutky 2:32","Hospodin, vyviedol si ma z ríše mŕtvych16. Zachoval si ma pri živote, aby som nezostúpil do hrobu.","Tohto Ježiša Boh vzkriesil a svedkami toho sme my všetci.","https://biblia.sk/citanie/seb/z/30"],["Žalm 31:5","„Do tvojich rúk porúčam svojho ducha.“","Lukáš 23:46","Svojho ducha zverujem do tvojej ruky. Vykúpil si ma, Hospodin, verný Bože.","Tu zvolal Ježiš silným hlasom: Otče, do tvojich rúk porúčam svojho ducha. Keď to povedal, dokonal.","https://biblia.sk/citanie/seb/z/31"],["Žalm 31:11","Jeho známi od neho utiekli","Marek 14:50","Všetci moji odporcovia, najmä susedia, ma potupujú. S om postrachom svojim známym. Tí, čo ma vidia na verejnosti, utekajú predo mnou.","Vtedy ho všetci opustili a rozutekali sa.","https://biblia.sk/citanie/seb/z/31"],["Žalm 31:13","Radili sa, ako ho usmrtiť","Matúš 27:1; Ján 11:53","Počul som predsa šepkanie mnohých: Hrôza zo všetkých strán! S polčili sa proti mne, radia sa, ako by mi vzali život.","Na úsvite všetci veľkňazi a starší ľudu vyniesli rozhodnutie proti Ježišovi, že ho treba usmrtiť. / A od toho dňa boli rozhodnutí, že ho zabijú.","https://biblia.sk/citanie/seb/z/31"],["Žalm 31:14–15","„Dúfal v Boha, nech ho vyslobodí.“","Matúš 27:43","Ja len tebe dôverujem, Hospodin. Povedal som: Ty si môj Boh. V tvojej ruke je môj čas. Vytrhni ma z moci nepriateľov a prenasledovateľov.","Dúfal v Boha, nech ho teraz vyslobodí, ak ho má rád! Veď povedal: Som Boží Syn!","https://biblia.sk/citanie/seb/z/31"],["Žalm 34:20","Nebude mu zlomená ani kosť","Ján 19:31–36","Chráni mu všetky kosti, ani jediná sa mu nezlomí.","Pretože bol prípravný deň, Židia požiadali Piláta, aby dal ukrižovaným polámať kosti a sňať ich, aby ich telá nezostali na kríži v sobotu, lebo na tú sobotu pripadal veľký sviatok. Prišli teda vojaci a polámali nohy prvému i druhému, čo boli s ním ukrižovaní. Keď však prišli k Ježišovi a videli, že je už mŕtvy, nepolámali mu nohy, …","https://biblia.sk/citanie/seb/z/34"],["Žalm 35:11","Povstali proti nemu falošní svedkovia","Matúš 26:59–61","Povstávajú podlí svedkovia a vypytujú sa ma na to, o čom ani neviem.","Veľkňazi a celá Veľrada zháňali krivé svedectvo proti Ježišovi, aby ho mohli usmrtiť. Nenašli ho však, hoci prišlo mnoho falošných svedkov. Napokon prišli dvaja a hovorili: Tento povedal: Môžem zbúrať Boží chrám a za tri dni ho postaviť.","https://biblia.sk/citanie/seb/z/35"],["Žalm 35:19","Nenávideli ho bez príčiny","Ján 15:25","Nech sa neradujú nado mnou podlí nepriatelia, nech nepožmurkávajú tí, čo ma bezdôvodne nenávidia.","Ale to preto, aby sa naplnilo slovo, napísané v ich zákone: Nenávideli ma bez príčiny.","https://biblia.sk/citanie/seb/z/35"],["Žalm 38:11","Jeho priatelia stáli obďaleč","Lukáš 23:49","Moji milí a priatelia neuniesli moju chorobu. Moji príbuzní stoja obďaleč.","Všetci jeho známi však stáli obďaleč. Aj ženy, ktoré ho nasledovali z Galiley, na to pozerali.","https://biblia.sk/citanie/seb/z/38"],["Žalm 38:12","Nepriatelia ho chceli chytiť ľsťou","Marek 14:1; Matúš 22:15","Tí, čo za mnou sliedia, nastavili mi pascu. Tí, čo mi chcú zle, radili sa, ako ma zničia. Celé dni vymýšľajú úklady,","Boli dva dni pred Veľkou nocou a sviatkom nekvasených chlebov. Veľkňazi a zákonníci hľadali spôsob, ako by sa úskokom zmocnili Ježiša a zabili ho. / Vtedy farizeji odišli a dohodli sa, ako ho podchytia v reči.","https://biblia.sk/citanie/seb/z/38"],["Žalm 38:12–13","Mlčal pred žalobcami","Matúš 27:12–14","Tí, čo za mnou sliedia, nastavili mi pascu. Tí, čo mi chcú zle, radili sa, ako ma zničia. Celé dni vymýšľajú úklady, ale ja som ako hluchý. Nepočujem. Som ako nemý, čo ústa neotvorí.","A keď ho veľkňazi a starší obviňovali, nič neodpovedal. Vtedy sa ho Pilát pýtal: Nepočuješ, čo všetko svedčia proti tebe? Ale on mu neodpovedal ani na jediné slovo, takže sa vladár veľmi čudoval.","https://biblia.sk/citanie/seb/z/38"],["Žalm 38:20","Chodil a dobre robil","Skutky 10:38","odplácajú sa mi zlým za dobré a napádajú ma za snahu o dobro.","Viete o Ježišovi z Nazareta, ako ho Boh pomazal Duchom Svätým a mocou, takže chodil, dobre robil a liečil všetkých diablom posadnutých, pretože Boh bol s ním.","https://biblia.sk/citanie/seb/z/38"],["Žalm 40:2–5","Predpovedaná radosť jeho vzkriesenia","Ján 20:20","Vytiahol ma z jamy hrôzy, z bahna a blata. N ohy mi postavil na skalu a spevňuje moje kroky. Do úst mi vkladá novú pieseň, chválospev na nášho Boha. Mnohí to uvidia, budú sa báť a dúfať v Hospodina. Blahoslavený muž, ktorý svoju nádej vkladá do Hospodina a neobracia sa k nafúkancom21 ani k tým, čo sa uchyľujú ku klamstvu. …","Keď to povedal, ukázal im ruky a bok. Učeníci sa zaradovali, keď videli Pána.","https://biblia.sk/citanie/seb/z/40"],["Žalm 40:6–8","Jeho záľuba — Otcova vôľa","Ján 4:34; Hebrejom 10:5–10","Obetu ani dary si nepraješ, ale otvoril si mi uši. S paľovanú obetu ani obetu za hriech si nežiadal. Vtedy som povedal: Hľa, prichádzam. Vo zvitku je napísané o mne, že mám plniť tvoju vôľu. A to chcem, Bože môj, vo svojom vnútri mám tvoj zákon.","Ježiš im povedal: Mojím pokrmom je plniť vôľu toho, čo ma poslal, a dokonať jeho dielo. / A preto keď Kristus prichádza na svet, hovorí: Obety ani dary si neželáš, ale dal si mi telo. Spaľované obety, ani obety za hriech sa ti nepáčili. Vtedy som povedal: Hľa, prichádzam, — vo zvitku knihy je o mne napísané — aby som plnil tvoju vôľu, Bože. …","https://biblia.sk/citanie/seb/z/40"],["Žalm 40:9","Bude hlásať spravodlivosť v Izraeli","Matúš 4:17","Radostne som oznámil spravodlivosť vo veľkom zhromaždení. Nezavrel som svoje ústa, Hospodin, ty to vieš.","Odvtedy začal Ježiš kázať: Kajajte sa, lebo sa priblížilo nebeské kráľovstvo.","https://biblia.sk/citanie/seb/z/40"],["Žalm 40:14","Konfrontovaný protivníkmi v záhrade","Ján 18:4–6","Nech sa zahanbia a zapýria všetci, čo ma chcú pripraviť o život. N ech odtiahnu zahanbene tí, čo sa tešia z môjho nešťastia.","No Ježiš, pretože vedel o všetkom, čo sa malo s ním stať, podišiel a opýtal sa ich: Koho hľadáte? Odpovedali mu: Ježiša Nazaretského. On im povedal: Ja som!. Aj Judáš, jeho zradca, bol s nimi. Len čo im Ježiš povedal: Ja som!, cúvli a padli na zem.","https://biblia.sk/citanie/seb/z/40"],["Žalm 41:9","Zradený dôverným priateľom","Ján 13:18","Ba aj môj priateľ, ktorému som dôveroval, čo jedával môj chlieb, sa odo mňa odvrátil.","Nehovorím to o vás všetkých. Ja viem, ktorých som si vyvolil; ale aby sa naplnilo Písmo: Ten, čo je môj chlieb, zdvihol proti mne pätu.","https://biblia.sk/citanie/seb/z/41"],["Žalm 45:2","Z jeho perí plynú slová milosti","Ján 1:17; Lukáš 4:22","Ty si najkrajší z ľudských synov, z tvojich pier plynie milota. Preto ťa Boh požehnal naveky.","Zákon bol totiž daný skrze Mojžiša, no milosť a pravda prišli skrze Ježiša Krista. / Všetci mu prisviedčali a obdivovali jeho láskavú reč, ktorá plynula z jeho úst. A hovorili si: Či to nie je Jozefov syn?","https://biblia.sk/citanie/seb/z/45"],["Žalm 45:6","Ponesie titul Boh — Elohim","Hebrejom 1:8","Tvoj trón je trón od Boha na večné veky a žezlo tvojho kráľovstva je žezlom práva.","O Synovi však: Tvoj trón, Bože, je na veky vekov a žezlo tvojho práva je žezlom tvojho kráľovstva.","https://biblia.sk/citanie/seb/z/45"],["Žalm 45:7","Osobitné pomazanie Duchom Svätým","Matúš 3:16; Hebrejom 1:9","Miluješ spravodlivosť a nenávidíš bezbožnosť, preto ťa hojnejšie pomazal Boh, tvoj Boh, olejom radosti ako tvojich druhov.","Po krste Ježiš hneď vystúpil z vody. Vtom sa mu otvorili nebesia a videl Božieho Ducha, ktorý sťa holubica zostupoval naňho. / Miloval si spravodlivosť a nenávidel neprávosť, preto ťa Boh, tvoj Boh, pomazal olejom plesania nad tvojich druhov.","https://biblia.sk/citanie/seb/z/45"],["Žalm 45:7–8","Nazvaný Kristus — Mesiáš, Pomazaný","Lukáš 2:11","Miluješ spravodlivosť a nenávidíš bezbožnosť, preto ťa hojnejšie pomazal Boh, tvoj Boh, olejom radosti ako tvojich druhov. Každé tvoje rúcho vonia myrhou, od aloy a škorice. Z palácov zdobených slonovinou ťa rozveseľuje hudba strún.","lebo v Dávidovom meste sa vám dnes narodil Spasiteľ, Kristus Pán.","https://biblia.sk/citanie/seb/z/45"],["Žalm 45:17","Jeho meno bude pripomínané naveky","Efezanom 1:20–21; Hebrejom 1:8","Tvoje meno budem pripomínať všetkým pokoleniam. Preto ťa národy budú oslavovať na večné veky.","Tú dokázal na Kristovi, keď ho vzkriesil z mŕtvych a posadil v nebi po svojej pravici nad každé kniežatstvo, moc, silu a panstvo a nad každé meno, ktoré sa spomína nielen v tomto, ale aj v budúcom veku. / O Synovi však: Tvoj trón, Bože, je na veky vekov a žezlo tvojho práva je žezlom tvojho kráľovstva.","https://biblia.sk/citanie/seb/z/45"],["Žalm 55:12–14","Zradený priateľom, nie nepriateľom","Ján 13:18","Keby ma tupil nepriateľ, to by som zniesol. Keby sa nado mnou vypínal nenávistník, pred ním by som sa skryl. Si to však ty, človek ako ja, môj druh a dôverný priateľ, s ktorým ma spájalo milé priateľstvo. S polu sme chodievali v jasavom sprievode do Božieho domu.","Nehovorím to o vás všetkých. Ja viem, ktorých som si vyvolil; ale aby sa naplnilo Písmo: Ten, čo je môj chlieb, zdvihol proti mne pätu.","https://biblia.sk/citanie/seb/z/55"],["Žalm 55:15","Zradcova smrť bez pokánia","Matúš 27:3–5; Skutky 1:16–19","Nech ich stihne smrť! Zaživa nech zostúpia do ríše mŕtvych, lebo v ich príbytkoch i v nich je plno zloby!","Keď zradca Judáš videl, že Ježiša odsúdili, rozľútostený vrátil tridsať strieborných veľkňazom a starším slovami: Zhrešil som, lebo som zradil nevinnú krv. Ale oni mu povedali: Čo nás do toho? To je tvoja vec! On odhodil strieborné peniaze do chrámu a vzdialil sa. Potom odišiel a obesil sa. / Muži, bratia! Muselo sa splniť, čo Duch Svätý ústami Dávida predpovedal v Písme o Judášovi, ktorý priviedol tých, čo zatkli Ježiša. Judáš bol jedným z nás a dostal podiel na tejto službe. Z odmeny za svoju ničomnosť si kúpil pole, no hneď nato spadol z výšky dolu hlavou, pričom ho roztrhlo tak, že sa z neho vyvalili všetky vnútornosti. …","https://biblia.sk/citanie/seb/z/55"],["Žalm 68:18","Dá ľuďom dary","Efezanom 4:7–16","Vystúpil si na výšinu, priviedol si zajatcov, ľudí si prijal do daru27, ešte aj odbojníkov, aby si trónil Hospodin, Bože!","Každému z nás však bola daná milosť podľa miery Kristovho daru. Preto je povedané: Keď vystúpil na výšiny, zajal zajatcov a ľuďom dal dary. A čo iné znamená „vystúpil“, ako že aj zostúpil do nižších častí zeme? …","https://biblia.sk/citanie/seb/z/68"],["Žalm 68:18","Vystúpil do neba","Lukáš 24:51","Vystúpil si na výšinu, priviedol si zajatcov, ľudí si prijal do daru27, ešte aj odbojníkov, aby si trónil Hospodin, Bože!","Keď ich žehnal, vzdialil sa od nich a vznášal sa do neba.","https://biblia.sk/citanie/seb/z/68"],["Žalm 69:4","Nenávidený bez príčiny","Ján 15:25","Viac ako vlasov na mojej hlave je tých, čo ma bez príčiny nenávidia. Mocní sú tí, čo ma chcú zničiť, podlí nepriatelia. — Mám nahradiť, čo som neulúpil? —","Ale to preto, aby sa naplnilo slovo, napísané v ich zákone: Nenávideli ma bez príčiny.","https://biblia.sk/citanie/seb/z/69"],["Žalm 69:8","Cudzí vlastným bratom","Ján 1:11; 7:5","Za cudzieho ma pokladajú vlastní bratia, cudzincom som pre synov svojej matky,","Do svojho vlastného prišiel, ale jeho vlastní ho neprijali. / Totiž ani jeho bratia neverili v neho.","https://biblia.sk/citanie/seb/z/69"],["Žalm 69:9","Horlivosť za Pánov dom","Ján 2:17","lebo horlenie za tvoj dom ma strávilo a hany tých, čo ťa tupia, padli na mňa.","Tu si jeho učeníci spomenuli, že je napísané: Horlivosť za tvoj dom ma stravuje.","https://biblia.sk/citanie/seb/z/69"],["Žalm 69:14–20","Úzkosť duše pred ukrižovaním","Matúš 26:36–45","Vytiahni ma z bahna, aby som sa neutopil! Osloboď ma od tých, čo ma nenávidia, zachráň ma z hlbokých vôd, aby ma neodniesol vodný prúd, aby ma nepohltila hlbočina a studňa nezavrela ústa nado mnou. Ozvi sa mi, Hospodin, lebo tvoja milosť je dobrotivá. Pre svoje hojné zľutovanie obráť sa ku mne. …","Vtedy Ježiš prišiel s nimi na miesto, ktoré sa volá Getsemani, a povedal učeníkom: Sadnite si, kým odídem tamto a pomodlím sa. Vzal so sebou Petra i dvoch Zebedejových synov a začal pociťovať zármutok a úzkosť. Vtedy im povedal: Moja duša je smutná až na smrť. Zostaňte tu a bedlite so mnou. …","https://biblia.sk/citanie/seb/z/69"],["Žalm 69:20","„Moja duša je smutná až na smrť.“","Matúš 26:38","Pohana mi zlomila srdce, som z toho celkom chorý. Očakával som súcit, ale márne, tých, čo by potešili, no nebolo ich.","Vtedy im povedal: Moja duša je smutná až na smrť. Zostaňte tu a bedlite so mnou.","https://biblia.sk/citanie/seb/z/69"],["Žalm 69:21","V smäde mu dali ocot","Matúš 27:34","Do jedla mi pridávali jed, smäd mi uhášali octom.","a dali mu piť víno zmiešané so žlčou. Ale keď to ochutnal, nechcel piť.","https://biblia.sk/citanie/seb/z/69"],["Žalm 69:26","Spasiteľ daný a zbitý Bohom","Ján 17:4; 18:11","Veď prenasledujú toho, koho si už ranil, hovoria o bolesti tých, ktorých si zasiahol.","Ja som ťa oslávil na zemi tým, že som dokonal dielo, ktoré si mi dal vykonať. / Ale Ježiš povedal Petrovi: Schovaj meč do pošvy! Azda nemám vypiť kalich, ktorý mi dal Otec?","https://biblia.sk/citanie/seb/z/69"],["Žalm 72:10–11","Navštívia ho vznešení s darmi","Matúš 2:1–11","Králi Taršíša a ostrovov nech prinesú dary, králi Šeby29\">a Sáby nech prinesú poplatky. Nech sa mu klaňajú všetci králi, nech mu slúžia všetky národy.","Keď sa za čias kráľa Herodesa v judskom Betleheme narodil Ježiš, prišli do Jeruzalema mudrci z východu. Pýtali sa: Kde je ten práve narodený židovský kráľ? Videli sme totiž na východe jeho hviezdu a prišli sme sa mu pokloniť. Keď to počul kráľ Herodes, rozrušil sa a s ním aj celý Jeruzalem. …","https://biblia.sk/citanie/seb/z/72"],["Žalm 72:16","Pšeničné zrno padne do zeme","Ján 12:24–25","Nech je v krajine hojnosť obilia, nech sa vlní na vrcholoch kopcov. N ech prináša ovocie ako Libanon, nech rozkvitajú mestá ako tráva zeme.","Amen, amen, hovorím vám: Ak pšeničné zrno, ktoré padne do zeme, neodumrie, zostane samo. Ale ak odumrie, prinesie veľkú úrodu. Kto miluje svoj život, stratí ho, a kto svoj život na tomto svete nenávidí, zachová si ho pre večný život.","https://biblia.sk/citanie/seb/z/72"],["Žalm 72:17","Viera v jeho meno plodí potomstvo","Ján 1:12–13","Nech jeho meno trvá naveky, nech jeho meno prekvitá, kým trvá slnko. N ech mu dobrorečia, nech ho blahoslavia všetky národy!","Tým však, čo ho prijali a veria v jeho meno, dal moc stať sa Božími deťmi; tí, čo sa nenarodili ani z krvi, ani z telesnej žiadosti, ani z vôle muža, ale z Boha.","https://biblia.sk/citanie/seb/z/72"],["Žalm 72:17","V ňom budú požehnané všetky národy","Galaťanom 3:8","Nech jeho meno trvá naveky, nech jeho meno prekvitá, kým trvá slnko. N ech mu dobrorečia, nech ho blahoslavia všetky národy!","Keďže sa v Písme predvídalo, že Boh z viery ospravedlňuje pohanov, už Abrahám dostal prísľub: V tebe budú požehnané všetky národy.","https://biblia.sk/citanie/seb/z/72"],["Žalm 72:17","Všetky národy ho budú blahoslaviť","Ján 12:13; Zjavenie 5:8–12","Nech jeho meno trvá naveky, nech jeho meno prekvitá, kým trvá slnko. N ech mu dobrorečia, nech ho blahoslavia všetky národy!","Nabrali palmových ratolestí, vyšli mu v ústrety a volali: „Hosanna! Požehnaný, ktorý prichádza v mene Pánovom, kráľ Izraela!“ / A potom, čo ju vzal, štyri bytosti a dvadsaťštyri starších padlo pred Baránkom. Všetci mali citary a zlaté čaše plné kadidla, čo sú modlitby svätých. A spievali novú pieseň: Hoden si vziať knihu a otvoriť jej pečate, lebo si bol zabitý a svojou krvou si Bohu vykúpil ľudí z každého kmeňa, jazyka, ľudu i národa, urobil si ich kráľovstvom a kňazmi nášmu Bohu, oni budú kraľovať na zemi. …","https://biblia.sk/citanie/seb/z/72"],["Žalm 78:1–2","Bude učiť v podobenstvách","Matúš 13:34–35","Asáfov poučný žalm. Ľud môj, počúvaj moje poučenie! Svoje ucho nakloň k slovám mojich úst. Chcem hovoriť príslovia, vyrozprávať záhadné príbehy dávnych čias,","Toto všetko hovoril Ježiš zástupom v podobenstvách. Bez podobenstiev im nehovoril nič, aby sa splnilo, čo bolo povedané ústami proroka: Otvorím svoje ústa v podobenstvách, vyrozprávam, čo bolo skryté od založenia sveta.","https://biblia.sk/citanie/seb/z/78"],["Žalm 78:2","Hovorí Božiu múdrosť s mocou","Matúš 7:29","Chcem hovoriť príslovia, vyrozprávať záhadné príbehy dávnych čias,","Učil ich totiž ako taký, čo má moc, a nie ako ich zákonníci.","https://biblia.sk/citanie/seb/z/78"],["Žalm 80:17","Muž Božej pravice","Marek 14:61–62","Drž ruku nad mužom svojej pravice, nad synom človeka, ktorého si si vychoval.","On však mlčal a nič neodpovedal. Preto mu veľkňaz znova položil otázku: Si ty Mesiáš, syn Požehnaného? Nato Ježiš odpovedal: Ja som. Uvidíte Syna človeka sedieť po pravici Moci a prichádzať s nebeskými oblakmi.","https://biblia.sk/citanie/seb/z/80"],["Žalm 88","Utrpenie a potupa Golgoty","Matúš 27:26–50","Hospodin, Boh mojej spásy, k tebe volám dňom i nocou. Kiež moja modlitba prenikne k tebe, nakloň ucho k môjmu náreku! Moja duša sa presýtila trápením, môj život sa už dotkol ríše mŕtvych. …","Vtedy im prepustil Barabbáša, Ježiša však dal zbičovať a vydal ho, aby ho ukrižovali. Vladárovi vojaci vzali Ježiša do vládnej budovy a zhromaždili okolo neho celú kohortu. Vyzliekli ho a obliekli do purpurového plášťa, …","https://biblia.sk/citanie/seb/z/88"],["Žalm 88:8","Stáli obďaleč a prizerali sa","Lukáš 23:49","Vzdialil si odo mňa mojich známych, sprotivil si ma pred nimi. Som uväznený, nemôžem vyjsť.","Všetci jeho známi však stáli obďaleč. Aj ženy, ktoré ho nasledovali z Galiley, na to pozerali.","https://biblia.sk/citanie/seb/z/88"],["Žalm 89:26","Mesiáš bude volať Boha svojím Otcom","Matúš 11:27","Bude ma vzývať: Ty si môj Otec, môj Boh a skala mojej spásy.","Všetko mi odovzdal môj Otec. Nikto nepozná Syna, iba Otec a ani Otca nepozná nikto, iba Syn a ten, komu to chce Syn zjaviť.","https://biblia.sk/citanie/seb/z/89"],["Žalm 89:27","Emanuel vyšší než pozemskí králi","Lukáš 1:32–33","Ustanovím ho za prvorodeného, za najvyššieho medzi kráľmi zeme.","On sa bude volať synom Najvyššieho a Pán, Boh, mu dá trón jeho otca Dávida. Bude kraľovať nad Jákobovým domom naveky a jeho kráľovstvu nebude konca.","https://biblia.sk/citanie/seb/z/89"],["Žalm 89:35–37","Dávidovo potomstvo, trón a kráľovstvo naveky","Lukáš 1:32–33","Raz navždy som na svoju svätosť prisahal, že nesklamem Dávida: Jeho rod bude trvať naveky, jeho trón bude predo mnou ako slnko. Naveky bude stáť pevne ako mesiac, verný svedok nad oblakmi. — Sela —","On sa bude volať synom Najvyššieho a Pán, Boh, mu dá trón jeho otca Dávida. Bude kraľovať nad Jákobovým domom naveky a jeho kráľovstvu nebude konca.","https://biblia.sk/citanie/seb/z/89"],["Žalm 90:2","Je od večnosti","Ján 1:1","Skôr ako sa vrchy zrodili, skôr než vznikla zem a svet, od vekov naveky ty si Boh.","Na počiatku bolo Slovo, to Slovo bolo u Boha a to Slovo bolo Boh.","https://biblia.sk/citanie/seb/z/90"],["Žalm 91:11–12","Mesiášsky žalm — použitý pri pokúšaní Krista","Lukáš 4:10–11","Veď on svojim anjelom prikáže, aby ťa chránili na všetkých tvojich cestách. Na rukách ťa budú nosiť, aby si si neudrel nohu o kameň.","Veď je napísané: Svojim anjelom prikáže o tebe, aby ťa chránili. oni ťa vezmú na ruky, aby si si neudrel nohu o kameň.","https://biblia.sk/citanie/seb/z/91"],["Žalm 97:9","Predpovedané jeho vyvýšenie","Skutky 1:11; Efezanom 1:20","Veď ty, Hospodin, si najvyšší na celej zemi, nesmierne vyvýšený nad všetkých bohov.","a povedali: Muži galilejskí, čo stojíte a hľadíte do neba? Tento Ježiš, ktorý bol vzatý od vás do neba, príde tak, ako ste ho videli odchádzať do neba. / Tú dokázal na Kristovi, keď ho vzkriesil z mŕtvych a posadil v nebi po svojej pravici","https://biblia.sk/citanie/seb/z/97"],["Žalm 100:5","Jeho povaha — dobrota","Matúš 19:16–17","lebo Hospodin je dobrý, jeho milosť trvá naveky a jeho vernosť z pokolenia na pokolenie!","Tu k nemu ktosi prišiel a povedal: Učiteľ, čo dobré mám robiť, aby som mal večný život? Ježiš mu odpovedal: Čo sa ma pýtaš na dobro? Jeden je Dobrý! Ak však chceš vojsť do života, zachovávaj prikázania.","https://biblia.sk/citanie/seb/z/100"],["Žalm 102:1–11","Utrpenie a potupa Golgoty","Ján 19:16–30","Hospodin, počuj moju modlitbu, kiež moje volanie k tebe prenikne! Neskrývaj svoju tvár predo mnou v deň súženia, nakloň ku mne ucho, keď volám, rýchlo mi odpovedz! Veď moje dni sa rozplynuli ako dym, kosti mám žeravé ako pahreba. …","Tak im ho teda vydal, aby ho ukrižovali. Ukrižovanie Ježiša Prevzali teda Ježiša. Niesol si kríž a šiel na miesto nazývané Lebka, po hebrejsky Golgota. Tam ho ukrižovali a spolu s ním aj iných dvoch, z jednej i z druhej strany, a Ježiša uprostred. …","https://biblia.sk/citanie/seb/z/102"],["Žalm 102:25–27","Mesiáš je Syn jestvujúci pred vekmi","Hebrejom 1:10–12","Pradávno si založil zem, aj nebesia sú dielo tvojich rúk. Tie sa pominú, ty ostaneš, všetko sa rozpadne ako rúcho, vymeníš ich ako odev, zmenia sa. Ty si však ten istý a tvoje roky sú bez konca.","A ešte: Ty, Pane, si na začiatku založil zem a nebesia sú dielom tvojich rúk. Ony sa pominú, ale ty zostávaš; a všetci zostarnú ako odev a zvinieš ich ako plášť, ako odev a zmenia sa. Ty si však ten istý a tvoje roky neprestanú.","https://biblia.sk/citanie/seb/z/102"],["Žalm 109:4","Modlí sa za svojich nepriateľov","Lukáš 23:34","Za lásku sa mi odplácajú nepriateľstvom, kým ja sa modlím.","Ježiš povedal: Otče, odpusť im, lebo nevedia, čo robia. Potom si rozdelili jeho šaty a losovali o ne.","https://biblia.sk/citanie/seb/z/109"],["Žalm 109:7–8","Iný zaujme Judášov úrad","Skutky 1:16–20","Nech ho súd uzná vinným, nech je hriechom jeho modlitba. Jeho dní nech je čím menej, jeho úrad nech prevezme iný.","Muži, bratia! Muselo sa splniť, čo Duch Svätý ústami Dávida predpovedal v Písme o Judášovi, ktorý priviedol tých, čo zatkli Ježiša. Judáš bol jedným z nás a dostal podiel na tejto službe. Z odmeny za svoju ničomnosť si kúpil pole, no hneď nato spadol z výšky dolu hlavou, pričom ho roztrhlo tak, že sa z neho vyvalili všetky vnútornosti. …","https://biblia.sk/citanie/seb/z/109"],["Žalm 109:25","Vysmievaný","Matúš 27:39","Som im na posmech, hľadia na mňa a potriasajú hlavou.","Tí, čo tade prechádzali, rúhali sa mu, výsmešne potriasali hlavou","https://biblia.sk/citanie/seb/z/109"],["Žalm 110:1","Syn Dávidov","Matúš 22:41–45","Dávidov. Žalm. Výrok Hospodina môjmu Pánovi: S eď po mojej pravici, kým nepoložím tvojich nepriateľov za podnožku tvojim nohám.","Keď sa farizeji zišli, opýtal sa ich Ježiš: Čo si myslíte o Kristovi? Čí syn je? Dávidov, odpovedali mu. Povedal im: Ako ho potom Dávid v Duchu nazýva Pánom, keď hovorí: …","https://biblia.sk/citanie/seb/z/110"],["Žalm 110:1","Zasadne po pravici Otca","Marek 16:19","Dávidov. Žalm. Výrok Hospodina môjmu Pánovi: S eď po mojej pravici, kým nepoložím tvojich nepriateľov za podnožku tvojim nohám.","Keď im to Pán Ježiš povedal, bol vzatý do neba a zasadol po Božej pravici.","https://biblia.sk/citanie/seb/z/110"],["Žalm 110:1","Dávidov syn nazvaný Pánom","Marek 12:35–37","Dávidov. Žalm. Výrok Hospodina môjmu Pánovi: S eď po mojej pravici, kým nepoložím tvojich nepriateľov za podnožku tvojim nohám.","Keď Ježiš učil v chráme, povedal: Ako môžu zákonníci tvrdiť, že Kristus je Dávidovým synom? Veď sám Dávid povedal vo Svätom Duchu: Pán povedal môjmu Pánovi: Sadni si po mojej pravici, kým ti nepoložím nepriateľov pod nohy! Sám Dávid ho nazýva Pánom, ako potom môže byť jeho synom? A veľký zástup ho s radosťou počúval.","https://biblia.sk/citanie/seb/z/110"],["Žalm 110:4","Kňaz podľa radu Melchizedecha","Hebrejom 6:20","Hospodin prisahal a neoľutuje: Ty si kňaz naveky na spôsob Melchisedeka.","kde za nás vošiel Ježiš ako predchodca, keď sa stal veľkňazom naveky na spôsob Melchisedeka.","https://biblia.sk/citanie/seb/z/110"],["Žalm 112:4","Jeho povaha — súcitný, milostivý","Matúš 9:36","Úprimným zasvitne svetlo v tme, veď Boh je milostivý, milosrdný a spravodlivý.","Pri pohľade na zástupy mu ich prišlo ľúto, lebo boli zbedačení a sklesnutí ako ovce bez pastiera.","https://biblia.sk/citanie/seb/z/112"],["Žalm 118:17–18","Mesiášovo vzkriesenie zaistené","Lukáš 24:5–7; 1. Korinťanom 15:20","Neumriem, budem žiť a vyrozprávam skutky Hospodina. Veľmi ma potrestal Hospodin, smrti ma však nevydal.","Ženy sa preľakli a sklonili tváre k zemi. Ale muži im povedali: Prečo hľadáte živého medzi mŕtvymi? Niet ho tu, bol vzkriesený. Spomeňte si, ako vám hovoril, keď bol ešte v Galilei: Syna človeka musia vydať hriešnikom do rúk a ukrižovať ho, ale tretieho dňa musí vstať z mŕtvych. / Kristus však bol vzkriesený z mŕtvych ako prvotina tých, čo zomreli.","https://biblia.sk/citanie/seb/z/118"],["Žalm 118:22–23","Zavrhnutý kameň sa stal uholným","Matúš 21:42–43","Kameň, ktorý stavitelia zavrhli, stal sa uholným kameňom. Stalo sa to na pokyn Hospodina: je to vec v našich očiach obdivuhodná.","Ježiš im povedal: Nikdy ste nečítali v Písmach: Kameň, ktorý stavitelia zavrhli, stal sa uholným kameňom. Pán to urobil, je to obdivuhodné v našich očiach? Preto vám hovorím, že vám bude odňaté Božie kráľovstvo a bude dané národu, ktorý bude prinášať úrodu.","https://biblia.sk/citanie/seb/z/118"],["Žalm 118:26","Požehnaný predstavený Izraelu","Matúš 21:9","Požehnaný, kto prichádza v mene Hospodina! Žehnáme vás z Hospodinovho domu.","A zástupy, čo šli pred ním i za ním, volali: Hosanna Synovi Dávidovmu! Požehnaný, ktorý prichádza v mene Pánovom! Hosanna na výsostiach!","https://biblia.sk/citanie/seb/z/118"],["Žalm 118:26","Príde, kým ešte stojí chrám","Matúš 21:12–15","Požehnaný, kto prichádza v mene Hospodina! Žehnáme vás z Hospodinovho domu.","Ježiš vošiel do chrámu a vyhnal všetkých, čo predávali a kupovali v chráme. Peňazomencom poprevracal stoly, predavačom holubov lavice a povedal im: Je napísané: Môj dom sa bude volať domom modlitby. Ale vy z neho robíte pelech lotrov. V chráme k nemu prišli slepí a chromí. A on ich uzdravoval. …","https://biblia.sk/citanie/seb/z/118"],["Žalm 129:3","Bol zbičovaný","Matúš 27:26","Oráči mi orali po chrbte, vyorávali dlhé brázdy.","Vtedy im prepustil Barabbáša, Ježiša však dal zbičovať a vydal ho, aby ho ukrižovali.","https://biblia.sk/citanie/seb/z/129"],["Žalm 132:11","Potomok Dávida — plod jeho tela","Lukáš 1:32; Skutky 2:30","Hospodin prisahal vernosť Dávidovi, neodstúpi od nej: Jedného potomka z tvojho rodu posadím po tebe na trón.","On sa bude volať synom Najvyššieho a Pán, Boh, mu dá trón jeho otca Dávida. / Keďže bol prorokom a vedel, že Boh sa mu prísahou zaviazal, že posadí na jeho trón potomka z jeho krvi,","https://biblia.sk/citanie/seb/z/132"],["Žalm 138:1–6","Zvrchovanosť Dávidovho potomka udivuje kráľov","Matúš 2:2–6","Dávidov. Ďakujem ti z celého srdca a pred božstvami ťa ospevujem48. Vrhám sa na tvár pred tvojím svätým chrámom a oslavujem tvoje meno pre tvoje milosrdenstvo a vernosť, lebo si nadovšetko zvelebil svoje meno a svoje slovo. Keď som volal k tebe, odpovedal si mi, dodal si mi odvahu a posilnil si ma. …","Pýtali sa: Kde je ten práve narodený židovský kráľ? Videli sme totiž na východe jeho hviezdu a prišli sme sa mu pokloniť. Keď to počul kráľ Herodes, rozrušil sa a s ním aj celý Jeruzalem. Zvolal všetkých veľkňazov a zákonníkov ľudu a vypytoval sa ich, kde sa má narodiť Mesiáš. …","https://biblia.sk/citanie/seb/z/138"],["Žalm 147:3–6","Opísaná Kristova pozemská služba","Lukáš 4:18","uzdravuje skrúšených srdcom a obväzuje im rany. On určil počet hviezd a všetky volá po mene. Veľký a všemocný je náš Pán, jeho múdrosť je nesmierna. …","Duch Pánov je nado mnou, lebo ma pomazal zvestovať chudobným evanjelium a uzdravovať skrúšených srdcom. Poslal ma oznámiť zajatým prepustenie, slepým vrátiť zrak, utláčaných prepustiť","https://biblia.sk/citanie/seb/z/147"],["Príslovia 1:23","Pošle Božieho Ducha","Ján 16:7","Venujte pozornosť mojim výčitkám! Hľa, vylejem na vás svojho ducha, oznámim vám svoje slová.","Ja vám však hovorím pravdu: Pre vás je lepšie, keď odídem. Ak totiž neodídem, Tešiteľ k vám nepríde. Ak však odídem, pošlem ho k vám.","https://biblia.sk/citanie/seb/pris/1"],["Príslovia 8:23","Ustanovený od večnosti","Zjavenie 13:8; 1. Petrov 1:19–20","Od večnosti som ustanovená, od začiatku, prv ako povstala zem.","Budú sa jej klaňať všetci obyvatelia zeme, ktorých mená nie sú od založenia sveta zapísané v knihe života Baránka, ktorý bol zabitý. / ale drahou krvou Krista. On ako bezchybný a nepoškvrnený baránok bol na to síce vopred vyhliadnutý ešte pred stvorením sveta, ale pre vás prišiel až na konci čias.","https://biblia.sk/citanie/seb/pris/8"],["Príslovia 30:4","Vyhlásený za Božieho Syna","Ján 3:13; Rimanom 1:2–4; 2. Petrov 1:17","Kto vystúpil do neba a odtiaľ zostúpil? Kto do svojej hrsti vietor nazbieral? Kto zabalil vodu do plášťa? Ktože vytýčil všetky končiny zeme? Ako sa volá a ako sa volá jeho syn? I sto to vieš!","Nik nevystúpil do neba, jedine ten, čo zostúpil z neba, Syn človeka. / ktoré Boh už dávno prisľúbil skrze svojich prorokov vo svätých Písmach, evanjelium o jeho Synovi, ktorý sa podľa tela narodil z Dávidovho potomstva a podľa Ducha svätosti je ustanovený od vzkriesenia z mŕtvych ako Boží Syn s mocou, evanjelium o Ježišovi Kristovi, našom Pánovi. / Veď prijal česť a slávu od Boha Otca, keď mu z velebnej slávy zaznel hlas: Toto je môj milovaný Syn, v ktorom mám zaľúbenie.","https://biblia.sk/citanie/seb/pris/30"],["Pieseň piesní 5:16","Celý je pôvabný — najkrajší z ľudí","Ján 1:17","Jeho podnebie je presladké, celý je príťažlivý. Taký je môj milý, taký je môj priateľ, dcéry jeruzalemské!","Zákon bol totiž daný skrze Mojžiša, no milosť a pravda prišli skrze Ježiša Krista.","https://biblia.sk/citanie/seb/vlp/5"],["Izaiáš 2:3","Bude učiť všetky národy","Ján 4:25","a putovať mnohé kmene a povedia si: Poďme, vystúpme na Hospodinov vrch, do domu Jákobovho Boha, aby nás poučil o svojich cestách a my budeme kráčať po jeho chodníkoch. Veď zo Siona vyjde zákon, Hospodinovo slovo z Jeruzalema.","Žena mu povedala: Viem, že prichádza Mesiáš, nazývaný Kristus; keď príde on, všetko nám oznámi.","https://biblia.sk/citanie/seb/iz/2"],["Izaiáš 2:4","Bude súdiť medzi národmi","Ján 5:22","On bude súdiť medzi národmi a naprávať mnohé kmene, takže si z mečov ukujú radlice, zo svojich kopijí vinárske nože. Národ proti národu nepozdvihne meč a už sa nebudú cvičiť v boji.","Lebo Otec nikoho ani nesúdi, lež celý súd odovzdal Synovi,","https://biblia.sk/citanie/seb/iz/2"],["Izaiáš 6:1","Izaiáš videl jeho slávu","Ján 12:40–41","V roku, keď zomrel kráľ Uzija, videl som Pána sedieť na vysokom a vznešenom tróne. Okraje jeho rúcha napĺňali chrám.","Oslepil im oči a zatvrdil im srdce, aby očami nevideli a srdcom nespoznali a neobrátili sa, a aby som ich neuzdravil. Toto povedal Izaiáš, lebo videl jeho slávu a hovoril o ňom.","https://biblia.sk/citanie/seb/iz/6"],["Izaiáš 6:8","Ten, ktorého poslal Boh","Ján 12:38–45","Potom som počul hlas Pána, ktorý povedal: Koho mám poslať, kto ta pôjde? Povedal som: Hľa, tu som, pošli mňa!","aby sa naplnilo slovo, ktoré povedal prorok Izaiáš: Pane, kto uveril nášmu kázaniu a komu bolo zjavené Pánovo rameno? Preto nemohli uveriť, lebo Izaiáš inde povedal: Oslepil im oči a zatvrdil im srdce, aby očami nevideli a srdcom nespoznali a neobrátili sa, a aby som ich neuzdravil. …","https://biblia.sk/citanie/seb/iz/6"],["Izaiáš 6:9–10","Podobenstvá padajú na hluché uši","Matúš 13:13–15","Povedal: Choď a povedz tomuto národu: Počúvajte, len počúvajte, ale nerozumejte, hľaďte, len sa dívajte, ale nechápte! Urob bezcitným srdce tohto ľudu, zapchaj mu uši a zastri oči, aby očami nevidel a ušami nepočul, aby jeho srdce nechápalo, neobrátil sa a nevyzdravel.","V podobenstvách im hovorím preto, že pozerajú, ale nevidia, počúvajú, ale nepočujú a ani nechápu. Plní sa na nich Izaiášovo proroctvo: Budete počúvať a počúvať, ale nebudete rozumieť, budete hľadieť a hľadieť, ale nebudete vidieť. Tomuto ľudu otupelo srdce: ušami ťažko počujú a oči si zažmúrili, aby očami nevideli a ušami nepočuli, aby srdcom neporozumeli a neobrátili sa — aby som ich neuzdravil.","https://biblia.sk/citanie/seb/iz/6"],["Izaiáš 6:9–12","Slepí voči Kristovi, hluchí k jeho slovám","Skutky 28:23–29","Povedal: Choď a povedz tomuto národu: Počúvajte, len počúvajte, ale nerozumejte, hľaďte, len sa dívajte, ale nechápte! Urob bezcitným srdce tohto ľudu, zapchaj mu uši a zastri oči, aby očami nevidel a ušami nepočul, aby jeho srdce nechápalo, neobrátil sa a nevyzdravel. Povedal som: Dokedy, Pane? Povedal: Dovtedy, kým nespustnú mestá a budú bez obyvateľov a domy bez ľudí, kým sa zem nestane púšťou. …","Určili mu teda deň a viacerí prišli k nemu ta, kde sa Pavol ubytoval. Od rána až do večera im vysvetľoval a vydával svedectvo o Božom kráľovstve a presviedčal ich o Ježišovi dôkazmi z Mojžišovho zákona a Prorokov. Tomu, čo hovoril, niektorí uverili, iní však neverili. Keďže neboli jednomyseľní, rozišli sa, keď Pavol povedal tieto slová: Duch Svätý dobre povedal vašim otcom ústami proroka Izaiáša: …","https://biblia.sk/citanie/seb/iz/6"],["Izaiáš 7:14","Narodí sa z panny","Lukáš 1:35","Preto sám Pán vám dá znamenie: Hľa, panna počne a porodí syna a dá mu meno Emanuel.","Anjel jej odpovedal: Duch Svätý zostúpi na teba a zatôni ťa moc Najvyššieho, a preto aj dieťa bude sväté a bude sa volať Božím Synom.","https://biblia.sk/citanie/seb/iz/7"],["Izaiáš 7:14","Bude Emanuel — Boh s nami","Matúš 1:18–23; 1. Timotejovi 3:16","Preto sám Pán vám dá znamenie: Hľa, panna počne a porodí syna a dá mu meno Emanuel.","S narodením Ježiša Krista to bolo takto: Jeho matka Mária bola zasnúbená s Jozefom. Skôr však, ako sa zišli, ukázalo sa, že počala z Ducha Svätého. Jej muž Jozef bol však spravodlivý a nechcel ju verejne vystaviť hanbe. Rozhodol sa teda tajne ju prepustiť. Keď o tom uvažoval, zjavil sa mu vo sne Pánov anjel a povedal: Jozef, syn Dávida, neboj sa prijať Máriu, svoju ženu. Veď to, čo sa v nej počalo, je z Ducha Svätého. … / Nepochybne, veľké je tajomstvo zbožnosti: Zjavený bol v tele, ospravedlnený v Duchu, videný anjelmi, zvestovaný medzi pohanmi, vierou prijatý vo svete a v sláve vzatý hore.","https://biblia.sk/citanie/seb/iz/7"],["Izaiáš 8:8","Nazvaný Emanuel","Matúš 28:20","Spolčujte sa, národy, zúrte, deste sa, počúvajte všetky diaľavy sveta, zbrojte, ale deste sa, zbrojte, ale deste sa!","a naučte ich zachovávať všetko, čo som vám prikázal. A hľa, ja som s vami po všetky dni až do konca sveta.","https://biblia.sk/citanie/seb/iz/8"],["Izaiáš 8:14","Kameň úrazu a skala pohoršenia","1. Petrov 2:8","Mnohí sa oň potknú, padnú a rozbijú sa, padnú do pasce a chytia sa.","a kameňom úrazu i skalou pohoršenia. Oni sa oň potkýnajú, lebo nepočúvajú slovo, — na to boli aj určení.","https://biblia.sk/citanie/seb/iz/8"],["Izaiáš 9:1–2","Jeho služba sa začne v Galilei","Matúš 4:12–17","Ľud, čo kráča vo tmách, uvidí veľké svetlo, nad tými, čo bývajú v krajine temnoty, zažiari svetlo. Rozmnožil si ich jasot, zväčšil si ich radosť. Radujú sa pred tebou, ako sa raduje pri žatve, ako sa jasá pri delení koristi.","Keď Ježiš počul, že Jána uväznili, odobral sa do Galiley. Zanechal Nazaret a usadil sa v prímorskom Kafarnaume na území Zabulona a Neftalima, aby sa splnilo, čo povedal prorok Izaiáš: …","https://biblia.sk/citanie/seb/iz/9"],["Izaiáš 9:6","Dieťa sa narodilo — jeho ľudskosť","Lukáš 1:31","Miera jeho vlády a pokoj nebude mať konca na Dávidovom tróne a v jeho kráľovstve, ktoré upevní a posilní právom a spravodlivosťou odteraz až naveky. Horlivosť Hospodina zástupov to urobí.","Hľa, počneš, porodíš syna a dáš mu meno Ježiš.","https://biblia.sk/citanie/seb/iz/9"],["Izaiáš 9:6","Syn je daný — jeho božstvo","Lukáš 1:32; Ján 1:14; 1. Timotejovi 3:16","Miera jeho vlády a pokoj nebude mať konca na Dávidovom tróne a v jeho kráľovstve, ktoré upevní a posilní právom a spravodlivosťou odteraz až naveky. Horlivosť Hospodina zástupov to urobí.","On sa bude volať synom Najvyššieho a Pán, Boh, mu dá trón jeho otca Dávida. / A Slovo sa stalo telom a prebývalo medzi nami a my sme videli jeho slávu, slávu, akú má od Otca jednorodený Syn, plný milosti a pravdy. / Nepochybne, veľké je tajomstvo zbožnosti: Zjavený bol v tele, ospravedlnený v Duchu, videný anjelmi, zvestovaný medzi pohanmi, vierou prijatý vo svete a v sláve vzatý hore.","https://biblia.sk/citanie/seb/iz/9"],["Izaiáš 9:6","Vyhlásený za Božieho Syna s mocou","Rimanom 1:3–4","Miera jeho vlády a pokoj nebude mať konca na Dávidovom tróne a v jeho kráľovstve, ktoré upevní a posilní právom a spravodlivosťou odteraz až naveky. Horlivosť Hospodina zástupov to urobí.","evanjelium o jeho Synovi, ktorý sa podľa tela narodil z Dávidovho potomstva a podľa Ducha svätosti je ustanovený od vzkriesenia z mŕtvych ako Boží Syn s mocou, evanjelium o Ježišovi Kristovi, našom Pánovi.","https://biblia.sk/citanie/seb/iz/9"],["Izaiáš 9:6","Obdivuhodný — Peleh","Lukáš 4:22","Miera jeho vlády a pokoj nebude mať konca na Dávidovom tróne a v jeho kráľovstve, ktoré upevní a posilní právom a spravodlivosťou odteraz až naveky. Horlivosť Hospodina zástupov to urobí.","Všetci mu prisviedčali a obdivovali jeho láskavú reč, ktorá plynula z jeho úst. A hovorili si: Či to nie je Jozefov syn?","https://biblia.sk/citanie/seb/iz/9"],["Izaiáš 9:6","Radca — Jaac","Matúš 13:54","Miera jeho vlády a pokoj nebude mať konca na Dávidovom tróne a v jeho kráľovstve, ktoré upevní a posilní právom a spravodlivosťou odteraz až naveky. Horlivosť Hospodina zástupov to urobí.","Prišiel do svojho otcovského mesta a tam učil v synagóge, takže ľudia sa veľmi čudovali a hovorili: Odkiaľ má takúto múdrosť a mocné činy?","https://biblia.sk/citanie/seb/iz/9"],["Izaiáš 9:6","Mocný Boh — El Gibor","1. Korinťanom 1:24; Títovi 2:13","Miera jeho vlády a pokoj nebude mať konca na Dávidovom tróne a v jeho kráľovstve, ktoré upevní a posilní právom a spravodlivosťou odteraz až naveky. Horlivosť Hospodina zástupov to urobí.","ale pre povolaných, tak Židov, ako aj Grékov, Krista, Božiu moc a Božiu múdrosť. / a očakávali blažené splnenie nádeje a príchod slávy veľkého Boha a nášho Spasiteľa Ježiša Krista.","https://biblia.sk/citanie/seb/iz/9"],["Izaiáš 9:6","Večný Otec — Avi Ad","Ján 8:58; 10:30","Miera jeho vlády a pokoj nebude mať konca na Dávidovom tróne a v jeho kráľovstve, ktoré upevní a posilní právom a spravodlivosťou odteraz až naveky. Horlivosť Hospodina zástupov to urobí.","Ježiš im odpovedal: Amen, amen, hovorím vám: Skôr ako bol Abrahám, Ja som! / Ja a Otec sme jedno.","https://biblia.sk/citanie/seb/iz/9"],["Izaiáš 9:6","Knieža pokoja — Sar Šalom","Ján 16:33","Miera jeho vlády a pokoj nebude mať konca na Dávidovom tróne a v jeho kráľovstve, ktoré upevní a posilní právom a spravodlivosťou odteraz až naveky. Horlivosť Hospodina zástupov to urobí.","Toto som vám povedal, aby ste našli vo mne pokoj. Na svete máte súženie, ale dúfajte, ja som premohol svet!","https://biblia.sk/citanie/seb/iz/9"],["Izaiáš 9:7","Ustanoví večné kráľovstvo","Lukáš 1:32–33","Hospodin zoslal slovo proti Jákobovi a dopadlo na Izrael.","On sa bude volať synom Najvyššieho a Pán, Boh, mu dá trón jeho otca Dávida. Bude kraľovať nad Jákobovým domom naveky a jeho kráľovstvu nebude konca.","https://biblia.sk/citanie/seb/iz/9"],["Izaiáš 11:1","Nazvaný Nazaretský — Výhonok, Necer","Matúš 2:23","Z Jeseho pňa vzíde ratolesť a z jeho koreňov vyrastie výhonok.","Tam sa usadil v meste, ktoré sa volalo Nazaret. Tak sa splnilo to, čo hovorili proroci, že sa bude volať Nazaretský.","https://biblia.sk/citanie/seb/iz/11"],["Izaiáš 11:1","Prút z kmeňa Izaiho — syn Izaiho","Lukáš 3:23–32","Z Jeseho pňa vzíde ratolesť a z jeho koreňov vyrastie výhonok.","Keď Ježiš začal účinkovať, mal asi tridsať rokov. Nazdávali sa, že je synom Jozefa. Jeho predkami boli: Heli, Matat, Lévi, Melchi, Janai, Jozef, Matatiáš, Amos, Naum, Hesli, Nagge, …","https://biblia.sk/citanie/seb/iz/11"],["Izaiáš 11:2","Pomazaný Duchom","Matúš 3:16–17; Skutky 10:38","Spočinie na ňom Duch Hospodina, duch múdrosti a rozumu, duch rady a sily, duch poznania a Hospodinovej bázne.","Po krste Ježiš hneď vystúpil z vody. Vtom sa mu otvorili nebesia a videl Božieho Ducha, ktorý sťa holubica zostupoval naňho. A z neba zaznel hlas: Toto je môj milovaný Syn, v ktorom som našiel zaľúbenie. / Viete o Ježišovi z Nazareta, ako ho Boh pomazal Duchom Svätým a mocou, takže chodil, dobre robil a liečil všetkých diablom posadnutých, pretože Boh bol s ním.","https://biblia.sk/citanie/seb/iz/11"],["Izaiáš 11:2","Jeho povaha — múdrosť a poznanie","Kolosanom 2:3","Spočinie na ňom Duch Hospodina, duch múdrosti a rozumu, duch rady a sily, duch poznania a Hospodinovej bázne.","Lebo v ňom sú ukryté všetky poklady múdrosti a poznania.","https://biblia.sk/citanie/seb/iz/11"],["Izaiáš 11:3","Poznal ich myšlienky","Lukáš 6:8; Ján 2:25","V bázni pred Hospodinom bude mať záľubu, nebude súdiť podľa vonkajšieho zdania ani nebude rozhodovať podľa toho, čo predtým počul,","On vedel o ich zmýšľaní a napriek tomu povedal človeku s vyschnutou rukou: Vstaň a postav sa do stredu. On vstal a postavil sa. / a od nikoho nepotreboval svedectvo o ľuďoch. Sám totiž vedel, čo je v človekovi.","https://biblia.sk/citanie/seb/iz/11"],["Izaiáš 11:4","Bude súdiť v spravodlivosti","Skutky 17:31","ale spravodlivo bude súdiť slabých a bude nestranne rozhodovať proti biednym v krajine. Palicou svojich úst bude biť násilníkov, dychom svojich pier usmrtí bezbožníka.","Lebo určil deň, keď bude spravodlivo súdiť celý svet skrze muža, ktorého ustanovil. Všetkým o tom poskytol spoľahlivý dôkaz, keď ho vzkriesil z mŕtvych.","https://biblia.sk/citanie/seb/iz/11"],["Izaiáš 11:10","Pohania ho hľadajú","Ján 12:18–21","V ten deň začnú prúdiť národy ku koreňu Jesseho, ktorý sa týči ako zástava pre národy a jeho príbytok sa stane slávnym.","Preto mu vyšiel v ústrety veľký zástup, lebo počuli, že urobil toto znamenie. Vtedy si farizeji hovorili medzi sebou: Vidíte, že nič nezmôžete. Hľa, svet odišiel za ním! Niektorí z tých, čo prišli na sviatky vykonať poklonu Bohu, boli Gréci. …","https://biblia.sk/citanie/seb/iz/11"],["Izaiáš 12:2","Nazvaný Ježiš — Ješua, spása","Matúš 1:21","Veď Boh je moja spása, dôverujem mu a nezľaknem sa, lebo moja sila a pieseň je Hospodin, Hospodin sa mi stal spásou.","Porodí syna a dáš mu meno Ježiš, lebo on zachráni svoj ľud z jeho hriechov.","https://biblia.sk/citanie/seb/iz/12"],["Izaiáš 22:22","Dostane všetku moc vládnuť","Zjavenie 3:7","Na plecia mu dám kľúč od Dávidovho domu, keď otvorí, nikto nezatvorí a keď zatvorí, nikto neotvorí.","Anjelovi cirkvi vo Filadelfii napíš: Toto hovorí Svätý, Pravdivý, ktorý má Dávidov kľúč, ktorý otvára tak, že nikto nezatvorí, a zatvára tak, že nikto neotvorí.","https://biblia.sk/citanie/seb/iz/22"],["Izaiáš 25:8","Predpovedané vzkriesenie","1. Korinťanom 15:54","Navždy pohltí smrť a Pán, Hospodin, zotrie slzu z každej tváre, odstráni potupu svojho ľudu z celej zeme, lebo Hospodin prehovoril.","Keď si však toto porušiteľné oblečie neporušiteľnosť a toto smrteľné si oblečie nesmrteľnosť, vtedy sa splní, čo je napísané: Smrť pohltilo víťazstvo!","https://biblia.sk/citanie/seb/iz/25"],["Izaiáš 26:19","Predpovedaná jeho moc vzkriesenia","Matúš 27:50–54","Tvoji mŕtvi budú žiť, ich telá vstanú. Prebuďte sa a plesajte, vy, čo ležíte v prachu! Veď tvoja rosa je rosou svetla a zem vydá tiene mŕtvych.","Ale Ježiš znova zvolal mocným hlasom a vypustil ducha. A hľa, chrámová opona sa roztrhla na dvoje odvrchu až naspodok, zem sa triasla a skaly pukali. Otvorili sa hroby a mnohé telá zosnulých svätých boli vzkriesené. …","https://biblia.sk/citanie/seb/iz/26"],["Izaiáš 28:16","Mesiáš je vzácny uholný kameň","Skutky 4:11–12","Nevysmievajte sa však, aby vám nespevneli okovy, lebo som počul o skaze, o tom, čo rozhodol Pán, Hospodina zástupov, nad celou zemou.","On je ten kameň, ktorý ste vy, stavitelia, zavrhli a sa stal uholným kameňom. A v nikom inom niet spásy, lebo pod nebom niet iného mena, daného ľuďom, v ktorom by sme mali byť spasení.","https://biblia.sk/citanie/seb/iz/28"],["Izaiáš 28:16","Pevný základ","1. Korinťanom 3:11; Matúš 16:18","Nevysmievajte sa však, aby vám nespevneli okovy, lebo som počul o skaze, o tom, čo rozhodol Pán, Hospodina zástupov, nad celou zemou.","Nik totiž nemôže položiť iný základ než ten, ktorý je už položený, a tým je Ježiš Kristus. / A ja ti hovorím: Ty si Peter a na tej skale si postavím Cirkev a pekelné brány ju nepremôžu.","https://biblia.sk/citanie/seb/iz/28"],["Izaiáš 29:13","Odhalil pokryteckú poslušnosť jeho slovu","Matúš 15:7–9","Pán povedal: Pretože sa mi tento ľud chce stať blízkym iba svojimi ústami a ctí si ma iba svojimi perami, no jeho srdce je ďaleko odo mňa a jeho bázeň voči mne je naučeným ľudským príkazom,","Pokrytci, dobre o vás prorokoval Izaiáš, keď povedal: Tento ľud ma ctí perami, ale jeho srdce je odo mňa ďaleko. Zbytočne ma však uctievajú, lebo ako náuku podávajú ľudské príkazy.","https://biblia.sk/citanie/seb/iz/29"],["Izaiáš 29:14","Múdri sú zahanbení Slovom","1. Korinťanom 1:18–31","opäť budem konať divy pre tento ľud, div za divom, a múdrosť jeho mudrcov sa stratí, rozumnosť jeho rozumných sa skryje.","Veď slovo o kríži je bláznovstvom pre tých, čo sú na ceste k záhube, nám však, ktorí smerujeme k spáse, je Božou mocou. Veď je napísané: Zmarím múdrosť múdrych a rozumnosť rozumných zničím. Kde je múdry? Kde zákonník? Kde rečník tohto veku? Neobrátil azda Boh múdrosť tohto sveta na bláznovstvo? …","https://biblia.sk/citanie/seb/iz/29"],["Izaiáš 32:2","Útočisko — človek bude skrýšou","Matúš 23:37","Každý z nich bude ako skrýša pred vetrom a úkryt pred lejakom, budú ako vodné prúdy na suchom mieste, ako tieň mohutnej skaly vo vyprahnutej krajine.","Jeruzalem, Jeruzalem, ktorý vraždíš prorokov a kameňuješ tých, čo boli poslaní k tebe! Koľko ráz som chcel zhromaždiť tvoje deti, ako sliepka zhromažďuje svoje kuriatka pod krídla, ale nechceli ste!","https://biblia.sk/citanie/seb/iz/32"],["Izaiáš 35:4","Príde a spasí vás","Matúš 1:21","Nočná príšera v ľudových predstavách.Povedzte malomyseľným: Vzchopte sa, nebojte sa! Pozrite, váš Boh! Príde s pomstou, Božou odplatou, on sám príde, aby vás zachránil.Vtedy sa otvoria oči slepýchaj uši hluchých sa otvoria. Vtedy chromý bude skákať ako jeleň a jazyk nemého zaplesá, lebo vyvrú vody na púšti a potoky na pustatine.Vyschnutá zem sa stane jazerom, vyprahnutá pôda prameňom vôd a na mieste, kde odpočívali šakaly, bude tráva, tŕstie a šašina.Bude tam chodník, cesta, tá, čo sa bude volať svätou cestou, po ktorej nečistý neprejde, bude iba pre môj ľud, čo po nej pôjde, a jednoduchí na nej nezblúdia.Nebude tam lev a nevstúpi na ňu dravá zver; nijaká sa tam nenájde, iba vykúpení tade pôjdu.Vrátia sa tí, ktorých oslobodil Hospodin, s jasotom prídu na Sion. Večná radosť bude na ich tvárach, veselosť a jasot získajú a pominie smútok a vzdychanie.","Porodí syna a dáš mu meno Ježiš, lebo on zachráni svoj ľud z jeho hriechov.","https://biblia.sk/citanie/seb/iz/35"],["Izaiáš 35:5–6","Služba plná zázrakov","Matúš 11:2–6","Vtedy sa roztvoria oči slepých a uši hluchých sa otvoria. Vtedy sťa jeleň bude skákať chromý a jazyk nemého zaplesá, ba vyvierať budú na púšti vody a potoky na pustatine.","Keď Ján počul v žalári o Kristových skutkoch, poslal k nemu svojich učeníkov, aby sa ho spýtali: Ty si ten, čo má prísť, alebo máme čakať iného? Ježiš im odpovedal: Choďte a oznámte Jánovi, čo počujete a vidíte: …","https://biblia.sk/citanie/seb/iz/35"],["Izaiáš 40:3–4","Predchádzaný predchodcom","Ján 1:23","Hlas volá: Na púšti pripravte cestu Hospodinovi, v stepi urovnajte chodník nášmu Bohu! Každé údolie nech sa zdvihne, každý vrch a kopec nech sa zníži. Všetko nerovné nech sa vyrovná a nech sa vyrovnajú hrbole,","Povedal: Ja som hlas volajúceho na púšti: Vyrovnajte Pánovu cestu, ako povedal prorok Izaiáš.","https://biblia.sk/citanie/seb/iz/40"],["Izaiáš 40:9","„Hľa, váš Boh.“","Ján 1:36; 19:14","Vystúp na vysoký vrch, ohlasovateľ radostnej zvesti Sionu, mocne pozdvihni svoj hlas, ohlasovateľ radostnej zvesti Jeruzalemu! Hlasno volaj, neboj sa, povedz judským mestám: Hľa, váš Boh!","a keď zbadal Ježiša, ktorý šiel okolo, povedal: Hľa, Baránok Boží! / Bol prípravný deň pred Veľkou nocou a bolo okolo šiestej hodiny. Tu prehovoril k Židom: Hľa, váš kráľ!","https://biblia.sk/citanie/seb/iz/40"],["Izaiáš 40:10","Príde odmeniť","Zjavenie 22:12","Pozri, Pán Boh prichádza v moci, vládne svojím ramenom. Hľa, nesie odmenu a jeho pláca ide pred ním.","Hľa, prídem čoskoro a moja odplata príde so mnou, aby som odplatil každému podľa jeho skutkov.","https://biblia.sk/citanie/seb/iz/40"],["Izaiáš 40:11","Pastier — súcitný darca života","Ján 10:10–18","Ako pastier bude pásť svoje stádo, svojím ramenom ho zhromaždí, baránky vezme do náručia a tie, čo pridájajú, nežne bude viesť.","Zlodej prichádza, len aby kradol, zbíjal a hubil. Ja som prišiel, aby mali život, a to v hojnej miere. Ja som dobrý pastier. Dobrý pastier kladie svoj život za ovce. Nájomník a ten, kto nie je pastier a ovce nie sú jeho, keď vidí prichádzať vlka, opúšťa ovce a uteká. A vlk ich chytá a rozháňa. …","https://biblia.sk/citanie/seb/iz/40"],["Izaiáš 42:1–4","Služobník — verný a trpezlivý vykupiteľ","Matúš 12:18–21","Hľa, môj služobník, podporujem ho, môj vyvolený, ktorého som si obľúbil. Svojho Ducha som vložil na neho, prinesie právo národom. Nebude kričať ani nezvýši hlas, nedá počuť svoj hlas na ulici. Nalomenú trstinu nedolomí, hasnúci knôtik nedohasí, podľa pravdy bude súdiť. …","Hľa, môj služobník, ktorého som si vyvolil, môj milovaný, v ktorom mám zaľúbenie. Na neho vložím svojho Ducha a on oznámi právo národom. Nebude sa škriepiť, ani kričať, na uliciach nikto nepočuje jeho hlas. Nalomenú trstinu nedolomí a tlejúci knôt nedohasí, kým nedopomôže právu k víťazstvu. …","https://biblia.sk/citanie/seb/iz/42"],["Izaiáš 42:2","Tichý a pokorný","Matúš 11:28–30","Nebude kričať ani nezvýši hlas, nedá počuť svoj hlas na ulici.","Poďte ku mne všetci, ktorí sa namáhate a ste preťažení; ja vám dám odpočinúť. Vezmite na seba moje jarmo a učte sa odo mňa, lebo som tichý a pokorný srdcom, a nájdete odpočinutie pre svoje duše. Veď moje jarmo je príjemné a bremeno ľahké.","https://biblia.sk/citanie/seb/iz/42"],["Izaiáš 42:3","Prináša nádej beznádejným","Ján 4:1–26","Nalomenú trstinu nedolomí, hasnúci knôtik nedohasí, podľa pravdy bude súdiť.","Keď sa Ježiš dozvedel, že farizeji počuli, ako získava a krstí viac učeníkov než Ján, hoci Ježiš sám nekrstil, ale jeho učeníci, opustil Judsko a odišiel znova do Galiley. …","https://biblia.sk/citanie/seb/iz/42"],["Izaiáš 42:4","Národy budú čakať na jeho učenie","Ján 12:20–26","Neochabne a nepodlomí sa, kým nezaloží právo na zemi. Na jeho náuku čakajú ostrovy.","Niektorí z tých, čo prišli na sviatky vykonať poklonu Bohu, boli Gréci. Pristúpili k Filipovi, ktorý bol z galilejskej Betsaidy, a prosili ho: Pane, chceme vidieť Ježiša! Filip šiel a povedal to Ondrejovi. Ondrej a Filip to šli povedať Ježišovi. …","https://biblia.sk/citanie/seb/iz/42"],["Izaiáš 42:6","Svetlo a spása pohanov","Lukáš 2:32","Ja, Hospodin som ťa povolal v spravodlivosti, uchopil som ťa za ruku, stvárnil som ťa a urobil som ťa zmluvou ľudu, svetlom pohanov,","svetlo na zjavenie pre pohanov a slávu pre tvoj ľud Izrael.","https://biblia.sk/citanie/seb/iz/42"],["Izaiáš 42:1, 6","Jeho súcit patrí celému svetu","Matúš 28:19–20","Hľa, môj služobník, podporujem ho, môj vyvolený, ktorého som si obľúbil. Svojho Ducha som vložil na neho, prinesie právo národom. Ja, Hospodin som ťa povolal v spravodlivosti, uchopil som ťa za ruku, stvárnil som ťa a urobil som ťa zmluvou ľudu, svetlom pohanov,","Choďte teda a získavajte mi učeníkov vo všetkých národoch a krstite ich v mene Otca i Syna i Svätého Ducha a naučte ich zachovávať všetko, čo som vám prikázal. A hľa, ja som s vami po všetky dni až do konca sveta.","https://biblia.sk/citanie/seb/iz/42"],["Izaiáš 42:7","Otvára slepé oči","Ján 9:25–38","aby sa slepým otvorili oči, aby väzni boli vyvedení zo žalára a z väznice tí, čo sedia v temnote.","On však odpovedal: Či je hriešny, neviem, ale jedno viem, že som bol slepý a teraz vidím. Spýtali sa ho teda: Čo ti urobil? Ako ti otvoril oči? Odpovedal im: Už som vám to povedal, a nepočúvali ste. Prečo to chcete počuť znova? Chcete sa azda aj vy stať jeho učeníkmi? …","https://biblia.sk/citanie/seb/iz/42"],["Izaiáš 43:11","Je jediný Spasiteľ","Skutky 4:12","Ja som Hospodin a okrem mňa niet spasiteľa.","A v nikom inom niet spásy, lebo pod nebom niet iného mena, daného ľuďom, v ktorom by sme mali byť spasení.","https://biblia.sk/citanie/seb/iz/43"],["Izaiáš 44:3","Pošle Božieho Ducha","Ján 16:7, 13","Lebo vylejem vodu na smädnú pôdu a vodné toky na súš. Vylejem svojho ducha na tvoje potomstvo a svoje požehnanie na tvojich potomkov.","Ja vám však hovorím pravdu: Pre vás je lepšie, keď odídem. Ak totiž neodídem, Tešiteľ k vám nepríde. Ak však odídem, pošlem ho k vám. Keď však príde on, Duch pravdy, uvedie vás do celej pravdy, lebo nebude hovoriť sám od seba, ale bude hovoriť, čo počuje. A zvestuje vám aj to, čo príde.","https://biblia.sk/citanie/seb/iz/44"],["Izaiáš 45:21–25","Je Pán a Spasiteľ","Filipanom 3:20; Títovi 2:13","Oznámte a priblížte sa, ba poraďte sa spolu: Kto toto hovoril od začiatku, predpovedal to oddávna? Či nie ja, Jahve? A niet už Boha okrem mňa: Boha pravého a spásneho nieto mimo mňa. Ku mne sa obráťte, spasené budete všetky končiny zeme, veď ja som Boh a iného niet. Na seba som prisahal, z mojich úst vyšla pravda, slovo, ktoré sa nevráti, že mne sa skloní každé koleno, prisahať bude každý jazyk: …","Ale naša vlasť je v nebesiach, odkiaľ očakávame aj Spasiteľa, Pána Ježiša Krista. / a očakávali blažené splnenie nádeje a príchod slávy veľkého Boha a nášho Spasiteľa Ježiša Krista.","https://biblia.sk/citanie/seb/iz/45"],["Izaiáš 45:23","Bude Sudcom","Ján 5:22; Rimanom 14:11","Na seba som prisahal, z mojich úst vyšla pravda, slovo, ktoré sa nevráti, že mne sa skloní každé koleno, prisahať bude každý jazyk:","Lebo Otec nikoho ani nesúdi, lež celý súd odovzdal Synovi, / Lebo je napísané: Akože žijem, hovorí Pán, predo mnou sa zohne každé koleno, každý jazyk bude vyznávať Boha.","https://biblia.sk/citanie/seb/iz/45"],["Izaiáš 46:9–10","Oznamuje veci, ktoré sa ešte nestali","Ján 13:19","Pamätajte na predchádzajúce veci od večnosti, lebo ja som Boh a iného Boha niet a nikto nie je ako ja. Od počiatku oznamujem budúcnosť, od pradávna to, čo sa ešte nestalo. Hovorím: Môj zámer trvá, všetko čo chcem, urobím.","Hovorím vám to už teraz, skôr ako sa to stane, aby ste uverili potom, keď sa to stane, že Ja som.","https://biblia.sk/citanie/seb/iz/46"],["Izaiáš 48:12","Prvý a Posledný","Ján 1:30; Zjavenie 1:8, 17","Počúvaj ma, Jákob a Izrael, môj povolaný: Ja som to, ja som prvý a ja som aj posledný.","To je ten, o ktorom som povedal: Po mne prichádza muž, ktorý je predomnou, pretože bol skôr ako ja. / Ja som Alfa i Omega, hovorí Pán, Boh, ktorý je, ktorý bol a ktorý príde, Všemohúci. Keď som ho uvidel, padol som mu k nohám ako mŕtvy. On položil na mňa pravicu a povedal: Neboj sa! Ja som Prvý a Posledný","https://biblia.sk/citanie/seb/iz/48"],["Izaiáš 48:16–17","Prišiel ako Učiteľ","Ján 3:2","Poďte ku mne a počujte toto: Nikdy som nehovoril v skrytosti. Od času, čo sa tak deje, som pri tom. A teraz Pán Boh poslal mňa a svojho Ducha. Takto hovorí Hospodin, tvoj vykupiteľ, Svätý Izraela: Ja som Hospodin, tvoj Boh. Učím ťa, čo ti osoží, vediem ťa po ceste, ktorou máš ísť.","On prišiel v noci k Ježišovi a povedal mu: Rabbi, vieme, že si učiteľ, ktorý prišiel od Boha, lebo nikto nemôže robiť také znamenia, aké robíš ty, ak nie je s ním Boh.","https://biblia.sk/citanie/seb/iz/48"],["Izaiáš 49:1","Povolaný od lona matky — jeho ľudskosť","Matúš 1:18","Počúvajte ma ostrovy, dávajte pozor národy zďaleka. Hospodin ma povolal od materského lona, od života matky ma volal mojím menom.","S narodením Ježiša Krista to bolo takto: Jeho matka Mária bola zasnúbená s Jozefom. Skôr však, ako sa zišli, ukázalo sa, že počala z Ducha Svätého.","https://biblia.sk/citanie/seb/iz/49"],["Izaiáš 49:5","Služobník od lona matky","Lukáš 1:31; Filipanom 2:7","Nato však hovorí Hospodin, ktorý si ma od materského lona stvárnil za služobníka, aby sa Jákob vrátil k nemu a Izrael pri ňom zhromaždil. Som oslávený v očiach Hospodina a môj Boh sa mi stal silou.","Hľa, počneš, porodíš syna a dáš mu meno Ježiš. / ale zriekol sa jej, keď vzal na seba podobu služobníka a stal sa jedným z ľudí,","https://biblia.sk/citanie/seb/iz/49"],["Izaiáš 49:6","Obnoví Izrael","Skutky 3:19–21; 15:16–17","Povedal: To je málo, že si mojím služobníkom, aby si povzniesol Jákobove kmene a priviedol späť zachránených Izraela. Ustanovujem ťa za svetlo národov, aby si bol mojou spásou až do končín zeme.","Robte pokánie a obráťte sa, aby boli zotrené vaše hriechy a aby nadišli časy odpočinutia od Pána, keď vám pošle predurčeného Mesiáša, ktorým je Ježiš. Jeho nebo musí prichyľovať až do chvíle, keď sa všetko obnoví, o čom odpradávna hovoril Boh ústami svojich svätých prorokov. / Potom sa vrátim a znova vybudujem zrúcaný Dávidov stánok a znova vybudujem jeho ruiny a vztýčim ho, aby aj ostatní ľudia hľadali Pána, všetky národy, nad ktorými sa vzývalo moje meno, hovorí Pán, ktorý koná tieto veci,","https://biblia.sk/citanie/seb/iz/49"],["Izaiáš 49:6","Je spásou pre Izrael","Lukáš 2:29–32","Povedal: To je málo, že si mojím služobníkom, aby si povzniesol Jákobove kmene a priviedol späť zachránených Izraela. Ustanovujem ťa za svetlo národov, aby si bol mojou spásou až do končín zeme.","Teraz, Pane, prepustíš v pokoji svojho služobníka podľa svojho slova, lebo moje oči uvideli tvoju spásu, ktorú si pripravil pred tvárou všetkých národov: …","https://biblia.sk/citanie/seb/iz/49"],["Izaiáš 49:6","Je Svetlom pohanov","Ján 8:12; Skutky 13:47","Povedal: To je málo, že si mojím služobníkom, aby si povzniesol Jákobove kmene a priviedol späť zachránených Izraela. Ustanovujem ťa za svetlo národov, aby si bol mojou spásou až do končín zeme.","Potom k nim Ježiš znova prehovoril: Ja som svetlo sveta. Kto mňa nasleduje, nebude chodiť v tme, ale bude mať svetlo života. / Lebo tak nám prikázal Pán: Ustanovil som ťa za svetlo pohanom, aby si bol spásou až do končín zeme.","https://biblia.sk/citanie/seb/iz/49"],["Izaiáš 49:6","Spása až po končiny zeme","Skutky 15:7–18","Povedal: To je málo, že si mojím služobníkom, aby si povzniesol Jákobove kmene a priviedol späť zachránených Izraela. Ustanovujem ťa za svetlo národov, aby si bol mojou spásou až do končín zeme.","Keď sa strhla veľká hádka, Peter vstal a povedal im: Muži, bratia! Vy viete, že od pradávna si ma Boh spomedzi vás vyvolil, aby z mojich úst počuli pohania slovo evanjelia a uverili. Boh, ktorý pozná srdcia, vydal im svedectvo tým, že im daroval Ducha Svätého tak ako aj nám. A medzi nami a nimi nerobil vôbec nijaký rozdiel, keď vierou očistil ich srdcia. …","https://biblia.sk/citanie/seb/iz/49"],["Izaiáš 49:7","Národ ním pohŕda","Ján 1:11; 8:48–49; 19:14–15","Takto Hospodin, vykupiteľ Izraela, jeho Svätý hovorí opovrhnutému, národmi odvrhnutému otrokovi panovníkov: Králi to uvidia a vstanú, kniežatá sa sklonia kvôli Hospodinovi, ktorý je verný, kvôli svätému Izraela, ktorý ťa vyvolil.","Do svojho vlastného prišiel, ale jeho vlastní ho neprijali. / Židia mu odpovedali: Nehovoríme vari dobre, že si Samaritán, a že si posadnutý zlým duchom? Ježiš sa ohradil: Ja nie som posadnutý zlým duchom, ale ctím si Otca, a vy ma znevažujete. / Bol prípravný deň pred Veľkou nocou a bolo okolo šiestej hodiny. Tu prehovoril k Židom: Hľa, váš kráľ! Nato oni začali kričať: Preč s ním, preč s ním! Ukrižuj ho! Pilát im povedal: Vášho kráľa mám ukrižovať? Veľkňazi odpovedali: Nemáme kráľa, iba cisára!","https://biblia.sk/citanie/seb/iz/49"],["Izaiáš 50:3","Nebo sa odelo do čierneho pri jeho ponížení","Lukáš 23:44–45","Nebesá odievam čierňavou a z vrecoviny im robím odev.","Bolo okolo šiestej hodiny a nastala po celej zemi tma až do deviatej hodiny. Slnko sa zatmelo a chrámová opona sa napoly roztrhla.","https://biblia.sk/citanie/seb/iz/50"],["Izaiáš 50:4","Učený radca pre unavených","Matúš 7:29; 11:28–29","Pán Boh mi dal jazyk učeníkov, aby som vedel unaveného posilniť slovom. Ráno čo ráno mi prebúdza ucho, aby som počúval ako učeníci.","Učil ich totiž ako taký, čo má moc, a nie ako ich zákonníci. / Poďte ku mne všetci, ktorí sa namáhate a ste preťažení; ja vám dám odpočinúť. Vezmite na seba moje jarmo a učte sa odo mňa, lebo som tichý a pokorný srdcom, a nájdete odpočinutie pre svoje duše.","https://biblia.sk/citanie/seb/iz/50"],["Izaiáš 50:5","Služobník dobrovoľne poslušný","Matúš 26:39","Pán Boh mi otvoril ucho a ja som sa nebúril, späť som neustúpil.","Trochu poodišiel, padol na tvár a modlil sa: Otče môj, ak je možné, nech ma minie tento kalich. Ale nie ako ja chcem, ale ako ty.","https://biblia.sk/citanie/seb/iz/50"],["Izaiáš 50:6","„Chrbát som nastavil tým, čo bili.“","Matúš 27:26","Chrbát som nastavil tým, čo bili, a líce tým, čo mi trhali bradu, tvár som si nezakryl pred potupou a slinou.","Vtedy im prepustil Barabbáša, Ježiša však dal zbičovať a vydal ho, aby ho ukrižovali.","https://biblia.sk/citanie/seb/iz/50"],["Izaiáš 50:6","Bili ho po lícach","Matúš 26:67","Chrbát som nastavil tým, čo bili, a líce tým, čo mi trhali bradu, tvár som si nezakryl pred potupou a slinou.","Potom mu pľuli do tváre, bili ho po hlave a iní ho tĺkli palicami,","https://biblia.sk/citanie/seb/iz/50"],["Izaiáš 50:6","Pľuli na neho","Matúš 27:30","Chrbát som nastavil tým, čo bili, a líce tým, čo mi trhali bradu, tvár som si nezakryl pred potupou a slinou.","Pľuli naňho, brali mu trstinu a bili ho po hlave.","https://biblia.sk/citanie/seb/iz/50"],["Izaiáš 52:7","Hlásal dobrú zvesť na vrchoch","Matúš 5:12; 15:29; 28:16","Aké milé sú na vrchoch nohy posla, ktorý oznamuje pokoj, posla blaha, ktorý ohlasuje spásu a hovorí Sionu: Tvoj Boh kraľuje!","Radujte sa a veseľte sa, lebo v nebesiach máte veľkú odmenu. Veď takto prenasledovali prorokov, ktorí boli pred vami. / Keď Ježiš odtiaľ odišiel, prišiel ku Galilejskému moru. Vystúpil na vrch a tam si sadol. / Jedenásti učeníci odišli do Galiley na vrch, kam im rozkázal Ježiš.","https://biblia.sk/citanie/seb/iz/52"],["Izaiáš 52:13","Služobník vyvýšený","Skutky 1:8–11; Efezanom 1:19–22","Hľa, môj služobník bude mať úspech, bude vyvýšený, vyzdvihnutý a veľmi zvelebený.","Teraz však na vás zostúpi Svätý Duch, vy dostanete jeho moc a budete mi svedkami v Jeruzaleme, v celom Judsku i Samárii, až po kraj zeme. Po týchto slovách sa pred ich očami vzniesol hore, až im ho vzal oblak z dohľadu. A kým uprene hľadeli k nebu, ako odchádza, zrazu pri nich zastali dvaja muži v bielom rúchu … / a aká nesmierne veľká je jeho moc pre nás, ktorí veríme tak, ako v nás pôsobí jeho mocná sila. Tú dokázal na Kristovi, keď ho vzkriesil z mŕtvych a posadil v nebi po svojej pravici nad každé kniežatstvo, moc, silu a panstvo a nad každé meno, ktoré sa spomína nielen v tomto, ale aj v budúcom veku. …","https://biblia.sk/citanie/seb/iz/52"],["Izaiáš 52:14","Služobník strašne znetvorený","Lukáš 18:31–34; Matúš 26:67–68","Ako sa nad ním mnohí začudovali; jeho výzor je neľudsky znetvorený a jeho tvár sa nepodobá človeku,","Vtedy si vzal so sebou Dvanástich a povedal im: Hľa, vystupujeme do Jeruzalema a vyplní sa o Synovi človeka všetko, čo napísali proroci. Vydajú ho pohanom, vysmejú ho, potupia a opľujú. Zbičujú ho a zabijú, ale on na tretí deň vstane z mŕtvych. … / Potom mu pľuli do tváre, bili ho po hlave a iní ho tĺkli palicami, a hovorili: Prorokuj nám, Mesiáš, kto ťa udrel!","https://biblia.sk/citanie/seb/iz/52"],["Izaiáš 52:15","Národy užasnú nad zvesťou o Služobníkovi","Rimanom 15:18–21","tak ho budú obdivovať mnohé národy a králi si pred ním zatvoria ústa, lebo uvidia, o čom sa im nehovorilo a spoznajú, čo nepočuli.","Neodvážil by som sa totiž hovoriť o niečom, čo by nevykonal Kristus cezo mňa slovom a skutkom, mocou znamení a divov, mocou Božieho Ducha, aby pohania prijali evanjelium. Tak som, počnúc od Jeruzalema a okolia až po Ilýriu, naplnil všetko Kristovým evanjeliom. A tak sa usilujem ohlasovať evanjelium nie tam, kde Kristovo meno bolo už známe, aby som nebudoval na cudzom základe, …","https://biblia.sk/citanie/seb/iz/52"],["Izaiáš 52:15","Jeho krv vyliata na zmierenie za všetkých","Zjavenie 1:5; Hebrejom 9:13–14","tak ho budú obdivovať mnohé národy a králi si pred ním zatvoria ústa, lebo uvidia, o čom sa im nehovorilo a spoznajú, čo nepočuli.","a od Ježiša Krista, verného svedka, prvorodeného z mŕtvych a vládcu nad kráľmi zeme. Jemu, ktorý nás miluje, oslobodil nás svojou krvou od našich hriechov / Veď ak už pokropenie krvou capov a býkov a popol z jalovice posväcuje poškvrnených, aby boli telesne čistí, o to viac krv Krista, ktorý mocou večného Ducha sám seba priniesol Bohu ako nepoškvrnenú obetu, očistí nám svedomie od mŕtvych skutkov, aby sme mohli slúžiť živému Bohu.","https://biblia.sk/citanie/seb/iz/52"],["Izaiáš 53:1","Jeho ľud mu neuverí","Ján 12:37–38","Kto uveril nášmu ohlasovaniu? Komu sa zjavilo rameno Hospodina?","Hoci pred nimi Ježiš urobil toľké znamenia, neuverili v neho, aby sa naplnilo slovo, ktoré povedal prorok Izaiáš: Pane, kto uveril nášmu kázaniu a komu bolo zjavené Pánovo rameno?","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:2","Vyrástol ako výhonok zo suchej zeme","Lukáš 2:40, 52","Vyrástol pred ním ako výhonok, ako koreň zo suchej zeme. Nemá podobu ani krásu, aby sme na neho hľadeli, ani výzor, aby sme po ňom túžili.","Chlapček rástol a mocnel, plný múdrosti, a Božia milosť bola s ním. A Ježiš napredoval v múdrosti, veku a obľube u Boha i u ľudí.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:2","Výzor obyčajného človeka","Filipanom 2:6–8","Vyrástol pred ním ako výhonok, ako koreň zo suchej zeme. Nemá podobu ani krásu, aby sme na neho hľadeli, ani výzor, aby sme po ňom túžili.","On, hoci mal Božiu podobu, svoju rovnosť s Bohom nepokladal za ulúpenú vec, ale zriekol sa jej, keď vzal na seba podobu služobníka a stal sa jedným z ľudí, ponížil sa a stal sa poslušným až na smrť, a to smrť na kríži.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:3","Opovrhnutý","Lukáš 4:28–29","Opovrhnutý a opustený ľuďmi, muž bolesti, ktorý poznal utrpenie, pred ktorým si zakrývajú tvár, opovrhnutý, a my sme si ho nevážili.","Keď to počuli, všetkých v synagóge zachvátil hnev. Vstali a hnali ho von z mesta. Vyviedli ho až na kraj vrchu, na ktorom bolo postavené ich mesto, aby ho odtiaľ zhodili.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:3","Odmietnutý","Matúš 27:21–23","Opovrhnutý a opustený ľuďmi, muž bolesti, ktorý poznal utrpenie, pred ktorým si zakrývajú tvár, opovrhnutý, a my sme si ho nevážili.","Vladár sa ich opýtal: Ktorého z tých dvoch chcete, aby som vám prepustil? Odpovedali: Barabbáša. Pilát im povedal: Čo teda mám urobiť s Ježišom, ktorý sa volá Kristus? Všetci odpovedali: Ukrižovať ho! On namietal: A čo zlé urobil? Ale oni tým väčšmi kričali: Ukrižovať ho!","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:3","Veľký žiaľ a bolesť","Matúš 26:37–38; Lukáš 19:41","Opovrhnutý a opustený ľuďmi, muž bolesti, ktorý poznal utrpenie, pred ktorým si zakrývajú tvár, opovrhnutý, a my sme si ho nevážili.","Vzal so sebou Petra i dvoch Zebedejových synov a začal pociťovať zármutok a úzkosť. Vtedy im povedal: Moja duša je smutná až na smrť. Zostaňte tu a bedlite so mnou. / Keď sa už priblížil a uzrel mesto, zaplakal nad ním","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:3","Ľudia sa skrývajú, aby s ním neboli spájaní","Marek 14:50–52","Opovrhnutý a opustený ľuďmi, muž bolesti, ktorý poznal utrpenie, pred ktorým si zakrývajú tvár, opovrhnutý, a my sme si ho nevážili.","Vtedy ho všetci opustili a rozutekali sa. Šiel za ním akýsi mladík s plachtou, prehodenou na holom tele. Chytili ho, on však plachtu pustil a utiekol nahý.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:4","Služba uzdravovania","Matúš 8:16–17","Naozaj, on niesol naše choroby a naše bolesti ho obťažili. My sme si mysleli, že je ranený, Bohom doudieraný a opovrhnutý.","Keď sa zvečerilo, priniesli mu mnohých posadnutých démonmi. On slovom vyhnal duchov a uzdravil všetkých trpiacich, aby sa splnilo to, čo povedal prorok Izaiáš: On vzal na seba naše slabosti a niesol naše choroby.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:4","Pokladaný za prekliateho Bohom","Matúš 26:66; 27:41–43","Naozaj, on niesol naše choroby a naše bolesti ho obťažili. My sme si mysleli, že je ranený, Bohom doudieraný a opovrhnutý.","Čo o tom súdite? Oni odpovedali: Hoden je smrti! / Podobne sa mu posmievali aj veľkňazi so zákonníkmi a staršími: Iných zachraňoval, sám seba nemôže zachrániť! Je kráľom Izraela, nech teraz zostúpi z kríža a uveríme v neho! Dúfal v Boha, nech ho teraz vyslobodí, ak ho má rád! Veď povedal: Som Boží Syn!","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:5","Nesie trest za neprávosti ľudstva","2. Korinťanom 5:21; Hebrejom 2:9","On však bol prebodnutý za naše hriechy, zdrvený za naše neprávosti. Trest, ktorý nám priniesol pokoj, spočinul na ňom a pre jeho rany sa nám dostalo uzdravenie.","Toho, ktorý nepoznal hriech, urobil za nás hriechom, aby sme sa v ňom stali Božou spravodlivosťou. / Hľadíme však na Ježiša, postaveného nakrátko nižšie ako sú anjeli, ktorý, pretože pretrpel smrť, bol ovenčený slávou a cťou, lebo z Božej milosti okúsil smrť za každého.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:5","Jeho obeta prináša pokoj medzi človekom a Bohom","Kolosanom 1:20","On však bol prebodnutý za naše hriechy, zdrvený za naše neprávosti. Trest, ktorý nám priniesol pokoj, spočinul na ňom a pre jeho rany sa nám dostalo uzdravenie.","a aby skrze neho a v ňom zmieril všetko, čo je na zemi i v nebesiach, keď nastolil pokoj preliatím jeho krvi na kríži.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:5","Jeho obeta uzdravuje človeka z hriechu","1. Petrov 2:24","On však bol prebodnutý za naše hriechy, zdrvený za naše neprávosti. Trest, ktorý nám priniesol pokoj, spočinul na ňom a pre jeho rany sa nám dostalo uzdravenie.","On sám, na vlastnom tele vyniesol naše hriechy na drevo, aby sme odumreli hriechom a žili vďaka spravodlivosti. Jeho ranami ste boli uzdravení.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:6","Nositeľ hriechu za celé ľudstvo","1. Jánov 2:2; 4:10","Všetci sme blúdili ako ovce, každý išiel svojou cestou, ale Hospodin na neho uvalil neprávosti nás všetkých.","On je obetou zmierenia za naše hriechy, no nielen za naše, ale aj za hriechy celého sveta. / Láska je v tom, že nie my sme milovali Boha, ale že on miloval nás a poslal svojho Syna ako obetu zmierenia za naše hriechy.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:6","Božia vôľa, aby niesol hriech za všetkých","Galaťanom 1:4","Všetci sme blúdili ako ovce, každý išiel svojou cestou, ale Hospodin na neho uvalil neprávosti nás všetkých.","ktorý seba samého vydal za naše hriechy, aby nás vytrhol z terajšieho zlého veku podľa vôle Boha, nášho Otca.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:7","Utláčaný a trápený","Matúš 27:27–31","Bol trápený a on sa nechal ponižovať, neotvoril ústa, ako baránok vedený na zabitie; neotvoril ústa ako ovca, ktorá onemie pred strihačom.","Vladárovi vojaci vzali Ježiša do vládnej budovy a zhromaždili okolo neho celú kohortu. Vyzliekli ho a obliekli do purpurového plášťa, z tŕnia uplietli veniec a nasadili mu ho na hlavu. Do pravej ruky mu dali trstinu, padali pred ním na kolená a posmievali sa mu: Buď pozdravený, židovský kráľ! …","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:7","Mlčal pred žalobcami","Matúš 27:12–14","Bol trápený a on sa nechal ponižovať, neotvoril ústa, ako baránok vedený na zabitie; neotvoril ústa ako ovca, ktorá onemie pred strihačom.","A keď ho veľkňazi a starší obviňovali, nič neodpovedal. Vtedy sa ho Pilát pýtal: Nepočuješ, čo všetko svedčia proti tebe? Ale on mu neodpovedal ani na jediné slovo, takže sa vladár veľmi čudoval.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:7","Obetný baránok","Ján 1:29; 1. Petrov 1:18–19","Bol trápený a on sa nechal ponižovať, neotvoril ústa, ako baránok vedený na zabitie; neotvoril ústa ako ovca, ktorá onemie pred strihačom.","Keď na druhý deň videl, ako Ježiš prichádza k nemu, povedal: Hľa, Baránok Boží, ktorý sníma hriech sveta. / Veď viete, že ste zo svojho márneho spôsobu života zdedeného po otcoch boli vykúpení nie pominuteľnými vecami, striebrom alebo zlatom, ale drahou krvou Krista. On ako bezchybný a nepoškvrnený baránok","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:8","Zajatý a prenasledovaný","Matúš 26:47–75; 27:1–31","Z úzkosti a súdu bol vzatý. Kto uvažuje o jeho pokolení? Veď bol vyťatý z krajiny živých, pre neprávosť svojho ľudu bol ranený.","Kým ešte hovoril, prišiel Judáš, jeden z Dvanástich, a s ním veľký zástup s mečmi a kyjmi od veľkňazov a starších ľudu. Jeho zradca im dal znamenie: Koho pobozkám, to je on. Toho chyťte! Hneď nato pristúpil k Ježišovi a povedal: Buď pozdravený, Rabbi! A pobozkal ho. … / Na úsvite všetci veľkňazi a starší ľudu vyniesli rozhodnutie proti Ježišovi, že ho treba usmrtiť. A tak ho spútali, odviedli a vydali vladárovi Pilátovi. Keď zradca Judáš videl, že Ježiša odsúdili, rozľútostený vrátil tridsať strieborných veľkňazom a starším …","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:8","Bol súdený","Ján 18:13–22","Z úzkosti a súdu bol vzatý. Kto uvažuje o jeho pokolení? Veď bol vyťatý z krajiny živých, pre neprávosť svojho ľudu bol ranený.","a odviedli najprv k Annášovi; bol totiž tesťom Kajfáša, ktorý bol v tom roku veľkňazom. A práve Kajfáš poradil Židom, že bude lepšie, keď jeden človek zomrie za ľud. Šimon Peter spolu s iným učeníkom nasledoval Ježiša. Ten učeník bol známy veľkňazovi a vošiel s Ježišom do veľkňazovho nádvoria. …","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:8","Zabitý","Matúš 27:35","Z úzkosti a súdu bol vzatý. Kto uvažuje o jeho pokolení? Veď bol vyťatý z krajiny živých, pre neprávosť svojho ľudu bol ranený.","Keď ho ukrižovali, hodili lós a rozdelili si jeho rúcho.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:8","Zomiera za hriechy sveta","1. Jánov 2:2","Z úzkosti a súdu bol vzatý. Kto uvažuje o jeho pokolení? Veď bol vyťatý z krajiny živých, pre neprávosť svojho ľudu bol ranený.","On je obetou zmierenia za naše hriechy, no nielen za naše, ale aj za hriechy celého sveta.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:9","Pochovaný v hrobe boháča","Matúš 27:57–60","Dali mu hrob s bezbožnými a s bohatým našiel smrť, hoci nepáchal násilie a v jeho ústach nebola lesť.","Keď sa zvečerilo, prišiel zámožný človek z Arimatie menom Jozef, ktorý bol tiež Ježišovým učeníkom. Zašiel k Pilátovi a poprosil ho o Ježišovo telo. Pilát rozkázal, aby mu ho vydali. Jozef vzal telo, zavinul ho do čistého plátna …","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:9","Nevinný — nedopustil sa násilia","Lukáš 23:41; Ján 18:38","Dali mu hrob s bezbožnými a s bohatým našiel smrť, hoci nepáchal násilie a v jeho ústach nebola lesť.","Lenže my spravodlivo dostávame zaslúžený trest, ale on neurobil nič zlé. / Pilát mu povedal: Čo je pravda?! Ako to povedal, opäť vyšiel k Židom a vyhlásil pred nimi: Ja na ňom nenachádzam nijakú vinu.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:9","V jeho ústach nebolo lesti","1. Petrov 2:22","Dali mu hrob s bezbožnými a s bohatým našiel smrť, hoci nepáchal násilie a v jeho ústach nebola lesť.","On sa hriechu nedopustil, ani lesť nebola v jeho ústach.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:10","Božia vôľa, aby zomrel za ľudstvo","Ján 18:11","Hospodinovi sa zapáčilo zdrviť ho utrpením. Ak položí svoj život za zotrenie viny, uvidí potomstvo, predĺži si život a skrze neho sa podarí Hospodinov zámer.","Ale Ježiš povedal Petrovi: Schovaj meč do pošvy! Azda nemám vypiť kalich, ktorý mi dal Otec?","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:10","Obeta za hriech","Matúš 20:28; Galaťanom 3:13","Hospodinovi sa zapáčilo zdrviť ho utrpením. Ak položí svoj život za zotrenie viny, uvidí potomstvo, predĺži si život a skrze neho sa podarí Hospodinov zámer.","Ani Syn človeka neprišiel dať sa obsluhovať, ale slúžiť a dať svoj život ako výkupné za mnohých. / Kristus nás vykúpil z kliatby zákona tým, že sám sa stal kliatbou za nás, lebo je napísané: Prekliaty je každý, kto visí na dreve,","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:10","Vzkriesený — žije naveky","Rimanom 6:9","Hospodinovi sa zapáčilo zdrviť ho utrpením. Ak položí svoj život za zotrenie viny, uvidí potomstvo, predĺži si život a skrze neho sa podarí Hospodinov zámer.","Veď vieme, že Kristus, vzkriesený z mŕtvych, už viac nezomiera, smrť už viac nad ním nepanuje.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:10","Pánova vôľa sa ním uskutoční","Ján 17:1–5","Hospodinovi sa zapáčilo zdrviť ho utrpením. Ak položí svoj život za zotrenie viny, uvidí potomstvo, predĺži si život a skrze neho sa podarí Hospodinov zámer.","Keď to Ježiš povedal, zdvihol oči k nebu a hovoril: Otče, prišla hodina; osláv svojho Syna, aby Syn oslávil teba. A ako si mu dal moc nad každým telom, tak nech on dá večný život všetkým, ktorých si mu dal. A večný život je v tom, aby poznali teba, jediného, pravého Boha i toho, ktorého si poslal, Ježiša Krista. …","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:11","Boh plne uspokojený jeho utrpením","Ján 12:27","Po útrapách svojho života uvidí svetlo, našiel uspokojenie, že ho pochopili. Môj spravodlivý služobník ospravedlní mnohých, vezme na seba ich viny.","Teraz je moja duša vzrušená. Čo mám povedať: Otče, zachráň ma pred touto hodinou? Ale veď práve pre túto hodinu som prišiel.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:11","Boží Služobník ospravedlní človeka","Rimanom 5:8–9, 18–19","Po útrapách svojho života uvidí svetlo, našiel uspokojenie, že ho pochopili. Môj spravodlivý služobník ospravedlní mnohých, vezme na seba ich viny.","No Boh dokazuje svoju lásku k nám tým, že Kristus zomrel za nás, keď sme boli ešte hriešni. Tým skôr teraz, keď sme boli ospravedlnení jeho krvou, budeme skrze neho zachránení pred hnevom. A tak ako previnenie jedného prinieslo odsúdenie všetkým ľuďom, tak aj spravodlivý skutok jedného priniesol ospravedlnenie všetkých ľudí, teda život. …","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:11","Nositeľ hriechu za celé ľudstvo","Hebrejom 9:28","Po útrapách svojho života uvidí svetlo, našiel uspokojenie, že ho pochopili. Môj spravodlivý služobník ospravedlní mnohých, vezme na seba ich viny.","tak aj Kristus bol len raz obetovaný, aby vzal na seba hriechy mnohých, a druhý raz sa zjaví nie pre hriech, ale na spásu tým, čo ho očakávajú.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:12","Vyvýšený Bohom pre svoju obetu","Matúš 28:18","Preto mu dám podiel s mnohými a s početnými si rozdelí korisť, lebo až na smrť vydal svoj život a pripočítali ho k zločincom, hoci on niesol hriechy mnohých a prihováral sa za zločincov.","Ježiš pristúpil a povedal im: Daná mi je všetka moc na nebi aj na zemi.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:12","Vydal svoj život na záchranu ľudstva","Lukáš 23:46","Preto mu dám podiel s mnohými a s početnými si rozdelí korisť, lebo až na smrť vydal svoj život a pripočítali ho k zločincom, hoci on niesol hriechy mnohých a prihováral sa za zločincov.","Tu zvolal Ježiš silným hlasom: Otče, do tvojich rúk porúčam svojho ducha. Keď to povedal, dokonal.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:12","Počítaný medzi zločincov","Marek 15:27–28; Lukáš 22:37","Preto mu dám podiel s mnohými a s početnými si rozdelí korisť, lebo až na smrť vydal svoj život a pripočítali ho k zločincom, hoci on niesol hriechy mnohých a prihováral sa za zločincov.","Spolu s ním ukrižovali aj dvoch lotrov: jedného sprava a druhého zľava. Okoloidúci sa mu rúhali, potriasali hlavami a hovorili: Hej ty, čo zbúraš chrám a za tri dni ho postavíš! / Lebo hovorím vám, že sa musí na mne splniť, čo je napísané: A pripočítali ho k zločincom. Všetko sa o mne plní.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:12","Niesol hriech mnohých","1. Petrov 2:24","Preto mu dám podiel s mnohými a s početnými si rozdelí korisť, lebo až na smrť vydal svoj život a pripočítali ho k zločincom, hoci on niesol hriechy mnohých a prihováral sa za zločincov.","On sám, na vlastnom tele vyniesol naše hriechy na drevo, aby sme odumreli hriechom a žili vďaka spravodlivosti. Jeho ranami ste boli uzdravení.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 53:12","Prihovára sa u Boha za ľudstvo","Lukáš 23:34; Rimanom 8:34","Preto mu dám podiel s mnohými a s početnými si rozdelí korisť, lebo až na smrť vydal svoj život a pripočítali ho k zločincom, hoci on niesol hriechy mnohých a prihováral sa za zločincov.","Ježiš povedal: Otče, odpusť im, lebo nevedia, čo robia. Potom si rozdelili jeho šaty a losovali o ne. / Kto ich odsúdi? Je to Ježiš, Kristus ktorý zomrel, ba čo viac, bol vzkriesený z mŕtvych, je po Božej pravici a prihovára sa za nás.","https://biblia.sk/citanie/seb/iz/53"],["Izaiáš 55:3","Vzkriesený Bohom","Skutky 13:34","Nakloňte si uši a poďte ku mne, počúvajte a budete žiť. Uzavriem s vami večnú zmluvu, preukážem milosrdenstvo prisľúbené Dávidovi.","To, že ho vzkriesil z mŕtvych, a že sa už nikdy nevráti do porušenia, oznámil takto: Splním vám sväté a verné prísľuby dané Dávidovi.","https://biblia.sk/citanie/seb/iz/55"],["Izaiáš 55:4","Svedok","Ján 18:37","Hľa, urobil som ho svedkom pre ľudí, ich kniežaťom a vládcom.","Nato mu Pilát povedal: Tak predsa si kráľ? Ježiš odpovedal: Ty hovoríš, že som kráľ. Ja som sa nato narodil a nato som prišiel na svet, aby som vydal svedectvo pravde. Každý, kto je z pravdy, počuje môj hlas.","https://biblia.sk/citanie/seb/iz/55"],["Izaiáš 55:4","Vodca a vojvodca národov","Hebrejom 2:10","Hľa, urobil som ho svedkom pre ľudí, ich kniežaťom a vládcom.","Veď sa patrilo, aby Boh, pre ktorého je všetko a skrze ktorého je všetko a ktorý priviedol mnoho synov do slávy, cez utrpenie zdokonalil pôvodcu ich spásy.","https://biblia.sk/citanie/seb/iz/55"],["Izaiáš 55:5","Boh ho oslávi","Skutky 3:13","Hľa, privoláš národ, ktorý nepoznáš. Národy, čo ťa nepoznajú, pribehnú k tebe, kvôli Hospodinovi, tvojmu Bohu, Svätému Izraela, lebo ťa oslávil.","Boh Abraháma, Izáka a Jákoba, Boh našich otcov oslávil svojho Služobníka, Ježiša, ktorého ste vy vydali a zriekli sa ho pred Pilátom, hoci on prikázal prepustiť ho.","https://biblia.sk/citanie/seb/iz/55"],["Izaiáš 59:16","Prímluvca medzi človekom a Bohom","Matúš 10:32","Videl, že niet nikoho, a zhrozil sa, že niet nikoho, kto by zasiahol. Pomocníkom mu bolo jeho rameno a podržala ho jeho spravodlivosť.","Toho však, kto by ma zaprel pred ľuďmi, zapriem aj ja pred svojím Otcom, ktorý je v nebesiach.","https://biblia.sk/citanie/seb/iz/59"],["Izaiáš 59:16","Príde priniesť spásu","Ján 6:40","Videl, že niet nikoho, a zhrozil sa, že niet nikoho, kto by zasiahol. Pomocníkom mu bolo jeho rameno a podržala ho jeho spravodlivosť.","Veď to je vôľa môjho Otca, aby každý, kto vidí Syna a verí v neho, mal večný život a ja ho vzkriesim v posledný deň.","https://biblia.sk/citanie/seb/iz/59"],["Izaiáš 59:20","Príde na Sion ako Vykupiteľ","Lukáš 2:38","K Sionu príde ako vykupiteľ, kvôli tým, čo sa v Jákobovi odvrátili od hriechu — znie výrok Hospodina.","Práve v tej chvíli prišla aj ona, velebila Boha a všetkým, čo očakávali vykúpenie Jeruzalema, rozprávala o dieťati.","https://biblia.sk/citanie/seb/iz/59"],["Izaiáš 60:1–3","Ukáže svetlo pohanom","Skutky 26:23","Vstaň, zasvieť, lebo prichádza tvoje svetlo a Hospodinova sláva vychádza nad tebou. Lebo hľa, tma bude pokrývať zem a temnota národy, ale nad tebou vyjde Hospodin a jeho sláva sa zjaví nad tebou. Národy prídu k tvojmu svetlu a králi k tvojej vychádzajúcej žiare.","že Mesiáš má trpieť, ako prvý vstane z mŕtvych a bude ohlasovať svetlo tomuto ľudu i pohanom.","https://biblia.sk/citanie/seb/iz/60"],["Izaiáš 61:1","Boží Duch na ňom","Matúš 3:16–17","Duch Pána, Boha je nado mnou, lebo ma Hospodin pomazal, poslal ma hlásať radostnú zvesť chudobným, obviazať rany tým, čo majú skrúšené srdce, zvestovať slobodu zajatcom a väzneným prepustenie,","Po krste Ježiš hneď vystúpil z vody. Vtom sa mu otvorili nebesia a videl Božieho Ducha, ktorý sťa holubica zostupoval naňho. A z neba zaznel hlas: Toto je môj milovaný Syn, v ktorom som našiel zaľúbenie.","https://biblia.sk/citanie/seb/iz/61"],["Izaiáš 61:1","Mesiáš bude hlásať dobrú zvesť","Lukáš 4:16–21","Duch Pána, Boha je nado mnou, lebo ma Hospodin pomazal, poslal ma hlásať radostnú zvesť chudobným, obviazať rany tým, čo majú skrúšené srdce, zvestovať slobodu zajatcom a väzneným prepustenie,","Prešiel do Nazareta, kde vyrastal a podľa zvyku v sobotu vošiel do synagógy. Keď vstal, aby čítal, podali mu knihu proroka Izaiáša. Knihu rozvinul na tom mieste, kde bolo napísané: Duch Pánov je nado mnou, lebo ma pomazal zvestovať chudobným evanjelium a uzdravovať skrúšených srdcom. Poslal ma oznámiť zajatým prepustenie, slepým vrátiť zrak, utláčaných prepustiť …","https://biblia.sk/citanie/seb/iz/61"],["Izaiáš 61:1","Sloboda z otroctva hriechu","Ján 8:31–36","Duch Pána, Boha je nado mnou, lebo ma Hospodin pomazal, poslal ma hlásať radostnú zvesť chudobným, obviazať rany tým, čo majú skrúšené srdce, zvestovať slobodu zajatcom a väzneným prepustenie,","Vtedy povedal Ježiš Židom, ktorí v neho uverili: Ak vy zostanete v mojom slove, budete naozaj mojimi učeníkmi, poznáte pravdu a pravda vás vyslobodí. Odpovedali mu: Sme potomkovia Abraháma a nikdy sme nikomu neslúžili. Ako to, že ty hovoríš: Stanete sa slobodnými? …","https://biblia.sk/citanie/seb/iz/61"],["Izaiáš 61:1–2","Vyhlási čas milosti","Galaťanom 4:4–5","Duch Pána, Boha je nado mnou, lebo ma Hospodin pomazal, poslal ma hlásať radostnú zvesť chudobným, obviazať rany tým, čo majú skrúšené srdce, zvestovať slobodu zajatcom a väzneným prepustenie, ohlásiť rok Hospodinovej priazne, deň pomsty nášho Boha na potešenie všetkým zarmúteným,","Ale keď prišla plnosť času, Boh poslal svojho Syna narodeného zo ženy, narodeného pod zákonom, aby vykúpil tých, čo sú pod zákonom, a aby sme dostali synovstvo.","https://biblia.sk/citanie/seb/iz/61"],["Jeremiáš 23:5–6","Potomok Dávida","Lukáš 3:23–31","Hľa, prídu dni — znie výrok Hospodina — že vzbudím Dávidovi spravodlivý výhonok. Bude panovať ako kráľ, bude si múdro počínať a v krajine bude konať podľa práva. Za jeho dní Júda dosiahne spásu, Izrael bude bývať v bezpečí. Toto je meno, ktorým sa budú volať: Hospodin je naša spravodlivosť.","Keď Ježiš začal účinkovať, mal asi tridsať rokov. Nazdávali sa, že je synom Jozefa. Jeho predkami boli: Heli, Matat, Lévi, Melchi, Janai, Jozef, Matatiáš, Amos, Naum, Hesli, Nagge, …","https://biblia.sk/citanie/seb/jer/23"],["Jeremiáš 23:5–6","Mesiáš bude Boh i človek","Ján 13:13; 1. Timotejovi 3:16","Hľa, prídu dni — znie výrok Hospodina — že vzbudím Dávidovi spravodlivý výhonok. Bude panovať ako kráľ, bude si múdro počínať a v krajine bude konať podľa práva. Za jeho dní Júda dosiahne spásu, Izrael bude bývať v bezpečí. Toto je meno, ktorým sa budú volať: Hospodin je naša spravodlivosť.","Vy ma nazývate Učiteľ a Pán, a dobre hovoríte, lebo to som. / Nepochybne, veľké je tajomstvo zbožnosti: Zjavený bol v tele, ospravedlnený v Duchu, videný anjelmi, zvestovaný medzi pohanmi, vierou prijatý vo svete a v sláve vzatý hore.","https://biblia.sk/citanie/seb/jer/23"],["Jeremiáš 31:15","Vraždenie neviniatok pri jeho narodení","Matúš 2:16–18","Toto hovorí Hospodin: Čuj, v Ráme počuť nariekanie, prehorký plač. Ráchel oplakáva svojich synov, nedá sa potešiť pre svojich synov, lebo ich už niet.","Keď potom Herodes zbadal, že ho mudrci oklamali, veľmi sa nahneval. Dal povraždiť v Betleheme a na celom okolí všetkých chlapcov do dvoch rokov, a to podľa času, na ktorý sa dôkladne povypytoval mudrcov. Vtedy sa splnilo, čo povedal prorok Jeremiáš: Hlas bolo počuť v Ráme, plač a veľký nárek. Ráchel oplakávala svoje deti a nechcela sa dať potešiť, lebo ich už niet.","https://biblia.sk/citanie/seb/jer/31"],["Jeremiáš 31:22","Narodený z panny","Matúš 1:18–20","Dokedy budeš blúdiť, odpadnutá dcéra? Čosi nové stvorí Hospodin v krajine: žena sa bude uchádzať o muža.","S narodením Ježiša Krista to bolo takto: Jeho matka Mária bola zasnúbená s Jozefom. Skôr však, ako sa zišli, ukázalo sa, že počala z Ducha Svätého. Jej muž Jozef bol však spravodlivý a nechcel ju verejne vystaviť hanbe. Rozhodol sa teda tajne ju prepustiť. Keď o tom uvažoval, zjavil sa mu vo sne Pánov anjel a povedal: Jozef, syn Dávida, neboj sa prijať Máriu, svoju ženu. Veď to, čo sa v nej počalo, je z Ducha Svätého.","https://biblia.sk/citanie/seb/jer/31"],["Jeremiáš 31:31","Mesiáš bude novou zmluvou","Matúš 26:28","Hľa, blíži sa čas — znie výrok Hospodina — keď uzavriem novú zmluvu s domom Izraela a s domom Júdu.","Veď toto je moja krv zmluvy, ktorá sa vylieva za mnohých na odpustenie hriechov.","https://biblia.sk/citanie/seb/jer/31"],["Jeremiáš 33:14–15","Potomok Dávida","Lukáš 3:23–31","Hľa, blíži sa čas — znie výrok Hospodina — keď uskutočním slovo o dobre, ktoré som prisľúbil domu Izraela a domu Júdu. V tých dňoch a v tom čase dám Dávidovi vyrásť spravodlivý výhonok, ktorý bude vykonávať v krajine právo a spravodlivosť.","Keď Ježiš začal účinkovať, mal asi tridsať rokov. Nazdávali sa, že je synom Jozefa. Jeho predkami boli: Heli, Matat, Lévi, Melchi, Janai, Jozef, Matatiáš, Amos, Naum, Hesli, Nagge, …","https://biblia.sk/citanie/seb/jer/33"],["Ezechiel 34:23–24","Potomok Dávida — jediný Pastier","Matúš 1:1; Ján 10:11","Ustanovím nad nimi jedného pastiera a ten ich bude pásť: svojho služobníka Dávida. On ich bude pásť a on im bude pastierom. Ja, Hospodin, budem ich Bohom a môj služobník Dávid bude kniežaťom uprostred nich. Ja, Hospodin, som to povedal.","Rodokmeň Ježiša Krista, syna Dávida, syna Abraháma. / Ja som dobrý pastier. Dobrý pastier kladie svoj život za ovce.","https://biblia.sk/citanie/seb/ez/34"],["Ezechiel 37:24–25","Potomok Dávida — kráľ naveky","Lukáš 1:31–33","Môj služobník Dávid bude kráľom nad nimi a jediným pastierom pre všetkých. Budú chodiť podľa mojich nariadení, zachovávať moje ustanovenia a plniť ich. Budú bývať v krajine, ktorú som dal svojmu služobníkovi Jákobovi a v ktorej bývali vaši otcovia; naveky budú bývať na nej oni a ich synovia i synovia ich synov. Môj služobník Dávid bude naveky ich kniežaťom.","Hľa, počneš, porodíš syna a dáš mu meno Ježiš. On sa bude volať synom Najvyššieho a Pán, Boh, mu dá trón jeho otca Dávida. Bude kraľovať nad Jákobovým domom naveky a jeho kráľovstvu nebude konca.","https://biblia.sk/citanie/seb/ez/37"],["Daniel 2:44–45","Kameň, ktorý rozdrví kráľovstvá","Matúš 21:44","V dňoch týchto kráľov Boh nebies dá povstať kráľovstvu, ktoré bude trvať naveky, nebude zničené a nebude patriť inému ľudu. Rozdrví všetky tie kráľovstvá a skoncuje s nimi, ono však bude stáť naveky. To, že si videl kameň odštiepený z hory bez zásahu rúk, ktorý rozdrvil železo, bronz, hlinu, striebro a zlato, znamená, že veľký Boh oboznámil kráľa s tým, čo nastane. Sen je pravdivý a jeho výklad je spoľahlivý.","Kto padne na ten kameň, doláme sa, a na koho padne on, toho rozmliaždi.","https://biblia.sk/citanie/seb/dan/2"],["Daniel 7:13–14","Vystúpi do neba","Skutky 1:9–11","V nočnom videní som videl: S nebeskými oblakmi prichádzal ktosi ako Syn človeka. Priblížil sa až k Starcovi dní, priviedli ho pred neho. Bola mu odovzdaná moc a sláva i kráľovstvo, aby mu slúžili ľudia každého národa i jazyka. Jeho moc je večná, nikdy nepominie, a jeho kráľovstvo nebude nikdy zničené.","Po týchto slovách sa pred ich očami vzniesol hore, až im ho vzal oblak z dohľadu. A kým uprene hľadeli k nebu, ako odchádza, zrazu pri nich zastali dvaja muži v bielom rúchu a povedali: Muži galilejskí, čo stojíte a hľadíte do neba? Tento Ježiš, ktorý bol vzatý od vás do neba, príde tak, ako ste ho videli odchádzať do neba.","https://biblia.sk/citanie/seb/dan/7"],["Daniel 7:13–14","Vysoko vyvýšený","Efezanom 1:20–22","V nočnom videní som videl: S nebeskými oblakmi prichádzal ktosi ako Syn človeka. Priblížil sa až k Starcovi dní, priviedli ho pred neho. Bola mu odovzdaná moc a sláva i kráľovstvo, aby mu slúžili ľudia každého národa i jazyka. Jeho moc je večná, nikdy nepominie, a jeho kráľovstvo nebude nikdy zničené.","Tú dokázal na Kristovi, keď ho vzkriesil z mŕtvych a posadil v nebi po svojej pravici nad každé kniežatstvo, moc, silu a panstvo a nad každé meno, ktoré sa spomína nielen v tomto, ale aj v budúcom veku. A všetko mu podrobil pod jeho nohy. Jeho však, ako hlavu nad všetkým, dal Cirkvi,","https://biblia.sk/citanie/seb/dan/7"],["Daniel 7:13–14","Jeho vláda bude večná","Lukáš 1:31–33","V nočnom videní som videl: S nebeskými oblakmi prichádzal ktosi ako Syn človeka. Priblížil sa až k Starcovi dní, priviedli ho pred neho. Bola mu odovzdaná moc a sláva i kráľovstvo, aby mu slúžili ľudia každého národa i jazyka. Jeho moc je večná, nikdy nepominie, a jeho kráľovstvo nebude nikdy zničené.","Hľa, počneš, porodíš syna a dáš mu meno Ježiš. On sa bude volať synom Najvyššieho a Pán, Boh, mu dá trón jeho otca Dávida. Bude kraľovať nad Jákobovým domom naveky a jeho kráľovstvu nebude konca.","https://biblia.sk/citanie/seb/dan/7"],["Daniel 9:24","Skoncuje s hriechom","Galaťanom 1:3–5","Sedemdesiat týždňov je stanovených pre tvoj ľud a pre tvoje sväté mesto na ukončenie priestupku, na skoncovanie s hriechom, na odpustenie viny, na privedenie večnej spravodlivosti, na zapečatenie prorockého videnia a na pomazanie svätyne svätých.","Milosť vám a pokoj od Boha, nášho Otca, a od Pána Ježiša Krista, ktorý seba samého vydal za naše hriechy, aby nás vytrhol z terajšieho zlého veku podľa vôle Boha, nášho Otca. Jemu sláva na veky vekov. Amen.","https://biblia.sk/citanie/seb/dan/9"],["Daniel 9:24","Vykoná zmierenie za neprávosť","Rimanom 5:10; 2. Korinťanom 5:18–21","Sedemdesiat týždňov je stanovených pre tvoj ľud a pre tvoje sväté mesto na ukončenie priestupku, na skoncovanie s hriechom, na odpustenie viny, na privedenie večnej spravodlivosti, na zapečatenie prorockého videnia a na pomazanie svätyne svätých.","Ak sme smrťou jeho Syna boli zmierení s Bohom, keď sme boli ešte nepriateľmi, tým skôr budeme zachránení jeho životom po tom, keď sme boli zmierení. / To všetko je z Boha, ktorý nás zmieril so sebou skrze Krista a dal nám službu zmierenia. Veď Boh v Kristovi zmieril svet so sebou. Nepočítal ľuďom ich previnenia a nám uložil ohlasovať slovo zmierenia. V mene Krista sme poslaní a cez nás akoby Boh napomínal. V mene Krista vás prosíme: Zmierte sa s Bohom! …","https://biblia.sk/citanie/seb/dan/9"],["Daniel 9:24","Bude svätý","Lukáš 1:35","Sedemdesiat týždňov je stanovených pre tvoj ľud a pre tvoje sväté mesto na ukončenie priestupku, na skoncovanie s hriechom, na odpustenie viny, na privedenie večnej spravodlivosti, na zapečatenie prorockého videnia a na pomazanie svätyne svätých.","Anjel jej odpovedal: Duch Svätý zostúpi na teba a zatôni ťa moc Najvyššieho, a preto aj dieťa bude sväté a bude sa volať Božím Synom.","https://biblia.sk/citanie/seb/dan/9"],["Daniel 9:25","Ohlásenie — čas jeho príchodu","Ján 12:12–13","Preto vedz a pochop: Odvtedy, čo zaznelo slovo o návrate a vybudovaní Jeruzalema až po pomazanie kniežaťa, uplynie sedem týždňov. Za šesťdesiatdva týždňov bude opäť vybudované námestie a priekopa. Budú to však časy súženia.","Na druhý deň sa veľké množstvo ľudí, ktorí prišli na sviatky, dopočulo, že Ježiš prichádza do Jeruzalema. Nabrali palmových ratolestí, vyšli mu v ústrety a volali: Hosanna, Požehnaný, ktorý prichádza v mene Pánovom a kráľ Izraela! Nabrali palmových ratolestí, vyšli mu v ústrety a volali: „Hosanna! Požehnaný, ktorý prichádza v mene Pánovom, kráľ Izraela!“","https://biblia.sk/citanie/seb/dan/9"],["Daniel 9:26","Bude vyťatý — zabitý","Matúš 16:21; 21:38–39","Po šesťdesiatich dvoch týždňoch bude zabitý pomazaný. Jeho mesto a svätyňu zničí ľud kniežaťa, ktoré príde. Potopa s nimi skoncuje a až do konca vojny bude trvať pustošenie.","Odvtedy začal Ježiš poukazovať svojim učeníkom na to, že musí ísť do Jeruzalema a mnoho trpieť od starších, veľkňazov a zákonníkov, bude zabitý a na tretí deň vzkriesený. / Pri pohľade na syna si však vinohradníci povedali: Toto je dedič! Poďte, zabime ho a jeho dedičstvo bude naše. Chytili ho, vyhodili von z vinice a zabili ho.","https://biblia.sk/citanie/seb/dan/9"],["Daniel 9:26","Zomrie za hriechy sveta","Hebrejom 2:9","Po šesťdesiatich dvoch týždňoch bude zabitý pomazaný. Jeho mesto a svätyňu zničí ľud kniežaťa, ktoré príde. Potopa s nimi skoncuje a až do konca vojny bude trvať pustošenie.","Hľadíme však na Ježiša, postaveného nakrátko nižšie ako sú anjeli, ktorý, pretože pretrpel smrť, bol ovenčený slávou a cťou, lebo z Božej milosti okúsil smrť za každého.","https://biblia.sk/citanie/seb/dan/9"],["Daniel 9:26","Zabitý pred zničením chrámu","Matúš 27:50–51","Po šesťdesiatich dvoch týždňoch bude zabitý pomazaný. Jeho mesto a svätyňu zničí ľud kniežaťa, ktoré príde. Potopa s nimi skoncuje a až do konca vojny bude trvať pustošenie.","Ale Ježiš znova zvolal mocným hlasom a vypustil ducha. A hľa, chrámová opona sa roztrhla na dvoje odvrchu až naspodok, zem sa triasla a skaly pukali.","https://biblia.sk/citanie/seb/dan/9"],["Ozeáš 11:1","Povolaný z Egypta","Matúš 2:15","Keď bol Izrael mladý, miloval som ho, z Egypta som povolal svojho syna.","Zostal tam až do Herodesovej smrti, aby sa splnilo to, čo povedal Pán ústami proroka: Z Egypta som povolal svojho syna.","https://biblia.sk/citanie/seb/oz/11"],["Ozeáš 13:14","Porazí smrť","1. Korinťanom 15:55–57","Vykúpil som ich zo spárov podsvetia, vyslobodil som ich zo smrti. Kde sú tvoje rany moru, smrť? Kde je tvoj osteň, podsvetie?","Smrť, kde je tvoje víťazstvo? Smrť, kde je tvoj osteň? Ostňom smrti je totiž hriech a silou hriechu je zákon. No vďaka Bohu, ktorý nám dáva víťazstvo skrze nášho Pána Ježiša Krista!","https://biblia.sk/citanie/seb/oz/13"],["Joel 2:28","Prisľúbenie Ducha","Skutky 2:17–21","Potom vylejem svojho Ducha na každého človeka. Vaši synovia a vaše dcéry budú prorokovať. Vaši starci budú mávať sny, vaši mládenci budú mávať videnia. prekl.: Učiteľa spravodlivosti.","V posledných dňoch, hovorí Boh, vylejem svojho Ducha na každé telo. Vaši synovia a vaše dcéry budú prorokovať, vaši mladíci budú mať videnia a vašim starcom sa budú snívať sny. V tých dňoch vylejem svojho Ducha aj na svojich služobníkov a svoje služobnice a budú prorokovať. Urobím divy hore na nebi a znamenia dolu na zemi, krv, oheň a kúdoly dymu. …","https://biblia.sk/citanie/seb/joel/2"],["Joel 2:32","Ponúkne spásu celému ľudstvu","Rimanom 10:9–13","Každý, kto bude vzývať jeho meno, bude zachránený, lebo na vrchu Sion a v Jeruzaleme bude záchrana, ako prisľúbil Hospodin. Medzi vyslobodenými budú tí, ktorých Hospodin povolá.","Pretože ak svojimi ústami vyznáš Ježiša ako Pána a vo svojom srdci uveríš, že Boh ho vzkriesil z mŕtvych, budeš spasený. Lebo srdcom veríme v spravodlivosť, ale ústami vyznávame spásu. Písmo totiž hovorí: Nikto, kto verí v neho, nebude zahanbený. …","https://biblia.sk/citanie/seb/joel/2"],["Jonáš 1:17","Tri dni a tri noci v hrobe","Matúš 12:40; 16:4","Pán priviedol veľkú rybu, aby pohltila Jonáša; a Jonáš bol vo vnútri ryby tri dni a tri noci.","Tak ako bol Jonáš v útrobách veľkej ryby tri dni a tri noci, tak bude aj Syn človeka v lone zeme tri dni a tri noci. / Zlé a cudzoložné pokolenie si žiada znamenie, ale znamenie nedostane, iba ak J onášovo znamenie. Nechal ich tam a odišiel.","https://biblia.sk/citanie/seb/jon/1"],["Micheáš 5:2","Narodený v Betleheme","Matúš 2:1–6","Ty však Betlehem, Efrata, hoci si najmenší medzi judskými rodinami, z teba mi vyjde ten, ktorý je určený za vládcu v Izraeli. Jeho pôvod je v dávnoveku, v odvekých časoch.","Keď sa za čias kráľa Herodesa v judskom Betleheme narodil Ježiš, prišli do Jeruzalema mudrci z východu. Pýtali sa: Kde je ten práve narodený židovský kráľ? Videli sme totiž na východe jeho hviezdu a prišli sme sa mu pokloniť. Keď to počul kráľ Herodes, rozrušil sa a s ním aj celý Jeruzalem. …","https://biblia.sk/citanie/seb/mich/5"],["Micheáš 5:2","Vládca v Izraeli","Lukáš 1:33","Ty však Betlehem, Efrata, hoci si najmenší medzi judskými rodinami, z teba mi vyjde ten, ktorý je určený za vládcu v Izraeli. Jeho pôvod je v dávnoveku, v odvekých časoch.","Bude kraľovať nad Jákobovým domom naveky a jeho kráľovstvu nebude konca.","https://biblia.sk/citanie/seb/mich/5"],["Micheáš 5:2","Od večnosti","Ján 8:58","Ty však Betlehem, Efrata, hoci si najmenší medzi judskými rodinami, z teba mi vyjde ten, ktorý je určený za vládcu v Izraeli. Jeho pôvod je v dávnoveku, v odvekých časoch.","Ježiš im odpovedal: Amen, amen, hovorím vám: Skôr ako bol Abrahám, Ja som!","https://biblia.sk/citanie/seb/mich/5"],["Aggeus 2:6–9","Navštívi druhý chrám","Lukáš 2:27–32","Lebo takto hovorí Hospodin zástupov: Bude to len o malú chvíľu a ja zatrasiem nebom a zemou, i morom a suchou zemou. Keď zatrasiem i všetkými národmi, prídu skvosty všetkých národov a naplním tento dom slávou, hovorí Hospodin zástupov. Moje je striebro, moje je zlato — znie výrok Hospodina zástupov. …","Z vnuknutia Ducha prišiel do chrámu. A keď rodičia prinášali dieťa Ježiša, aby splnili, čo predpisoval zákon, aj on si vzal dieťa do náručia a velebil Boha slovami: Teraz, Pane, prepustíš v pokoji svojho služobníka podľa svojho slova, …","https://biblia.sk/citanie/seb/ag/2"],["Aggeus 2:23","Potomok Zorobábela","Lukáš 3:26–27","V ten deň — znie výrok Hospodina zástupov — vezmem ťa, služobník môj Zerubábel, syn Šealtiélov — znie výrok Hospodina — a učiním ťa pečatným prsteňom, lebo som si teba vyvolil — znie výrok Hospodina zástupov.","Mahat, Matatiáš, Semein, Josech, Joda, Johannan, Resa, Zorobábel, Salatiel, Neri,","https://biblia.sk/citanie/seb/ag/2"],["Ámos 8:9","Tma nad krajinou napoludnie","Matúš 27:45; Marek 15:33","V ten deň sa stane — znie výrok Hospodina, Pána — že dám zapadnúť slnku na poludnie a zahalím temnotou zem za jasného dňa.","Od šiestej hodiny nastala tma po celej zemi, až do deviatej hodiny. / O deviatej Ježiš zvolal mocným hlasom: Eloi, Eloi — lema sabachthani? Čo v preklade znamená: Bože môj, Bože môj, prečo si ma opustil?","https://biblia.sk/citanie/seb/am/8"],["Zachariáš 3:8","Boží služobník — Výhonok","Ján 17:4","Počúvaj teda, veľkňaz Jozua, ty aj tvoji druhovia, čo sedia pred tebou, lebo títo muži sú predzvesťou. Pozri, privádzam svojho sluhu — Výhonok.","Ja som ťa oslávil na zemi tým, že som dokonal dielo, ktoré si mi dal vykonať.","https://biblia.sk/citanie/seb/zach/3"],["Zachariáš 6:12–13","Kňaz i Kráľ","Hebrejom 8:1","Povedz mu: Takto hovorí Hospodin zástupov: Pozri, muž, ktorého meno je Výhonok, vyrastie na svojom mieste a vybuduje Hospodinov chrám. On vybuduje Hospodinov chrám, poctia ho slávou a bude sedieť a panovať na svojom tróne; kňaz bude pri jeho tróne a medzi oboma bude zhoda.","Zo všetkého, o čom hovoríme, je hlavné toto: máme takého veľkňaza, ktorý si zasadol po pravici trónu Velebnosti v nebesiach","https://biblia.sk/citanie/seb/zach/6"],["Zachariáš 9:9","Vítaný s jasotom v Jeruzaleme","Matúš 21:8–10","Hlasne plesaj, dcéra Sion, zvučne jasaj, dcéra Jeruzalem. Pozri, tvoj kráľ prichádza k tebe, je spravodlivý a prináša víťazstvo, je pokorný a jazdí na oslovi, na osliatku, mláďati oslice.","Veľký zástup prestieral na cestu svoje plášte, iní odsekávali ratolesti zo stromov a prestierali ich na cestu. A zástupy, čo šli pred ním i za ním, volali: Hosanna Synovi Dávidovmu! Požehnaný, ktorý prichádza v mene Pánovom! Hosanna na výsostiach! Keď Ježiš vošiel do Jeruzalema, v celom meste nastal rozruch. Pýtali sa: Kto je to?","https://biblia.sk/citanie/seb/zach/9"],["Zachariáš 9:9","Videný ako Kráľ","Ján 12:12–13","Hlasne plesaj, dcéra Sion, zvučne jasaj, dcéra Jeruzalem. Pozri, tvoj kráľ prichádza k tebe, je spravodlivý a prináša víťazstvo, je pokorný a jazdí na oslovi, na osliatku, mláďati oslice.","Na druhý deň sa veľké množstvo ľudí, ktorí prišli na sviatky, dopočulo, že Ježiš prichádza do Jeruzalema. Nabrali palmových ratolestí, vyšli mu v ústrety a volali: Hosanna, Požehnaný, ktorý prichádza v mene Pánovom a kráľ Izraela! Nabrali palmových ratolestí, vyšli mu v ústrety a volali: „Hosanna! Požehnaný, ktorý prichádza v mene Pánovom, kráľ Izraela!“","https://biblia.sk/citanie/seb/zach/9"],["Zachariáš 9:9","Mesiáš bude spravodlivý","Ján 5:30","Hlasne plesaj, dcéra Sion, zvučne jasaj, dcéra Jeruzalem. Pozri, tvoj kráľ prichádza k tebe, je spravodlivý a prináša víťazstvo, je pokorný a jazdí na oslovi, na osliatku, mláďati oslice.","Ja nemôžem nič robiť sám od seba. Súdim, ako počujem, a môj súd je spravodlivý, pretože nehľadám svoju vôľu, ale vôľu toho, ktorý ma poslal.","https://biblia.sk/citanie/seb/zach/9"],["Zachariáš 9:9","Mesiáš prinesie spásu","Lukáš 19:10","Hlasne plesaj, dcéra Sion, zvučne jasaj, dcéra Jeruzalem. Pozri, tvoj kráľ prichádza k tebe, je spravodlivý a prináša víťazstvo, je pokorný a jazdí na oslovi, na osliatku, mláďati oslice.","Lebo Syn človeka prišiel hľadať a spasiť, čo zahynulo.","https://biblia.sk/citanie/seb/zach/9"],["Zachariáš 9:9","Mesiáš bude pokorný","Matúš 11:29","Hlasne plesaj, dcéra Sion, zvučne jasaj, dcéra Jeruzalem. Pozri, tvoj kráľ prichádza k tebe, je spravodlivý a prináša víťazstvo, je pokorný a jazdí na oslovi, na osliatku, mláďati oslice.","Vezmite na seba moje jarmo a učte sa odo mňa, lebo som tichý a pokorný srdcom, a nájdete odpočinutie pre svoje duše.","https://biblia.sk/citanie/seb/zach/9"],["Zachariáš 9:9","Vchádza do Jeruzalema na oslovi","Matúš 21:6–9","Hlasne plesaj, dcéra Sion, zvučne jasaj, dcéra Jeruzalem. Pozri, tvoj kráľ prichádza k tebe, je spravodlivý a prináša víťazstvo, je pokorný a jazdí na oslovi, na osliatku, mláďati oslice.","Učeníci šli a urobili, ako im Ježiš prikázal. Priviedli oslicu aj osliatko, pokládli na ne svoje plášte a on si na ne sadol. Veľký zástup prestieral na cestu svoje plášte, iní odsekávali ratolesti zo stromov a prestierali ich na cestu. …","https://biblia.sk/citanie/seb/zach/9"],["Zachariáš 10:4","Uholný kameň","Efezanom 2:20","Bude z neho uhol, bude z neho kolík, bude z neho bojová kuša. Ide o kultúrne oblasti starovekého Grécka. Z neho vyjde každý utláčateľ.","Ste vybudovaní na základe apoštolov a prorokov, pričom uholným prekl.: vzbudzovali sme Boží hnev. kameňom je Ježiš Kristus.","https://biblia.sk/citanie/seb/zach/10"],["Zachariáš 11:4–6","Pri jeho príchode má Izrael nehodných vodcov","Matúš 23:1–4","Takto hovorí Hospodin, môj Boh: Pas stádo určené na zabitie, ktoré majitelia beztrestne zabíjajú. Jeho kupci po jednom hovoria: Nech je zvelebený Hospodin, zbohatol som. Jeho pastieri sa nad ním nezľutujú. Ani ja sa už nezľutujem nad obyvateľmi krajiny — znie výrok Hospodina. Pozri, vydám každého človeka do ruky jeho blížneho a do ruky jeho kráľa. Rozdrvia krajinu, ale ja z ich ruky nikoho nevytrhnem.","Vtedy Ježiš povedal zástupom a svojim učeníkom: Na Mojžišovu stolicu zasadli zákonníci a farizeji. Robte teda a zachovávajte všetko, čo vám hovoria, ale podľa ich skutkov nekonajte. Lebo oni len hovoria, ale nerobia. …","https://biblia.sk/citanie/seb/zach/11"],["Zachariáš 11:4–6","Odmietnutie spôsobí odňatie Božej ochrany","Lukáš 19:41–44","Takto hovorí Hospodin, môj Boh: Pas stádo určené na zabitie, ktoré majitelia beztrestne zabíjajú. Jeho kupci po jednom hovoria: Nech je zvelebený Hospodin, zbohatol som. Jeho pastieri sa nad ním nezľutujú. Ani ja sa už nezľutujem nad obyvateľmi krajiny — znie výrok Hospodina. Pozri, vydám každého človeka do ruky jeho blížneho a do ruky jeho kráľa. Rozdrvia krajinu, ale ja z ich ruky nikoho nevytrhnem.","Keď sa už priblížil a uzrel mesto, zaplakal nad ním a povedal: Kiežby si aj ty, aspoň v tento deň, spoznalo, čo ti prináša pokoj! Teraz je to však skryté pred tvojimi očami. Lebo prídu na teba dni, keď ťa tvoji nepriatelia oboženú valom, obkľúčia ťa a zovrú zo všetkých strán. …","https://biblia.sk/citanie/seb/zach/11"],["Zachariáš 11:4–6","Odmietnutý v prospech iného kráľa","Ján 19:13–15","Takto hovorí Hospodin, môj Boh: Pas stádo určené na zabitie, ktoré majitelia beztrestne zabíjajú. Jeho kupci po jednom hovoria: Nech je zvelebený Hospodin, zbohatol som. Jeho pastieri sa nad ním nezľutujú. Ani ja sa už nezľutujem nad obyvateľmi krajiny — znie výrok Hospodina. Pozri, vydám každého človeka do ruky jeho blížneho a do ruky jeho kráľa. Rozdrvia krajinu, ale ja z ich ruky nikoho nevytrhnem.","Keď teda Pilát počul tieto slová, vyviedol Ježiša von, posadil sa na súdnu stolicu, na miesto menované Litostrótos, po hebrejsky Gabbata. Bol prípravný deň pred Veľkou nocou a bolo okolo šiestej hodiny. Tu prehovoril k Židom: Hľa, váš kráľ! Nato oni začali kričať: Preč s ním, preč s ním! Ukrižuj ho! Pilát im povedal: Vášho kráľa mám ukrižovať? Veľkňazi odpovedali: Nemáme kráľa, iba cisára!","https://biblia.sk/citanie/seb/zach/11"],["Zachariáš 11:7","Služba chudobným — veriacemu zvyšku","Matúš 9:35–36","Pásol som stádo určené na zabitie pre kupcov s ovcami. A vzal som dve palice: jednu som nazval Priazeň, druhej som dal meno Jednota, a tak som pásol stádo.","Ježiš chodil po všetkých okolitých mestách a dedinách. Učil v ich synagógach, hlásal evanjelium o kráľovstve a uzdravoval každú chorobu a každý neduh. Pri pohľade na zástupy mu ich prišlo ľúto, lebo boli zbedačení a sklesnutí ako ovce bez pastiera.","https://biblia.sk/citanie/seb/zach/11"],["Zachariáš 11:8","Nevera núti Mesiáša odmietnuť ich","Matúš 23:33","V jednom mesiaci som odstránil troch pastierov. Stratil som s nimi trpezlivosť a aj oni cítili voči mne znechutenie.","Hadi, vreteničie plemeno! Ako uniknete odsúdeniu do pekla?","https://biblia.sk/citanie/seb/zach/11"],["Zachariáš 11:8","Opovrhnutý","Matúš 27:20","V jednom mesiaci som odstránil troch pastierov. Stratil som s nimi trpezlivosť a aj oni cítili voči mne znechutenie.","Veľkňazi a starší však naviedli zástupy, aby si žiadali Barabbáša a Ježiša zahubili.","https://biblia.sk/citanie/seb/zach/11"],["Zachariáš 11:9","Prestáva slúžiť tým, ktorí ho odmietli","Matúš 13:10–11","I povedal som: Nebudem vás pásť. Čo má zomrieť, nech zomrie; čo má zahynúť, nech zahynie, a tie čo zostanú, nech si vzájomne obžierajú mäso.","Učeníci pristúpili k Ježišovi a opýtali sa ho: Prečo im hovoríš v podobenstvách? On odpovedal: Preto, že vám je dané poznať tajomstvá nebeského kráľovstva, ale im nie je dané.","https://biblia.sk/citanie/seb/zach/11"],["Zachariáš 11:10–11","Veriaci zvyšok spoznáva Božie slovo","Lukáš 19:41–44","Vzal som svoju palicu Priazeň a zlomil som ju; tým som zrušil svoju zmluvu, ktorú som uzavrel so všetkými národmi. V ten deň bola zrušená. Vtedy kupci s ovcami, čo ma pozorovali, spoznali, že je to slovo Hospodina.","Keď sa už priblížil a uzrel mesto, zaplakal nad ním a povedal: Kiežby si aj ty, aspoň v tento deň, spoznalo, čo ti prináša pokoj! Teraz je to však skryté pred tvojimi očami. Lebo prídu na teba dni, keď ťa tvoji nepriatelia oboženú valom, obkľúčia ťa a zovrú zo všetkých strán. …","https://biblia.sk/citanie/seb/zach/11"],["Zachariáš 11:10–11","Mesiáš bude Boh","Ján 14:7","Vzal som svoju palicu Priazeň a zlomil som ju; tým som zrušil svoju zmluvu, ktorú som uzavrel so všetkými národmi. V ten deň bola zrušená. Vtedy kupci s ovcami, čo ma pozorovali, spoznali, že je to slovo Hospodina.","Ak ste ma spoznali, budete poznať aj môjho Otca. Odteraz ho už poznáte a videli ste ho.","https://biblia.sk/citanie/seb/zach/11"],["Zachariáš 11:12–13","Zradený za tridsať strieborných","Matúš 26:14–15","Povedal som im: Ak uznáte za dobré, dajte mi moju mzdu, ak nie, nechajte tak! Odvážili mi teda mzdu: tridsať strieborných. Hospodin mi povedal: Hoď ju do pokladnice! — tú cennú mzdu, ktorou ma ocenili. Vzal som teda tridsať strieborných a hodil som ich do pokladnice v Hospodinovom dome.","Vtedy odišiel jeden z Dvanástich, menom Judáš Iškariotský, k veľkňazom a povedal: Čo mi dáte, ak vám ho zradím? Oni mu určili tridsať strieborných.","https://biblia.sk/citanie/seb/zach/11"],["Zachariáš 11:12–13","Ocenený mzdou otroka","Matúš 26:14–15","Povedal som im: Ak uznáte za dobré, dajte mi moju mzdu, ak nie, nechajte tak! Odvážili mi teda mzdu: tridsať strieborných. Hospodin mi povedal: Hoď ju do pokladnice! — tú cennú mzdu, ktorou ma ocenili. Vzal som teda tridsať strieborných a hodil som ich do pokladnice v Hospodinovom dome.","Vtedy odišiel jeden z Dvanástich, menom Judáš Iškariotský, k veľkňazom a povedal: Čo mi dáte, ak vám ho zradím? Oni mu určili tridsať strieborných.","https://biblia.sk/citanie/seb/zach/11"],["Zachariáš 11:12–13","Striebro hodené v Pánovom dome","Matúš 27:3–5","Povedal som im: Ak uznáte za dobré, dajte mi moju mzdu, ak nie, nechajte tak! Odvážili mi teda mzdu: tridsať strieborných. Hospodin mi povedal: Hoď ju do pokladnice! — tú cennú mzdu, ktorou ma ocenili. Vzal som teda tridsať strieborných a hodil som ich do pokladnice v Hospodinovom dome.","Keď zradca Judáš videl, že Ježiša odsúdili, rozľútostený vrátil tridsať strieborných veľkňazom a starším slovami: Zhrešil som, lebo som zradil nevinnú krv. Ale oni mu povedali: Čo nás do toho? To je tvoja vec! On odhodil strieborné peniaze do chrámu a vzdialil sa. Potom odišiel a obesil sa.","https://biblia.sk/citanie/seb/zach/11"],["Zachariáš 11:12–13","Cena zaplatená za hrnčiarovo pole","Matúš 27:6–10","Povedal som im: Ak uznáte za dobré, dajte mi moju mzdu, ak nie, nechajte tak! Odvážili mi teda mzdu: tridsať strieborných. Hospodin mi povedal: Hoď ju do pokladnice! — tú cennú mzdu, ktorou ma ocenili. Vzal som teda tridsať strieborných a hodil som ich do pokladnice v Hospodinovom dome.","Veľkňazi vzali peniaze a povedali: Neslobodno ich dať do chrámovej pokladnice, lebo je to cena za krv. Po porade kúpili za ne hrnčiarovo pole na pochovávanie cudzincov. Preto sa to pole až dodnes volá Pole krvi. …","https://biblia.sk/citanie/seb/zach/11"],["Zachariáš 12:10","Mesiášovo telo bude prebodnuté","Ján 19:34–37","No na Dávidov dom a na obyvateľov Jeruzalema vylejem Ducha milosti a úpenlivých prosieb. Potom budú hľadieť na mňa, ktorého prebodli. Budú nad ním nariekať, ako sa narieka nad jedináčikom, a bedákať, ako sa bedáka nad prvorodeným.","ale jeden z vojakov mu prebodol kopijou bok, odkiaľ hneď vyšla krv a voda. Ten, čo to videl, vydal o tom svedectvo a jeho svedectvo je pravdivé. On vie, že hovorí pravdu — aby ste aj vy verili. Stalo sa to preto, aby sa splnilo Písmo: Kosť mu nebude zlomená. …","https://biblia.sk/citanie/seb/zach/12"],["Zachariáš 12:10","Mesiáš bude Boh i človek","Ján 10:30","No na Dávidov dom a na obyvateľov Jeruzalema vylejem Ducha milosti a úpenlivých prosieb. Potom budú hľadieť na mňa, ktorého prebodli. Budú nad ním nariekať, ako sa narieka nad jedináčikom, a bedákať, ako sa bedáka nad prvorodeným.","Ja a Otec sme jedno.","https://biblia.sk/citanie/seb/zach/12"],["Zachariáš 12:10","Mesiáš bude odmietnutý","Ján 1:11","No na Dávidov dom a na obyvateľov Jeruzalema vylejem Ducha milosti a úpenlivých prosieb. Potom budú hľadieť na mňa, ktorého prebodli. Budú nad ním nariekať, ako sa narieka nad jedináčikom, a bedákať, ako sa bedáka nad prvorodeným.","Do svojho vlastného prišiel, ale jeho vlastní ho neprijali.","https://biblia.sk/citanie/seb/zach/12"],["Zachariáš 13:7","Božia vôľa, aby zomrel za ľudstvo","Ján 18:11","Meč, povstaň proti môjmu pastierovi a proti mužovi, čo mi je blízky — znie výrok Hospodina zástupov — Udri pastiera a stádo sa rozpŕchne! K maličkým však obrátim svoju ruku.","Ale Ježiš povedal Petrovi: Schovaj meč do pošvy! Azda nemám vypiť kalich, ktorý mi dal Otec?","https://biblia.sk/citanie/seb/zach/13"],["Zachariáš 13:7","Násilná smrť","Marek 14:27","Meč, povstaň proti môjmu pastierovi a proti mužovi, čo mi je blízky — znie výrok Hospodina zástupov — Udri pastiera a stádo sa rozpŕchne! K maličkým však obrátim svoju ruku.","Vtedy im Ježiš povedal: Všetci sa pohoršíte, lebo je napísané: Udriem pastiera a ovce sa rozpŕchnu.","https://biblia.sk/citanie/seb/zach/13"],["Zachariáš 13:7","Boh i človek","Ján 14:9","Meč, povstaň proti môjmu pastierovi a proti mužovi, čo mi je blízky — znie výrok Hospodina zástupov — Udri pastiera a stádo sa rozpŕchne! K maličkým však obrátim svoju ruku.","Ježiš mu povedal: Filip, toľký čas som s vami a nespoznal si ma? Kto videl mňa, videl aj Otca. Ako to, že teraz hovoríš: Ukáž nám Otca?","https://biblia.sk/citanie/seb/zach/13"],["Zachariáš 13:7","Ovce sa rozpŕchnu — učeníci sa rozutekajú","Matúš 26:31–56","Meč, povstaň proti môjmu pastierovi a proti mužovi, čo mi je blízky — znie výrok Hospodina zástupov — Udri pastiera a stádo sa rozpŕchne! K maličkým však obrátim svoju ruku.","Vtedy im Ježiš povedal: Vy všetci sa tejto noci nado mnou pohoršíte, lebo je napísané: Budem biť pastiera a ovce stáda sa rozpŕchnu. Ale po svojom vzkriesení vás predídem do Galiley. Peter mu však povedal: Aj keby sa všetci nad tebou pohoršili, ja sa nikdy nepohorším. …","https://biblia.sk/citanie/seb/zach/13"],["Malachiáš 3:1","Posol pripraví cestu Mesiášovi","Matúš 11:10","Pozrite, posielam svojho posla, on mi pripraví cestu. Vtedy zrazu príde do svojho chrámu Pán, ktorého hľadáte; príde posol zmluvy, po ktorom túžite — vraví Hospodin zástupov.","Toto je ten, o ktorom je napísané: Hľa, posielam pred tvojou tvárou svojho posla, ktorý pripraví cestu pred tebou.","https://biblia.sk/citanie/seb/mal/3"],["Malachiáš 3:1","Náhle príde do chrámu","Marek 11:15–16","Pozrite, posielam svojho posla, on mi pripraví cestu. Vtedy zrazu príde do svojho chrámu Pán, ktorého hľadáte; príde posol zmluvy, po ktorom túžite — vraví Hospodin zástupov.","Tak prišli do Jeruzalema. Keď vstúpil do chrámu, začal vyháňať tých, čo v chráme predávali a kupovali. Peňazomencom poprevracal stoly a predavačom holubov pulty. Nedovolil, aby niekto niečo prenášal cez chrám.","https://biblia.sk/citanie/seb/mal/3"],["Malachiáš 3:1","Posol novej zmluvy","Lukáš 4:43","Pozrite, posielam svojho posla, on mi pripraví cestu. Vtedy zrazu príde do svojho chrámu Pán, ktorého hľadáte; príde posol zmluvy, po ktorom túžite — vraví Hospodin zástupov.","No on im odpovedal: Aj iným mestám musím hlásať Božie kráľovstvo, lebo na to som poslaný.","https://biblia.sk/citanie/seb/mal/3"],["Malachiáš 4:5","Predchodca v duchu Eliáša","Matúš 3:1–3; 11:10–14; 17:11–13","Ja vám pošlem proroka Eliáša, prv ako príde veľký a hrozný deň Hospodina.","V tých dňoch vystúpil Ján Krstiteľ, ktorý kázal v judskej púšti: Kajajte sa, lebo sa priblížilo nebeské kráľovstvo. — Je to ten, o ktorom bolo povedané ústami proroka Izaiáša: Hlas volajúceho na púšti: Pripravte cestu Pánovi, vyrovnávajte mu chodníky. / Toto je ten, o ktorom je napísané: Hľa, posielam pred tvojou tvárou svojho posla, ktorý pripraví cestu pred tebou. Amen, hovorím vám: Medzi narodenými zo ženy nepovstal nikto väčší ako Ján Krstiteľ. Ale aj ten najmenší v nebeskom kráľovstve je väčší ako on. Od dní Jána Krstiteľa až doteraz nebeské kráľovstvo trpí násilie a násilníci sa ho zmocňujú. … / On odpovedal: Áno, Eliáš príde a všetko obnoví. Ba, hovorím vám, že Eliáš už prišiel, a nespoznali ho, ale urobili s ním, čo chceli. Takisto bude od nich trpieť aj Syn človeka. Vtedy učeníci porozumeli, že im hovoril o Jánovi Krstiteľovi.","https://biblia.sk/citanie/seb/mal/4"],["Malachiáš 4:6","Predchodca obráti mnohých k spravodlivosti","Lukáš 1:16–17","On obráti srdce otcov k synom a srdce synov k otcom, aby som pri svojom príchode neuvalil na zem kliatbu.","Mnohých z izraelských synov obráti k Pánovi, ich Bohu. On sám pôjde pred ním v Eliášovom duchu a v jeho sile, aby obrátil srdcia otcov k deťom a neposlušných k múdrosti spravodlivých, a pripravil tak Pánovi dokonalý ľud.","https://biblia.sk/citanie/seb/mal/4"]];

const PAPER = new Color("#ffffff");
const INK = new Color("#666666");
const INK_STRONG = new Color("#000000");
const INK_FAINT = new Color("#aaaaaa");
const RULE = new Color("#e5e5e5");

// deterministický výber: deň → položka (celý zoznam za 351 dní)
const today = new Date();
const dayN = Math.floor((today.getTime() - today.getTimezoneOffset() * 60000) / 86400000);
const idx = ((dayN % DATA.length) + DATA.length) % DATA.length;
const [otRef, what, ntRef, otText, ntText, url] = DATA[idx];

const serif = (size) => new Font("Georgia", size);
const small = (size) => new Font("Georgia", size);

function trim(t, max) {
  return t.length > max ? t.slice(0, max - 1).trimEnd() + "…" : t;
}

function makeWidget(size) {
  const w = new ListWidget();
  w.backgroundColor = PAPER;
  w.url = "https://proroctva.sk/";
  w.setPadding(14, 16, 14, 16);
  // obnoviť po polnoci
  const tomorrow = new Date(today);
  tomorrow.setDate(tomorrow.getDate() + 1);
  tomorrow.setHours(0, 5, 0, 0);
  w.refreshAfterDate = tomorrow;

  const head = w.addStack();
  const num = head.addText((idx + 1) + " / " + DATA.length);
  num.font = small(9);
  num.textColor = INK_FAINT;
  head.addSpacer();
  const lbl = head.addText("PROROCTVO DŇA");
  lbl.font = small(9);
  lbl.textColor = INK_FAINT;

  w.addSpacer(6);
  const title = w.addText(what);
  title.font = serif(size === "small" ? 12 : 14);
  title.textColor = INK_STRONG;
  title.lineLimit = 2;

  if (size === "small") {
    w.addSpacer(4);
    const r1 = w.addText(otRef);
    r1.font = small(10);
    r1.textColor = INK;
    const r2 = w.addText(ntRef);
    r2.font = small(10);
    r2.textColor = INK_FAINT;
    w.addSpacer();
    return w;
  }

  w.addSpacer(8);
  const ref1 = w.addText(otRef.toUpperCase());
  ref1.font = small(9);
  ref1.textColor = INK_FAINT;
  w.addSpacer(2);
  const t1 = w.addText(trim(otText, size === "large" ? 260 : 110));
  t1.font = serif(size === "large" ? 13 : 12);
  t1.textColor = INK;
  t1.lineLimit = size === "large" ? 5 : 2;

  w.addSpacer(8);
  const line = w.addStack();
  line.backgroundColor = RULE;
  line.size = new Size(0, 1);
  line.addSpacer();
  w.addSpacer(8);

  const ref2 = w.addText(ntRef.toUpperCase() + " · NAPLNENIE");
  ref2.font = small(9);
  ref2.textColor = INK_FAINT;
  w.addSpacer(2);
  const t2 = w.addText(trim(ntText, size === "large" ? 260 : 110));
  t2.font = serif(size === "large" ? 13 : 12);
  t2.textColor = INK;
  t2.lineLimit = size === "large" ? 5 : 2;

  w.addSpacer();
  return w;
}

const size = config.widgetFamily || "large";
const widget = makeWidget(size);

if (config.runsInWidget) {
  Script.setWidget(widget);
} else {
  await widget.presentLarge();
}
Script.complete();
